-- Poems batch 267
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fe1e0e5b-2466-4278-b1e9-ca0baa61a085','題雪霽望弁山圖  其五','錢選','宋','宋诗','song-poetry','','[]','子猷安道何爲者，自是相忘意最真。',32,'全唐诗/poet.song.238000.json','["子猷安道何爲者，自是相忘意最真。", "千載寥寥風雪夜，始知乘興更無人。"]'),
('caef4f26-3d4e-4f23-820f-b3e61fd5200d','題雪霽望弁山圖  其六','錢選','宋','宋诗','song-poetry','','[]','一冬飛雪又將春，能報年豐不救貧。',32,'全唐诗/poet.song.238000.json','["一冬飛雪又將春，能報年豐不救貧。", "我亦曽聞散花手，不知天女意何勤。"]'),
('246f937d-bae6-4b52-adf8-88871364bc42','題雪霽望弁山圖  其七','錢選','宋','宋诗','song-poetry','','[]','眼前觸物動成氷，凍筆頻枯字不成。',32,'全唐诗/poet.song.238000.json','["眼前觸物動成氷，凍筆頻枯字不成。", "獨坐火爐煨酒喫，細聽撲簌打窗聲。"]'),
('177caebf-fe3e-4f90-a75e-4cd300e84ebd','題雪霽望弁山圖  其八','錢選','宋','宋诗','song-poetry','','[]','階簷積雪動經旬，猶自霏霏夜向晨。',64,'全唐诗/poet.song.238000.json','["階簷積雪動經旬，猶自霏霏夜向晨。", "四望莫分天地色，一時遮盡海山塵。", "舞風不住緣何事，見日還銷亦快人。", "獨欠故交來叩户，洛中髙臥是前身。"]'),
('8c0413f5-4ea0-4bc5-b3a2-0bdd4d306f97','題雪霽望弁山圖  其九','錢選','宋','宋诗','song-poetry','','[]','亂山積雪欝崔嵬，對景慚無倡和才。',64,'全唐诗/poet.song.238000.json','["亂山積雪欝崔嵬，對景慚無倡和才。", "晴日舊曾梅下飲，好懐今爲竹林開。", "仙人千劫能居此，俗客三生始一來。", "未許扁舟落吾手，明朝相約共傳杯。"]'),
('4774ddb3-db65-4165-8735-bbed6807da34','題山居圖卷','錢選','宋','宋诗','song-poetry','','[]','山居惟愛靜，白日掩柴門。',48,'全唐诗/poet.song.238000.json','["山居惟愛靜，白日掩柴門。", "寡合人多忌，無求道自尊。", "鷃鵬俱有意，蘭艾不同根。", "安得蒙莊叟，相逢與細論。"]'),
('d8e15e26-d7ff-411e-8a0e-644c29bb86c0','五君詠 阮籍','錢選','宋','宋诗','song-poetry','','[]','阮公雖淪跡，識密鑒亦洞。',48,'全唐诗/poet.song.238000.json','["阮公雖淪跡，識密鑒亦洞。", "沉醉似埋照，寓辭類託諷。", "長嘯若懷人，越禮自驚衆。", "物故不可論，途窮能無慟。"]'),
('2362d4de-dba4-4c99-975f-503a31f999b1','五君詠 嵇康','錢選','宋','宋诗','song-poetry','','[]','中散不偶世，本自餐霞人。',48,'全唐诗/poet.song.238000.json','["中散不偶世，本自餐霞人。", "形解驗黙仙，吐論知凝神。", "立俗迕流議，尋山洽隱淪。", "鸞翮有時鏘，龍性誰能馴。"]'),
('817661c9-7d80-4bac-8b8b-7991f4554e91','五君詠 劉伶','錢選','宋','宋诗','song-poetry','','[]','劉公善閉關，懷情滅聞見。',48,'全唐诗/poet.song.238000.json','["劉公善閉關，懷情滅聞見。", "鼓鐘不足歡，容色豈能眩。", "韜精日沉飲，誰知非荒宴。", "頌酒雖短章，深衷自此見。"]'),
('e6419c7d-6d66-4bd7-a48a-d838e27c412c','五君詠 阮咸','錢選','宋','宋诗','song-poetry','','[]','仲容青雲器，實禀生民秀。',48,'全唐诗/poet.song.238000.json','["仲容青雲器，實禀生民秀。", "達音何用深，識微在金奏。", "郭奕巳心醉，山公非虛覯。", "屢薦不入官，一麾乃出守。"]'),
('537806d6-7775-4ac8-82f8-3ee6061ee594','五君詠 向秀','錢選','宋','宋诗','song-poetry','','[]','向秀甘淡薄，深心託毫素。',48,'全唐诗/poet.song.238000.json','["向秀甘淡薄，深心託毫素。", "探道好淵玄，觀書鄙章句。", "交吕既鴻軒，攀嵇亦鳯舉。", "流連河裏游，惻愴山陽賦。"]'),
('a32b2219-2fc5-4a0e-889b-8f632398f9e7','題唐三學士圖','錢選','宋','宋诗','song-poetry','','[]','唐三學士粲三英，挺挺人才藝術精。',32,'全唐诗/poet.song.238000.json','["唐三學士粲三英，挺挺人才藝術精。", "無事圍棋春晝永，至今畫筆尚傳名。"]'),
('33850f7f-ff98-4832-b32b-3af62ea0e62e','題觀梅圖','錢選','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不見西湖處士星，儼然風月爲誰明。',32,'全唐诗/poet.song.238000.json','["不見西湖處士星，儼然風月爲誰明。", "當時寂寞孤山下，兩句詩成萬古名。"]'),
('2de7bc14-ac67-462d-8cd0-2191c00201c5','題秋江待渡圖','錢選','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山色空濛翠欲流，長江清澈一天秋。',32,'全唐诗/poet.song.238000.json','["山色空濛翠欲流，長江清澈一天秋。", "茅茨落日寒煙外，久立行人待渡舟。"]'),
('91c4e5a3-ec9a-4876-af8f-27f0c87d9343','題韓左軍馬圖','錢選','宋','宋诗','song-poetry','','[]','韓公胸次有神奇，寫得天閑八尺駒。',64,'全唐诗/poet.song.238000.json','["韓公胸次有神奇，寫得天閑八尺駒。", "曾爲岐王天上賜，不隨即護雨中驅。", "霜蹄奮迅追飛電，鳳首昂藏似渴烏。", "春草青青華山曲，三邊今日已無虞。"]'),
('d13b86fb-2420-4981-a7d5-8c24fb4433c9','題秋茄圖','錢選','宋','宋诗','song-poetry','','[]','憶昔毗山愛寫生，瓜茄任我筆縱橫。',32,'全唐诗/poet.song.238000.json','["憶昔毗山愛寫生，瓜茄任我筆縱橫。", "自憐老去翻成拙，學圃今猶學不成。"]'),
('67a76155-9ff8-464f-84f5-559921bffb09','題石勒問道圖','錢選','宋','宋诗','song-poetry','','[]','磊落爲人天下奇，來參佛法始知機。',32,'全唐诗/poet.song.238000.json','["磊落爲人天下奇，來參佛法始知機。", "一言能悟圓通理，却笑劉聰事事非。"]'),
('5f42b509-ed78-4f66-a7e1-2179351a3e3d','題楊妃上馬圖','錢選','宋','宋诗','song-poetry','','[]','唐室開元致太平，年年十月幸華清。',32,'全唐诗/poet.song.238000.json','["唐室開元致太平，年年十月幸華清。", "當時馬上多嬌態，不相驅馳蜀道行。"]'),
('a03dc333-1a1c-4f18-80a4-0c5f972fac9d','中秋月','錢選','宋','宋诗','song-poetry','','[]','皎皎無邊白玉盤，年年此夕带愁看。',64,'全唐诗/poet.song.238000.json','["皎皎無邊白玉盤，年年此夕带愁看。", "松枝積翠欺人老，桂影浮香入鬢寒。", "常記醉來多謬誤，又逢秋至輒悲酸。", "疎桐清露中庭下，淚灑西風爲一彈。"]'),
('13d126a0-6e1e-477e-a15c-5f53f702f667','天台雜書','錢選','宋','宋诗','song-poetry','','[]','靈境無人桃自花，東風吹散赤城霞。',64,'全唐诗/poet.song.238000.json','["靈境無人桃自花，東風吹散赤城霞。", "山容對我橫天末，柳色將春到水涯。", "王粲憶秦空有恨，杜陵入蜀更無家。", "干戈滿眼何年定，回雁悠悠白日斜。"]'),
('e4e4daa6-a509-4d48-92ce-bb18e77ed6ad','夜宿南山僧寺','錢選','宋','宋诗','song-poetry','','[]','高樓一日賞新晴，白羽停揮倚繡楹。',64,'全唐诗/poet.song.238000.json','["高樓一日賞新晴，白羽停揮倚繡楹。", "塵世可憐人易老，海門還見月長生。", "蓬瀛縹緲南山小，殿閣森羅北斗橫。", "今古登臨盡如此，不須遊子獨含情。"]'),
('bd3ec864-0ee4-4280-8809-82a207147917','題歸去來圖','錢選','宋','宋诗','song-poetry','','[]','衡門植五柳，東籬采叢菊。',48,'全唐诗/poet.song.238000.json','["衡門植五柳，東籬采叢菊。", "長嘯有餘清，無奈酒不足。", "當世宜沈酣，作色召侮辱。", "乘興賦歸歟，千載一辭獨。"]'),
('e2e80bfe-98de-4ca0-8009-02b417bcd456','春暮','錢選','宋','宋诗','song-poetry','','[]','晴日溪光動草堂，兩峯浮翠瞰滄浪。',64,'全唐诗/poet.song.238000.json','["晴日溪光動草堂，兩峯浮翠瞰滄浪。", "獨揮羽扇成何事，更嘆芒鞋爲底忙。", "一水澄清魚避影，萬紅狼藉蜨分香。", "東風自是無情物，白日楊花莫漫狂。"]'),
('5534e8d8-4742-48b5-85a4-9b4f694790c5','題友人判太平歸來詩卷','錢選','宋','宋诗','song-poetry','','[]','宮錦翩翩五色麟，如君端合侍楓宸。',64,'全唐诗/poet.song.238000.json','["宮錦翩翩五色麟，如君端合侍楓宸。", "山中老去陶弘景，湖曲歸來賀季真。", "上界神仙足官府，此身城郭舊人民。", "還鄉我結同盟社，只看桃花莫問春。"]'),
('a3f0e96c-1430-43b0-8529-f3d45775bc9a','春日即事','錢選','宋','宋诗','song-poetry','','[]','十日春風暄且妍，溪頭花柳競相鮮。',64,'全唐诗/poet.song.238000.json','["十日春風暄且妍，溪頭花柳競相鮮。", "美人遙隔山川外，社雨忽來尊俎前。", "白髮青春猶故我，夕陽幽草自新阡。", "五陵公子莫相笑，曾散黄金樂少年。"]'),
('8a42ce09-e68d-4896-9932-ae2e40dd58ee','雜詩  其一','錢選','宋','宋诗','song-poetry','','[]','地僻秋深戎馬閒，一尊隨處且開顔。',64,'全唐诗/poet.song.238000.json','["地僻秋深戎馬閒，一尊隨處且開顔。", "誰思銅雀埋黄土，但憶金人出漢關。", "六合茫茫天共遠，五湖杳杳雁飛還。", "中年陶寫無絲竹，王謝風流莫強攀。"]'),
('58174385-68ba-433a-a3d5-a5771281a9e7','雜詩  其二','錢選','宋','宋诗','song-poetry','','[]','青春躍馬兩山間，溪柳巖花動客顔。',64,'全唐诗/poet.song.238000.json','["青春躍馬兩山間，溪柳巖花動客顔。", "日落孤城金鐸振，草深荒塚石人閒。", "庾郎賦就元無味，阮籍途窮且未還。", "江左風流半摧謝，白頭猶自繞鄉關。"]'),
('2b009975-f8f5-4a50-b0f4-ac781c18ae39','題壽陽梅妝圖','王思謙','宋','宋诗','song-poetry','','[]','一聲白雁度江潮，便覺金陵王氣銷。',32,'全唐诗/poet.song.238000.json','["一聲白雁度江潮，便覺金陵王氣銷。", "畫史不知亡國恨，猶將鉛粉記前朝。"]'),
('a128e13a-18f1-4ee9-b6a0-bf149d634004','小桃源','詹復','宋','宋诗','song-poetry','','[]','遠尋瑤草到仙家，衝破雲間一片霞。',32,'全唐诗/poet.song.238000.json','["遠尋瑤草到仙家，衝破雲間一片霞。", "道士不知興廢事，又來溪上種桃花。"]'),
('66c0ab3c-7b66-4c31-b544-38a733d8c925','峽中和卜彥才韻','方逢振','宋','宋诗','song-poetry','','[]','尹躬樂不在耕莘，樂在明明以及民。',64,'全唐诗/poet.song.238000.json','["尹躬樂不在耕莘，樂在明明以及民。", "貪看回頭多應錯，偶聞變色始知真。", "聖賢氣象心爲大，天地根萌人是仁。", "認著濂溪窗草意，自家胸次一般春。"]'),
('41cfe79c-d644-4edd-9658-ae5dfea01f31','峽塾講中庸第二章詩','方逢振','宋','宋诗','song-poetry','','[]','滔滔逝者若斯夫，不有耆儒孰共扶。',64,'全唐诗/poet.song.238000.json','["滔滔逝者若斯夫，不有耆儒孰共扶。", "昭揭五條皆遠道，由來一本不殊途。", "聖賢奧義難窮盡，老筆名言妙寫模。", "我欲研硃同點易，先生肯位此中無。"]'),
('17129d30-c8d4-4d99-b9a9-233328001b4d','次盧月山賀建造韻','方逢振','宋','宋诗','song-poetry','','[]','轍雪營巢近歲除，樵奴溪友落成初。',64,'全唐诗/poet.song.238000.json','["轍雪營巢近歲除，樵奴溪友落成初。", "卜鄰喜有玉川子，作計拚爲陶隱居。", "架上多儲韓杜卷，案頭不著老莊書。", "乾坤自有關心事，非是幽人偏愛廬。"]'),
('e8fdff64-073d-4784-81ef-7bfd96fdb90b','至元廿四年十一月二十日得宣命詣朝可菴有詩不敢當次韻以謝  其一','方逢振','宋','宋诗','song-poetry','','[]','雪棹殷勤泛剡溪，吟香爲拂案頭埃。',64,'全唐诗/poet.song.238000.json','["雪棹殷勤泛剡溪，吟香爲拂案頭埃。", "老軀久已乞骸去，瘦骨應難入畫來。", "但願東皇憐病瘦，早從西華覓雲臺。", "當年自是渠無分，明主何曾棄不才。"]'),
('cc89d75e-139d-4340-a0e0-4915b1bfa7c9','至元廿四年十一月二十日得宣命詣朝可菴有詩不敢當次韻以謝  其二','方逢振','宋','宋诗','song-poetry','','[]','抱琴來會錦沙溪，音響能清一世埃。',64,'全唐诗/poet.song.238000.json','["抱琴來會錦沙溪，音響能清一世埃。", "不學晉人反招隱，頗知陶令欲歸來。", "羨君雪裏騎驢興，哀我年前戲馬臺。", "留取老翁看雲月，乾坤撐拓賴奇才。"]'),
('8f4019ba-1f1a-47a0-864f-b0d07e5fc235','風潭精舍月夜偶成','方逢振','宋','宋诗','song-poetry','','[]','茅屋三間一塢雲，此窩真足養吾神。',64,'全唐诗/poet.song.238000.json','["茅屋三間一塢雲，此窩真足養吾神。", "不知逐鹿斷蛇手，但見落花啼鳥春。", "石几梅瓶添水活，地爐茶鼎煮泉新。", "古今天地何窮盡，愧我其間作散人。"]'),
('30b1d1ec-911f-48be-bddb-370b66bd9d3f','挽諫坡居士','方逢振','宋','宋诗','song-poetry','','[]','諫議村中一布衾，幽潛兩事最堪稱。',64,'全唐诗/poet.song.238000.json','["諫議村中一布衾，幽潛兩事最堪稱。", "瘞骸鬼結來生草，削髪僧然後夜燈。", "螭篆淒涼嗟老鈍，薤章鳴咽動親朋。", "羨公有子能如此，多少英雄叫不譍。"]'),
('8143f686-df9f-430d-b89d-521caa216918','贈相士葉秋月','方逢振','宋','宋诗','song-poetry','','[]','麻衣道眼明如月，學士神仙带不來。',32,'全唐诗/poet.song.238000.json','["麻衣道眼明如月，學士神仙带不來。", "天上貴人若相問，只渭三字畫爐灰。"]'),
('5442f203-4bf3-474d-994a-923d1be66079','江湖穩處','方逢振','宋','宋诗','song-poetry','','[]','此舟無物本來虛，萬斛清香只有詩。',32,'全唐诗/poet.song.238000.json','["此舟無物本來虛，萬斛清香只有詩。", "昨夜潮頭高幾丈，老僧睡著不曾知。"]'),
('6a5e4d30-8241-428e-a8dd-4997edfb0bc8','贈山屋相士','方逢振','宋','宋诗','song-poetry','','[]','圓顱方趾具仁端，性體由來只一般。',32,'全唐诗/poet.song.238000.json','["圓顱方趾具仁端，性體由來只一般。", "若見裏頭腔子黑，相書已作死人看。"]'),
('4eef4a1f-680e-4388-8fd5-7509040223eb','悼亡祕書','方逢振','宋','宋诗','song-poetry','','[]','翠華東南來，奎聚屬吳域。',144,'全唐诗/poet.song.238000.json','["翠華東南來，奎聚屬吳域。", "分王百餘年，靈光赫天德。", "龍文發南源，圓書粲東壁。", "誰折天罅開，猝忽正氣泄。", "剖藏發金櫃，抉藴破石室。", "籤怕逐汗牛，至珍去遐絕。", "我欲然藜人，四庫亦赤立。", "細人慕所愛，但嗟珠玉翼。", "君子爲道謀，惟憂孔孟北。", "風氣日已趨，南強變金革。", "周禮吾能言，欲徵恐無籍。", "落落星向晨，後生當努力。"]'),
('e38e5bc5-0f43-4db7-aa47-015ebdb46f84','毛伯玉以六月廿七日來訪是年天不雨梅亢熱異常書數韻述懷且以贈之','方逢振','宋','宋诗','song-poetry','','[]','伯玉不我過，過我必六月。',156,'全唐诗/poet.song.238000.json','["伯玉不我過，過我必六月。", "老天雨不梅，五行一乃絕。", "亢離單用事，赤烏赤如血。", "人寰何辠辜，幾欲炮烙殺。", "左手解衣襟，右手不停箑。", "脫帽無奈何，而況可腰折。", "西望禽鬼焦，東望金魚涸。", "前山牛眠洿，亦復如火發。", "相携將安之，只合坐論說。", "伯玉老先輩，家傳洞林訣。", "談辯管郭雄，五鬼皆避易。", "借君鐵拄杖，蹴踏六月雪。", "爲我買雪山，斵冰作天穴。"]'),
('525b4b29-8e3c-4133-8191-3b0595950852','庚寅人日雨夕大雷電激而成雹陽專而陰不勝寒反爲燠復雷雹大雨彌旬燠極而霰繼以大雪三日深山盈丈自人日至晦凡二十三日雨雹霰雪農民告苦爲二十韻以記之','方逢振','宋','宋诗','song-poetry','','[]','龍馬交戰相長雄，一勝一負互始終。',176,'全唐诗/poet.song.238000.json','["龍馬交戰相長雄，一勝一負互始終。", "二氣脅擊威力窮，凝冰迸出焦火中。", "跳丸飛砲怒打空，一夜白盡午頭峰。", "頃田十萬銀裹封，東皇未肯開冶鎔。", "山眩水晃人滅蹤，癡猿凍鶴驚折松。", "鄰雞失旦僧懶鐘，昏曉不辨天地聾。", "鹽虎坐險終陷凶，獰獅見日空眼紅。", "書生徑臥身龍鍾，諷諫不到齊王宮。", "灞陵無驢句不工，萬家醜怪難形容。", "我聞古語盈尺豐，今深一丈愁殺農。", "欲將此意問天公，天公高高高幾重。"]'),
('16308a62-68df-4e9f-af0e-d3ec399676f2','翰林將指下學峽賓聲叟爲諸友先雨雪載途民亦勞止一詩懷之','方逢振','宋','宋诗','song-poetry','','[]','空山雪片大如盤，有客遠在孤館眠。',128,'全唐诗/poet.song.238000.json','["空山雪片大如盤，有客遠在孤館眠。", "翰林喝馬不到地，白帝叱馭親行鞭。", "疾驅滕六笞飛廉，六花急舞狂且顛。", "玉皇香案口讀宣，深衣大带依然仙。", "東里先生履欲穿，濕透布襪枵嚢纏。", "高談雄辯罏亭邊，不有義意誰肯前。", "陽羨山中春信傳，兩驂已發垂虹鞭。", "諸君急棹山陰船，子猷逸興今翻然。"]'),
('55065146-be3c-41c3-8f92-eafda8f06b13','茶具一贄鮮于伯機','方逢振','宋','宋诗','song-poetry','','[]','惠山天下第一泉，陽羨百草不敢先。',168,'全唐诗/poet.song.238000.json','["惠山天下第一泉，陽羨百草不敢先。", "二絕獨與端石便，不受翠鐵黄金煎。", "古來風韻擅玉川，日高丈五猶打眠。", "山中舊事今不然，石銚不在坡爐塼。", "伯機卓犖美少年，好官不做自取廉。", "床頭月俸無一錢，手續陸羽經二篇。", "我有片石出古端，瓜師斵成無脚鐺。", "爲君置之書几邊，自汲活水烹新煙。", "不待七碗肌骨仙，飛去玉皇香案前。", "天公高高望眼穿，百姓墮落深深淵，無人敢說江南天。"]'),
('f8285cf4-49c5-4ba1-b8f3-e792a706968f','示湖田菴僧','方逢振','宋','宋诗','song-poetry','','[]','千里渴驥奔橫川，萬松滴翠蜿蜒盤。',200,'全唐诗/poet.song.238000.json','["千里渴驥奔橫川，萬松滴翠蜿蜒盤。", "我來廬墓分一龕，紙窗搖動卓錫泉。", "鑄鐘𩊭鼓買祭田，雲冠雪衲聊結緣。", "崑崙石壁蛟龍淵，呵禁守護靈物專。", "六根五藴洗不蠲，山鬼不肯降太顛。", "內熱正坐饑火煎，睡蛇滅盡方安眠。", "君不見溈山禪，剛把鐵牛鼻孔穿。", "犯人禾稼痛撻鞭，常見迥迥在我前。", "又不見高公嵬，天遣妖魔下玉軿。", "試我楞壁堅，不知死灰無復燃。", "我遊諸方三十年，出入無界參人天。", "不羨翬紺碧捐金錢，不羨高堂會食羅大午，只羨當年開祖師賢。"]'),
('af7b1c3c-143d-47b2-aef7-fd852ebe7da1','送姪隆吉作遂安教諭','方逢振','宋','宋诗','song-poetry','','[]','舊時州置文學掾，南宮集英大學選。',192,'全唐诗/poet.song.238000.json','["舊時州置文學掾，南宮集英大學選。", "英雄壯志必此爭，飯囊郡庠奴隸縣。", "今時學籍難登天，青山□老天厭。", "蟻蜁驢磨猶自癡，不釋不玄良覺窘。", "南州諭缺數百員，得即忻忻不得慍。", "他年一些錄繇此遷，視博士員居四緊。", "博士以上梯級危，仕至泮宮鑽天令。", "小阮膽大志復狂，拔起泥中尤自奮。", "不顧在列嘲好爲，濫取皋比得家便。", "天上知心愛屋烏，尚覺知心相勉勸。", "弘文弟子需補員，徑合翰林集賢院。", "我欲勸子入翰林，却恐遠嫁難爲情。"]'),
('9390d68e-0eda-4789-bbed-b3a483cf97b5','賀蛟峰先生得孫','方逢振','宋','宋诗','song-poetry','','[]','翁年六十九，大郎才得孫。',120,'全唐诗/poet.song.238000.json','["翁年六十九，大郎才得孫。", "五行不孤亢，停當乾與坤。", "於焉觀於穆，孝悌天已根。", "賢愚一任汝，鞠育推予恩。", "我觀人祖心，恨不見曾元。", "曾元日以遠，多至昧厥源。", "惟有眉山家，潁弟坡爲昆。", "慶圖掛高堂，幼幼而尊尊。", "代昌賢才出，根碩枝葉煩。", "願是我家兒，庶幾大吾門。"]'),
('0cbe5d5f-08a5-4418-88c5-05dd65ef6a10','鳳潭精舍偶成','方逢振','宋','宋诗','song-poetry','','[]','茅屋三間一塢雲，此窩真足養吾神。',64,'全唐诗/poet.song.238000.json','["茅屋三間一塢雲，此窩真足養吾神。", "不知逐鹿斷蛇手，但見落花啼鳥春。", "石几梅瓶添水活，地爐茶鼎煮泉新。", "古今天地何窮盡，媿我其間作散人。"]'),
('0744b8bc-0edf-46c0-b10b-3ca163abcd3e','贈山房先生得宣命','何昭德','宋','宋诗','song-poetry','','[]','飛鳳翩翩下九閽，先生出處重斯文。',64,'全唐诗/poet.song.238000.json','["飛鳳翩翩下九閽，先生出處重斯文。", "不將鐘鼎易朱紱，要老桐山守白雲。", "處士一生純是晉，逸民千古尚爲殷。", "皇家恩意如天大，定把三峰乞與君。"]'),
('d2d3c7d5-4bff-4488-9344-01ef76271d6b','賀山房先生得宣命','盧珏','宋','宋诗','song-poetry','','[]','自從驄馬到清溪，浄洗江山絕點埃。',64,'全唐诗/poet.song.238000.json','["自從驄馬到清溪，浄洗江山絕點埃。", "霜月高擎隨地轉，春風吹喜自天來。", "皇華禮遣榮花縣，宣命恩濃出柏臺。", "海內蒼生望霖雨，廟堂正要棟梁材。"]'),
('73d181e0-b64c-4aea-8569-4e66e581664c','天邊風露樓漫題','盧珏','宋','宋诗','song-poetry','','[]','十二闌干俯碧溪，憑高一覽萬山低。',65,'全唐诗/poet.song.238000.json','["十二闌干俯碧溪，憑高一覽萬山低。", "晴灘歷歷輕帆上，煙樹重重幽鳥啼。", "但覺興隨流水遠，不知身與白雲齊。", "年來先寄東君信，多種梅花在屋衹要。"]'),
('0e75a538-13a1-4d5e-aa5c-83597623c5f2','慈井','方山京','宋','宋诗','song-poetry','','[]','古井千年尚著名，只緣慈孝不勝情。',32,'全唐诗/poet.song.238000.json','["古井千年尚著名，只緣慈孝不勝情。", "碧煙自好濃霜白，何必溪流擅獨清。"]'),
('c505c114-acd8-4b6b-854f-b193748cf372','重遊臨武秀巖  其一','曾晞顔','宋','宋诗','song-poetry','','[]','瓊樓玉宇落荒村，雞犬無聲到洞門。',65,'全唐诗/poet.song.238000.json','["瓊樓玉宇落荒村，雞犬無聲到洞門。", "采鳳久藏丹穴羽，青蓮倒續華峯根。", "笑談疑歪風宮商應，剜刻渾無斧鑿痕。", "莫訝空中能卓立，亭亭一柱拄乾坤。"]'),
('d7d61336-badb-4ae4-9ad3-3eb57b2e0cfa','重遊臨武秀巖  其二','曾晞顔','宋','宋诗','song-poetry','','[]','十番春事付風埃，屐齒參經識蒼苔。',64,'全唐诗/poet.song.238000.json','["十番春事付風埃，屐齒參經識蒼苔。", "野鳥避人猶巧語，山花向日儘遲開。", "奇峯自是平地起，活水不知何處來。", "天若便教羈馽脫，寧須海上覓蓬萊。"]'),
('6e31f598-d7f9-4b37-9a02-f30415966b37','四柏亭','孔夢斗','宋','宋诗','song-poetry','','[]','道鄉採芹暇，手植四株柏。',132,'全唐诗/poet.song.238000.json','["道鄉採芹暇，手植四株柏。", "相對有正味，愛此歲寒格。", "忠言賈奇禍，幾削諫臣跡。", "柏亦助道鄉，每號風雨夕。", "柏死公不死，大名日皦白。", "後人補種之，存棠思召伯。", "亭亭儼相持，撐雲空百尺。", "是柏出雖晚，風致猶古昔。", "我來跂遺芳，清坐假一席。", "徘徊意難捨，猛把闌干拍。", "寄語景行人，用意幸勿窄。"]'),
('f8fdd8c2-e941-4f73-a989-6752f48b5266','神燈','朱天民','宋','宋诗','song-poetry','','[]','昔向長老說，北山有神燈。',168,'全唐诗/poet.song.238000.json','["昔向長老說，北山有神燈。", "六月神初度，邑人競高登。", "夜深無消息，忽其見崚嶒。", "璀璨作奇葩，點綴橫玉繩。", "漸漸出陰壑，兩兩度松藤。", "乍明既倏晦，此沒或彼興。", "光中若有人，前後相參承。", "久久乃散去，各自爲儕朋。", "神意會羣望，歡盡車方升。", "我家枕朔岡，夢寐雲氣騰。", "日暮啟窗戶，揮扇卻炎蒸。", "跂于默一祝，祥光來相應。", "體大赤杲日，中瑩融明冰。", "此乃少爲貴，羣囑當未曾。"]'),
('097a3673-7321-49af-9e8d-c18f53e768b7','襄樊失守','彭秋宇','宋','宋诗','song-poetry','','[]','六年援絕困重圍，到此無謀更出奇。',64,'全唐诗/poet.song.238000.json','["六年援絕困重圍，到此無謀更出奇。", "慷慨如張雖有愧，孤窮似李亦堪悲。", "列城寒月驚鴻散，夷路西風哨馬馳。", "機速房深謀畫處，豈無高着活危棋。"]'),
('b34aad14-d88d-4caa-9f65-5d85b8b4e2aa','江上師潰','彭秋宇','宋','宋诗','song-poetry','','[]','江上西風督戍秋，國人延頸捷隨收。',65,'全唐诗/poet.song.238000.json','["江上西風督戍秋，國人延頸捷隨收。", "中宵棄甲三軍潰，往歲藏已經百戰休。", "甚羨虞公前采石，可憐下謂後雷州。", "諸賢着意籌新局，嫠婦如今正有憂。"]'),
('c4ee30f3-f7fa-417d-bdeb-d7d317d0bd2e','南征','彭秋宇','宋','宋诗','song-poetry','','[]','聖皇神武志規恢，南國胡爲貢未來。',64,'全唐诗/poet.song.238000.json','["聖皇神武志規恢，南國胡爲貢未來。", "銅柱地荒雲隔斷，珠崖天聖鴈飛回。", "秋風曾見秦師出，曉日今聞漢詔哀。", "中國有人終慕化，且看萬象樂春臺。"]'),
('6b98eb84-2833-42c9-8094-cce6e4db7b36','再平南擾','彭秋宇','宋','宋诗','song-poetry','','[]','乾坤重闢八荒春，何事中間有末臣。',64,'全唐诗/poet.song.238000.json','["乾坤重闢八荒春，何事中間有末臣。", "南粵一隅先漢地，陽樊數世有周民。", "山川慣識旌旗影，道路長愁士馬塵。", "聞說討平歸奏凱，剩俘女子載珠珍。"]'),
('0c36b1c4-aeb7-4f87-b485-af14c7e144c6','西風','彭秋宇','宋','宋诗','song-poetry','','[]','邊笳悽慘動江城，朔鴈南飛幾陣橫。',64,'全唐诗/poet.song.238000.json','["邊笳悽慘動江城，朔鴈南飛幾陣橫。", "雲氣昏昏秋萬里，旄頭烱烱夜三更。", "向來海上鳬毛出，何日關中馬角生。", "天地無情豪傑盡，西風顛倒若爲情。"]'),
('eb38afbb-bb38-4462-917a-a4f435ffc4d1','庚申喜聞','彭秋宇','宋','宋诗','song-poetry','','[]','萬方歡喜醉春風，數路飛書奏凱同。',64,'全唐诗/poet.song.238000.json','["萬方歡喜醉春風，數路飛書奏凱同。", "天擬諸公扶社稷，人言多難識英雄。", "周邦雖小名猶正，楚國方強力易窮。", "從此東南基岱岳，好磨崖石頌成功。"]'),
('849f5487-8f03-4a4f-b793-675bdc1f4c60','邊事','彭秋宇','宋','宋诗','song-poetry','','[]','邊頭無日不秋風，薦食無厭更啟戎。',64,'全唐诗/poet.song.238000.json','["邊頭無日不秋風，薦食無厭更啟戎。", "誰擁貔貅專玉帳，不收鸚鵡着金籠。", "江曾飛度量絲熟，襄已重圍墮甑同。", "安得扶持今社稷，重來韓岳數英雄。"]'),
('a780d6ad-9ae6-4e20-8a0c-faa1ba648585','乙亥紀聞','彭秋宇','宋','宋诗','song-poetry','','[]','羽書朝暮漲氛埃，天詔勤王起草萊。',64,'全唐诗/poet.song.238000.json','["羽書朝暮漲氛埃，天詔勤王起草萊。", "寒上風高鷹颺去，江頭霧暗馬飛來。", "諸賢忠愛謀安出，四將英靈喚不回。", "漠漠雪天秋萬里，飛鳴無數鴈鴻哀。"]'),
('df747dad-50b9-44a6-96af-0ee64f9cabc4','乙亥冬','彭秋宇','宋','宋诗','song-poetry','','[]','禍亂方來苦不禁，此生誰料有如今。',64,'全唐诗/poet.song.238000.json','["禍亂方來苦不禁，此生誰料有如今。", "四郊雲擾旌旗影，諸閫風寒社稷心。", "杞國有人憂凜凜，桃源無路入深深。", "少陵野老懷忠憤，醉裏攢眉強自吟。"]'),
('274a6d92-b695-4229-85cc-e407f18ba1e4','讀吟嘯集  其一','彭秋宇','宋','宋诗','song-poetry','','[]','興廢明知數有天，臣心感激義當然。',64,'全唐诗/poet.song.238000.json','["興廢明知數有天，臣心感激義當然。", "孔明尚欲西都蜀，王蠋寧甘北面燕。", "鳳鶴不靈凄落日，蛟龍已逝冷長川。", "丈夫一爲綱常死，表表人間萬古傳。"]'),
('c22d1be8-d5f9-4361-bed8-bfea331a97a9','讀吟嘯集  其二','彭秋宇','宋','宋诗','song-poetry','','[]','力支大廈烱孤忠，太息黄旗運不東。',64,'全唐诗/poet.song.238000.json','["力支大廈烱孤忠，太息黄旗運不東。", "天若有情虹貫日，人誰不死氣凌空。", "倍增晁董儒科重，可與夷齊史傳同。", "地位九分人物好，更於何處覓英雄。"]'),
('ef0f7e7b-acaa-4b2b-8cd5-35ca362010c6','秋興  其一','彭秋宇','宋','宋诗','song-poetry','','[]','沙塵破褐客秋風，落落親朋半老翁。',64,'全唐诗/poet.song.238000.json','["沙塵破褐客秋風，落落親朋半老翁。", "野曠有時聞嘯虎，天寬無處寄征鴻。", "四方玉帛燕山北，萬里帆檣海水東。", "回首可憐歌舞地，芳花石礎樹陰中。"]'),
('496bae57-3935-4fda-b2aa-679b0e15c526','秋興  其二','彭秋宇','宋','宋诗','song-poetry','','[]','西風捲地送凄涼，目斷歸帆落日黄。',64,'全唐诗/poet.song.238000.json','["西風捲地送凄涼，目斷歸帆落日黄。", "鴈過江天雲漠漠，龍遊滄海水茫茫。", "故人入夢三更月，近事驚心兩鬢霜。", "試把濁醪澆磊磈，樽中猶带芷蘭香。"]'),
('c7af38d2-0e0f-4819-829e-279d51a805f9','世事','彭秋宇','宋','宋诗','song-poetry','','[]','茫茫世事等浮萍，愁緒方濃醉又醒。',64,'全唐诗/poet.song.238000.json','["茫茫世事等浮萍，愁緒方濃醉又醒。", "日月雙飛天不老，干戈百戰地常腥。", "此時弓馬多秦戍，何日衣冠見漢庭。", "宇宙西風愁不盡，誰家門巷草青青。"]'),
('5f702289-7e2f-453b-9a5c-577c171f908a','聞鬼','彭秋宇','宋','宋诗','song-poetry','','[]','荒郊白骨臥枯莎，有鬼銜冤苦奈何。',64,'全唐诗/poet.song.238000.json','["荒郊白骨臥枯莎，有鬼銜冤苦奈何。", "半夜數聲凄枕席，十年幾度慘干戈。", "英魂無託子孫絕，史筆不知忠義多。", "欲反髑髏生世樂，近來富貴亦消磨。"]'),
('fbe4e156-6035-4691-a006-d8abb1453ec9','感舊','彭秋宇','宋','宋诗','song-poetry','','[]','五更漏盡醉魂醒，誰富胸中十萬兵。',64,'全唐诗/poet.song.238000.json','["五更漏盡醉魂醒，誰富胸中十萬兵。", "如昔襄陽堅砥柱，至今江左屹金城。", "南來鐵馬吹唇沸，北去銅人淚眼盈。", "聞說錢塘風景異，胥濤猶有不平鳴。"]'),
('d133461f-e096-4437-8749-3d9e528431c1','罪言','彭秋宇','宋','宋诗','song-poetry','','[]','四境風寒滿目秋，區區嫠婦深憂。',63,'全唐诗/poet.song.238000.json','["四境風寒滿目秋，區區嫠婦深憂。", "豈無豪傑二三策，亦有東南百十州。", "斫案肯迎新造魏，揮戈曾復舊宗周。", "倉公一望休驚走，好把囊中暝眩投。"]'),
('1183659e-1e5f-4cd1-acb9-862ad9550a0c','閑愁','彭秋宇','宋','宋诗','song-poetry','','[]','江橫天塹湧鯨波，信是閑愁兩鬢皤。',64,'全唐诗/poet.song.238000.json','["江橫天塹湧鯨波，信是閑愁兩鬢皤。", "上界有春娛日月，中原無夢冷山河。", "扶持宇宙人非少，經濟風濤論儘多。", "昨夜甘泉烽火急，禁中拊髀憶廉頗。"]'),
('3538be7a-bd1b-42e6-8580-4226b230f7f3','感舊','彭秋宇','宋','宋诗','song-poetry','','[]','督府由來十十六秋，幾回祈去幾回留。',66,'全唐诗/poet.song.238000.json','["督府由來十十六秋，幾回祈去幾回留。", "人稱姬旦三朝輔，誰羨鴟夷一舸遊。", "葛嶺春風天地醉，蕪湖夜月戰事今愁。", "平生心事青編在，身與皇家共戚休。"]'),
('b84cf332-7ce3-41b7-97f7-141d32cd7860','感時','林伯元','宋','宋诗','song-poetry','','[]','舊穀新絲價未平，田苗一半屬官青。',32,'全唐诗/poet.song.238000.json','["舊穀新絲價未平，田苗一半屬官青。", "白頭老子面如鬼，倚杖開門見彗星。"]'),
('1e4d60ae-5027-4639-8396-f9a3e4ecb2a7','題衢州驛舍','衢州士人','宋','宋诗','song-poetry','','[]','午夫荷擔在山阿，膏血如何有許多。',32,'全唐诗/poet.song.238000.json','["午夫荷擔在山阿，膏血如何有許多。", "不若扁舟竟歸去，休從清獻墓前過。"]'),
('912cfc51-5824-4dee-88ae-712df51c3b9d','詩三首  其一','嚴中和','宋','宋诗','song-poetry','','[]','山中道人不裹巾，一片石床生綠鱗。',32,'全唐诗/poet.song.238000.json','["山中道人不裹巾，一片石床生綠鱗。", "昨夜瓦瓶冰凍破，梅花無水自精神。"]'),
('3789a1c6-fb17-4ba1-b47d-8fc12ceac523','詩三首  其二','嚴中和','宋','宋诗','song-poetry','','[]','梅天雨氣入簾櫳，衣潤頻添柏火烘。',32,'全唐诗/poet.song.238000.json','["梅天雨氣入簾櫳，衣潤頻添柏火烘。", "四月江南無矮樹，人家都在綠陰中。"]'),
('7bb9942a-db30-4aaf-a392-1d8b3b7acead','詩三首  其三','嚴中和','宋','宋诗','song-poetry','','[]','一聲杜宇三更後，向曉綠陰連碧苔。',32,'全唐诗/poet.song.238000.json','["一聲杜宇三更後，向曉綠陰連碧苔。", "却恨樓高春數尺，柳綿飛不上窗來。"]'),
('0102a066-3f10-45af-8270-086fc5ec5a51','月夜看桂','嚴中和','宋','宋诗','song-poetry','','[]','玉杵聲中舞素娥，西風葉葉自婆娑。',32,'全唐诗/poet.song.238000.json','["玉杵聲中舞素娥，西風葉葉自婆娑。", "一天清氣無人管，惟有山樓樹影多。"]'),
('865e0d4e-83b5-4ee1-a312-61afa8106566','句  其一','嚴中和','宋','宋诗','song-poetry','','[]','樹影踏不碎，花香嗅却無。',12,'全唐诗/poet.song.238000.json','["樹影踏不碎，花香嗅却無。"]'),
('5eb4d3f5-6d4f-4af0-baeb-0120758f9cd9','句  其二','嚴中和','宋','宋诗','song-poetry','','[]','寺老柳遮塔，雨多春礙船。',12,'全唐诗/poet.song.238000.json','["寺老柳遮塔，雨多春礙船。"]'),
('605316fe-6b1e-4815-b3cc-85db8f8e498d','句  其三','嚴中和','宋','宋诗','song-poetry','','[]','澗水活不凍，山楓老自靈。',12,'全唐诗/poet.song.238000.json','["澗水活不凍，山楓老自靈。"]'),
('d97da44a-213d-4916-9bf8-192b0dbba06a','句  其四','嚴中和','宋','宋诗','song-poetry','','[]','畫扇題詩鸞背濕，銅彝煎腦鴨心香。',16,'全唐诗/poet.song.238000.json','["畫扇題詩鸞背濕，銅彝煎腦鴨心香。"]'),
('5fde8586-2ff1-4cc8-bda8-38bab7150dfb','冬日','翁定遠','宋','宋诗','song-poetry','','[]','遲明騎馬謁朱門，安得梅花入夢魂。',32,'全唐诗/poet.song.238000.json','["遲明騎馬謁朱門，安得梅花入夢魂。", "慚愧高人眠正熟，一生知不受人恩。"]'),
('927584f6-59a5-4206-904a-c26d38077587','題廨壁','士人某','宋','宋诗','song-poetry','','[]','霜拂金鞍玉墜腰，鄰雞催喚紫宸朝。',32,'全唐诗/poet.song.238000.json','["霜拂金鞍玉墜腰，鄰雞催喚紫宸朝。", "爭如林下飽清夢，殘月半窗松影搖。"]'),
('3c56d859-3d6c-46c2-91d0-27ba856d2d0b','於朱宣慰家作畫訖作','釋子溫','宋','宋诗','song-poetry','','[]','昔有朱買臣，今有朱宣慰。',24,'全唐诗/poet.song.238000.json','["昔有朱買臣，今有朱宣慰。", "兩個擔柴失，並皆金紫貴。"]'),
('4b32b6cd-33d5-4c87-82d5-619412352565','題畫葡萄','釋子溫','宋','宋诗','song-poetry','','[]','曾向流沙取梵書，草龍珠帳滿征途。',32,'全唐诗/poet.song.238000.json','["曾向流沙取梵書，草龍珠帳滿征途。", "輕句短策難將带，記得西風月上初。"]'),
('9daa1b86-f0fe-4845-96fb-695eb73367a6','題葡萄圖','釋子溫','宋','宋诗','song-poetry','','[]','明月清風宗炳社，夕陽秋色庾公樓。',32,'全唐诗/poet.song.238000.json','["明月清風宗炳社，夕陽秋色庾公樓。", "修心未到無心地，萬種千般逐水流。"]'),
('8c446bcc-f652-47b8-8025-185ac7e70359','天台陳石居出示乃祖梅隱先生遺稿其序中所載與友人馮使君入蜀之事可傷因賦四十字','呂勝之','宋','宋诗','song-poetry','','[]','臨文增太息，復見此人不。',48,'全唐诗/poet.song.238000.json','["臨文增太息，復見此人不。", "義重午金諾，身輕萬里遊。", "好詩今寡和，壯志古難酬。", "一盞梅花露，年年薦隴頭。"]'),
('d73d488a-87db-4f02-8d89-6b8db657b6ba','題周草窗江村小景扇面','呂勝之','宋','宋诗','song-poetry','','[]','飛鷺落鳬渚，山花燦如繡。',24,'全唐诗/poet.song.238000.json','["飛鷺落鳬渚，山花燦如繡。", "愛閑人不來，柴門掩春晝。"]'),
('a19bf9a5-a02e-4e6c-9822-77b5237e00e5','晉王大令保母帖','王沂孫','宋','宋诗','song-poetry','','[]','脫落黄祊帖，按辭大令書。',168,'全唐诗/poet.song.238000.json','["脫落黄祊帖，按辭大令書。", "稍作蘭亭面，七美諒非虛。", "或訝缺勿毀，或疑集悲夫。", "考真固云癖，訂僞亦以愚。", "第觀竁中藏，清玩唯研壺。", "晉人擅風流，宜與後世殊。", "所惜尚言數，卜年八百餘。", "貞石久且泐，雙松當幾枯。", "片磗曷未化，逮茲厄耕鋤。", "方其內幽鐫，要以托荒墟。", "孰知坐此故，反能誤意如。", "傳世豈所幸，況遭孽韓汙。", "辨端更爲累，但資文字娛。", "陶土或若此，何爲殉玉魚。"]'),
('c4042dc0-f2d0-4ee7-b330-0aa44769453f','觀周曾秋塘圖有作','王沂孫','宋','宋诗','song-poetry','','[]','秋，秋。',70,'全唐诗/poet.song.238000.json','["秋，秋。", "蕭灑，清幽。", "人靜處，水邊頭。", "波細紋紋，風色颼颼。", "鷗鷺情相狎，鳬鴛樂自由。", "疎葦敗荷池沼，白蘋紅蓼汀洲。", "幾竿漁釣去已盡，一段晚雲寒不收。"]'),
('9d53a4da-1567-49d0-a066-dd9ddd78d097','夢中作','陳觀國','宋','宋诗','song-poetry','','[]','水聲兮激激，雲容兮茸茸。',78,'全唐诗/poet.song.238000.json','["水聲兮激激，雲容兮茸茸。", "千松拱綠，萬荷奏紅。", "爰宅茲巖，以逸放翁。", "屹萬仞與世隔，峻一極而天通。", "予乃控野鶴，追冥鴻，往來乎蓬萊之宮。", "披海氛而一笑，以觀九州之同。"]'),
('07f3054c-5833-42b8-97c7-0e9be9b5eda2','送鄧牧心出陶山','陳觀國','宋','宋诗','song-poetry','','[]','青山無送迎，幽人自來去。',68,'全唐诗/poet.song.238000.json','["青山無送迎，幽人自來去。", "落葉若相送，卷卷及行屨。", "簷端有孤雲，仍爲守其處。", "落葉惜人不在山，孤雲尚期人再還。", "斯人可期復可惜，我處落葉孤雲間。"]'),
('29dd1cbc-5cc9-4a44-ade6-3242f522d62f','游九鎖山','陳觀國','宋','宋诗','song-poetry','','[]','名山隔游塵，九鎖塵更少。',120,'全唐诗/poet.song.238000.json','["名山隔游塵，九鎖塵更少。", "閒雲抱蒼石，古澗茁靈草。", "一亭瞰蛟舞，曾此憩坡老。", "水性自云靜，潴洩寄人巧。", "聊復助奇觀，未須縱瀾倒。", "小挹丹泉潤，側步石壁峭。", "洞深篝火入，志險極幽討。", "人間幾何年，仙迹棋未了。", "向夕山月吐，光碎松下道。", "天空瓊館寒，禽響藥如搗。"]'),
('b4bf4314-7643-4f5e-bd21-f17ed31aceef','送劉蒙川','陳一齋','宋','宋诗','song-poetry','','[]','春草征帆遠，春江落日程。',48,'全唐诗/poet.song.238000.json','["春草征帆遠，春江落日程。", "瘴鄉官是客，儒服老談兵。", "海闊龍無影，山空鳳不鳴。", "梅花東閣路，悽斷故人情。"]'),
('0f377c8f-dba6-446d-a936-409d5cfbac5d','谿亭次汪桐陽','陳一齋','宋','宋诗','song-poetry','','[]','空亭明遠嶂，老樹黯餘矄。',48,'全唐诗/poet.song.238000.json','["空亭明遠嶂，老樹黯餘矄。", "野興臨流坐，秋聲入夜聞。", "漁歸孤棹月，鶴睡一松雲。", "記得前溪路，人家兩岸分。"]'),
('eb679a7b-4ee1-4677-9ea4-ab720bb26522','維揚懷項朴菴','陳一齋','宋','宋诗','song-poetry','','[]','長鋏悲彈負壯遊，京華倦客又揚州。',64,'全唐诗/poet.song.238000.json','["長鋏悲彈負壯遊，京華倦客又揚州。", "西風昨夜他鄉夢，明月故人何處樓。", "石塔鐘殘楓葉暝，瓜州棹遠荻花秋。", "幽窗一點寒燈影，徙倚闌干生暮愁。"]'),
('4ab28c75-ca71-41e5-b9e2-a62e0dbe8702','句','梅州民','宋','宋诗','song-poetry','','[]','曾氏井泉千古冽，蒲侯心事一般清。',16,'全唐诗/poet.song.238000.json','["曾氏井泉千古冽，蒲侯心事一般清。"]'),
('138878a6-d471-4b3b-9cac-59caed7e85fb','投蒲壽宬  其一','潮州書生','宋','宋诗','song-poetry','','[]','梅花落地點蒼苔，天意商量要入梅。',32,'全唐诗/poet.song.238000.json','["梅花落地點蒼苔，天意商量要入梅。", "蛺蝶不知春去也，雙雙飛過粉牆來。"]'),
('515723db-b662-4b35-a924-bcdd15cac75f','投蒲壽宬  其二','潮州書生','宋','宋诗','song-poetry','','[]','劍戟紛紛扶主日，山林寂寞閉門時。',32,'全唐诗/poet.song.238000.json','["劍戟紛紛扶主日，山林寂寞閉門時。", "水聲禽語皆時事，莫道山翁總不知。"]'),
('62183e13-bc59-4826-b092-4d76eb5d0cae','贈金仁山  其一','唐良驥','宋','宋诗','song-poetry','','[]','公已蒼頭我黑頭，兩情常得守清幽。',64,'全唐诗/poet.song.238000.json','["公已蒼頭我黑頭，兩情常得守清幽。", "紛紛世事浮雲變，汩汩人生逝水流。", "行止何期南又北，交情又見夏還秋。", "可堪天意常如此，只合無心任去留。"]'),
('7ea20226-ee8d-407a-9791-4a12a3d11b90','贈金仁山  其二','唐良驥','宋','宋诗','song-poetry','','[]','命有窮時道不窮，命窮何處更求通。',64,'全唐诗/poet.song.238000.json','["命有窮時道不窮，命窮何處更求通。", "此生未老應須學，萬事由來要適中。", "物欲盡時心始曠，天真動處氣初融。", "百般佳處難形狀，自與常人迥不同。"]'),
('3a271c6b-b8e8-40c5-be2e-ce5d575daba9','威烈王','徐鈞','宋','宋诗','song-poetry','','[]','大柄潛移勢可憂，朝綱未正況諸侯。',32,'全唐诗/poet.song.238000.json','["大柄潛移勢可憂，朝綱未正況諸侯。", "時人只咎輕分晉，不道東西已剖周。"]'),
