('0698448c-6ced-4356-876e-6377bcf2fe01','寇恂','徐鈞','宋','宋诗','song-poetry','','[]','王郎百萬肆憑陵，誰集漁陽上谷兵。',32,'全唐诗/poet.song.238000.json','["王郎百萬肆憑陵，誰集漁陽上谷兵。", "一剪妖氛河北定，中興從此創基成。"]'),
('505cb876-4e6a-4810-8782-3369e9379a77','馮異','徐鈞','宋','宋诗','song-poetry','','[]','舊是起兵時主簿，今爲大樹下將軍。',32,'全唐诗/poet.song.238000.json','["舊是起兵時主簿，今爲大樹下將軍。", "若看勸帝施恩語，俁獨區區戰伐勳。"]'),
('41754f70-be9e-41ae-9723-e0cc6c337816','岑彭','徐鈞','宋','宋诗','song-poetry','','[]','雨驟風馳善用兵，公孫擊地嘆如神。',32,'全唐诗/poet.song.238000.json','["雨驟風馳善用兵，公孫擊地嘆如神。", "如何壁壘疏防夜，已悟彭亡竟殞身。"]'),
('e0f130a2-e446-4c09-9fb7-cc55c4445049','賈復','徐鈞','宋','宋诗','song-poetry','','[]','驍勇稱奇賜左驂，潰圍解急敵心寒。',32,'全唐诗/poet.song.238000.json','["驍勇稱奇賜左驂，潰圍解急敵心寒。", "卒能剽甲敦儒學，可作尋常武將看。"]'),
('09266d2c-a10f-411d-b46b-8d04d49c713b','吳漢','徐鈞','宋','宋诗','song-poetry','','[]','智謀勇畧已過人，況擁幽州突騎兵。',32,'全唐诗/poet.song.238000.json','["智謀勇畧已過人，況擁幽州突騎兵。", "拉朽摧枯功蓋世，可令縱掠損威名。"]'),
('7401768c-85a0-41bb-bb92-a7e3145b0c5f','耿弇','徐鈞','宋','宋诗','song-poetry','','[]','馳召蕭王命罷兵，獻謀懷貳見尤明。',32,'全唐诗/poet.song.238000.json','["馳召蕭王命罷兵，獻謀懷貳見尤明。", "平齊定趙基圖壯，有志方知事竟成。"]'),
