('314c2ba2-6381-497f-bc07-d1af66934d87','馬融','徐鈞','宋','宋诗','song-poetry','','[]','士迫饑寒已變初，權門寧免曳長裾。',32,'全唐诗/poet.song.238000.json','["士迫饑寒已變初，權門寧免曳長裾。", "帳紗所學明何事，却陷忠良草奏書。"]'),
('13648cb6-e87d-40bb-9a53-e826fd545590','胡廣','徐鈞','宋','宋诗','song-poetry','','[]','六朝黄髪老三公，固位依違善取容。',32,'全唐诗/poet.song.238000.json','["六朝黄髪老三公，固位依違善取容。", "真是鄉原爲德賊，如何至德比中庸。"]'),
('7c2f14d0-82e0-43c1-9581-9c4f7d273a36','茅容','徐鈞','宋','宋诗','song-poetry','','[]','一雞供母不供賓，主亦無慚賓不嗔。',32,'全唐诗/poet.song.238000.json','["一雞供母不供賓，主亦無慚賓不嗔。", "禮遇何須分厚薄，論交只是貴清真。"]'),
('1ece1589-ffae-4ef4-8eaa-95e04c566aa5','徐穉','徐鈞','宋','宋诗','song-poetry','','[]','萬里冥鴻惜羽毛，安車雖聘邈難招。',32,'全唐诗/poet.song.238000.json','["萬里冥鴻惜羽毛，安車雖聘邈難招。", "清名自足高天下，豈獨南州擅得高。"]'),
('319908e7-7b42-48b7-a3cc-0fbca3a8f4aa','姜肱','徐鈞','宋','宋诗','song-poetry','','[]','畫手尚難圖我貌，安車何可屈吾身。',32,'全唐诗/poet.song.238000.json','["畫手尚難圖我貌，安車何可屈吾身。", "惟餘爭死同衾事，千載稱爲孝友人。"]'),
('234a70a2-1ee2-43db-93fc-2da1bd064ac1','陳蕃','徐鈞','宋','宋诗','song-poetry','','[]','身居一室尚凝塵，天下如何掃得清。',32,'全唐诗/poet.song.238000.json','["身居一室尚凝塵，天下如何掃得清。", "須信修齊可平治，絕憐志大竟無成。"]'),
('4639b847-0240-4aaf-be2c-2ce796c0ed11','荀淑','徐鈞','宋','宋诗','song-poetry','','[]','家號八龍名父子，學傳二李好師生。',32,'全唐诗/poet.song.238000.json','["家號八龍名父子，學傳二李好師生。", "風標想見當時少，況是閑居絕宦情。"]'),
('e58ef952-325e-45a9-b743-61c900ce2216','陳寔','徐鈞','宋','宋诗','song-poetry','','[]','世多揚激伯夷隘，公獨謙虛下惠和。',32,'全唐诗/poet.song.238000.json','["世多揚激伯夷隘，公獨謙虛下惠和。", "弔死自慚知己少，逃生却喜活人多。"]'),
('f1d75b97-8e47-4dd0-8a42-4281619333d2','范滂','徐鈞','宋','宋诗','song-poetry','','[]','慨然攬轡志澄清，一激誰知黨禍成。',32,'全唐诗/poet.song.238000.json','["慨然攬轡志澄清，一激誰知黨禍成。", "母子可憐終死別，庶幾廣孝在揚名。"]'),
('1434a3b3-9b9b-4b32-a111-2c2bf4b17a33','劉寵','徐鈞','宋','宋诗','song-poetry','','[]','門無吏擾夜安眠，前守何如此守賢。',32,'全唐诗/poet.song.238000.json','["門無吏擾夜安眠，前守何如此守賢。", "却是山民纏舊習，區區相送尚持錢。"]'),
