('ab4f2a8a-74ec-4290-89e1-c1fb75f1763a','元結','徐鈞','宋','宋诗','song-poetry','','[]','漫勞當日牧舂陵，立石尤多感德民。',32,'全唐诗/poet.song.238000.json','["漫勞當日牧舂陵，立石尤多感德民。", "獨有磨崖碑故在，文章千古耀湘濱。"]'),
('2a6ba36f-4270-481b-9dd2-db21688976e8','啖助','徐鈞','宋','宋诗','song-poetry','','[]','談經唐世豈無人，君獨春秋學最深。',32,'全唐诗/poet.song.238000.json','["談經唐世豈無人，君獨春秋學最深。", "力辯邱陽非左氏，後來朱子始知音。"]'),
('6d37ff97-14f5-4a64-bd99-e7561b8bc5ae','張志和','徐鈞','宋','宋诗','song-poetry','','[]','細雨斜風一釣絲，綠簑青笠鎮相隨。',32,'全唐诗/poet.song.238000.json','["細雨斜風一釣絲，綠簑青笠鎮相隨。", "朝廷休覓漁歌看，萬頃千波總是詩。"]'),
('d7a84646-48b1-4714-8799-51bac38c4e00','嚴武','徐鈞','宋','宋诗','song-poetry','','[]','蜀政貪殘豈自全，母心直向死方安。',32,'全唐诗/poet.song.238000.json','["蜀政貪殘豈自全，母心直向死方安。", "如何三度專方面，不博庭闈一餉歡。"]'),
('ec7c5a6f-9619-4355-959c-2feef466ce6a','崔祐甫','徐鈞','宋','宋诗','song-poetry','','[]','道德馳聲滿建中，豈無人可繼餘風。',32,'全唐诗/poet.song.238000.json','["道德馳聲滿建中，豈無人可繼餘風。", "最憐貞觀開元治，付與奸邪蕞陋翁。"]'),
('fbeeebaa-83c6-4d4c-8dce-2a9ed724034b','題壁','趙良埈','宋','宋诗','song-poetry','','[]','三北何人知管仲，五湖何處覓陶朱。',32,'全唐诗/poet.song.238000.json','["三北何人知管仲，五湖何處覓陶朱。", "壁間遺墨還堪睹，吊罷靈魂一束芻。"]'),
('a862524b-0842-4207-8931-d8e94af30485','鳳凰谷','趙良埈','宋','宋诗','song-poetry','','[]','羅浮絕頂凌蒼穹，五雲飛繞蓬萊宮。',112,'全唐诗/poet.song.238000.json','["羅浮絕頂凌蒼穹，五雲飛繞蓬萊宮。", "金烏玉兔出西東，鐵橋萬丈橫霽虹。", "臥虎踞石龍蟠松，異香不動煙騰空。", "餐霞飲露凡聖同，水簾碎玉聲玲瓏。", "桃花流出片片紅，碧梧翠竹環三峯。", "天邊鳳鳥來雝雝，仙風吹入石洞中。", "我欲呼之儀九重，歌舞聖化同天功。"]'),
('d354fbc7-eac2-405e-9b22-ada56418ac00','鄉飲酒唱和詩','趙良埈','宋','宋诗','song-poetry','','[]','警書雙羽出乎西，端坐凝香惡境移。',64,'全唐诗/poet.song.238000.json','["警書雙羽出乎西，端坐凝香惡境移。", "已鑄劍鋒成耒耜，更陶瓦缶作尊彝。", "雅南歌裏聲千古，乾巽維邊位兩儀。", "細數旴江知郡事，有如此事幾人知。"]'),
('aabf24a5-9693-4257-81b9-8fc7942c053e','鄉飲酒唱和詩','張肅','宋','宋诗','song-poetry','','[]','位分南北與東西，曠典纔修俗頓移。',64,'全唐诗/poet.song.238000.json','["位分南北與東西，曠典纔修俗頓移。", "樂合鸞皇下庭宇，觶揚虎蜼伏樽彝。", "頭顱如許堪殊席，筋力無多奈縟儀。", "敢昧邦君明德意，後知方遣負先知。"]'),
('819dff2b-4ca5-46b5-b62d-c3ec82772ae7','勉子讀書','趙崇濘','宋','宋诗','song-poetry','','[]','男兒立志要崚嶒，莫與閭閻較重輕。',64,'全唐诗/poet.song.238000.json','["男兒立志要崚嶒，莫與閭閻較重輕。", "一寸光陰無放過，十年燈火夙修成。", "學疏達境還堪愧，道在窮途亦可亨。", "未必儒冠能見悮，書窗努力繼芳聲。"]'),
('6a72b228-1424-4796-aff4-7ad5d85df939','浯溪','戴煜','宋','宋诗','song-poetry','','[]','斷崖文字是唐碑，無限名賢贊頌詩。',32,'全唐诗/poet.song.238000.json','["斷崖文字是唐碑，無限名賢贊頌詩。", "莫把中興？前代，會須重見太平時。"]'),
('368a1593-7e3f-4dff-8030-d3c4876376be','嘲丁大全  其一','林桂龍','宋','宋诗','song-poetry','','[]','一舵中流欠把持，偏輕偏重失便宜。',32,'全唐诗/poet.song.238000.json','["一舵中流欠把持，偏輕偏重失便宜。", "孤舟不是無人渡，身作風波問阿誰。"]'),
('413f8d63-a4dc-47d7-ae0b-6e2d4cb10282','嘲丁大全  其二','林桂龍','宋','宋诗','song-poetry','','[]','移溪實壑誤明君，驚動沿江十萬軍。',32,'全唐诗/poet.song.238000.json','["移溪實壑誤明君，驚動沿江十萬軍。", "幸是不沈湘水死，有何面目見靈均。"]'),
('8d31bf8f-42c3-4138-8fa7-9a9bef72a1af','嘲丁大全  其三','林桂龍','宋','宋诗','song-poetry','','[]','稚子如何濟急流，一篙才錯便難收。',32,'全唐诗/poet.song.238000.json','["稚子如何濟急流，一篙才錯便難收。", "當初把作尋常看，豈料中流解覆舟。"]'),
('3c44c56a-315f-4b9a-8867-5e8ede643efb','題魏鵬臥屏','賈雲華','宋','宋诗','song-poetry','','[]','花柳芳菲二月時，名園剩有牡丹枝。',32,'全唐诗/poet.song.238000.json','["花柳芳菲二月時，名園剩有牡丹枝。", "風流杜牧還知否，莫恨尋春去較遲。"]'),
('7a3b80e3-6ef5-467f-b1cc-7f90c84487d3','魏鵬負期醉臥戲題練裙','賈雲華','宋','宋诗','song-poetry','','[]','暮雨朝雲少定蹤，空勞神女下巫峰。',32,'全唐诗/poet.song.238000.json','["暮雨朝雲少定蹤，空勞神女下巫峰。", "襄王自是無情緒，醉臥明月花影中。"]'),
('bf47b256-fe75-42fc-9901-3396ab5fbee0','七夕','賈雲華','宋','宋诗','song-poetry','','[]','斜軃香雲倚翠屏，紗衣先覺露華零。',32,'全唐诗/poet.song.238000.json','["斜軃香雲倚翠屏，紗衣先覺露華零。", "誰云天上無離合，看取牽牛織女星。"]'),
('ffcd912a-968e-48ea-a406-2274ccdb4401','永別  其一','賈雲華','宋','宋诗','song-poetry','','[]','自從消瘦減容光，雲雨巫山枉斷腸。',32,'全唐诗/poet.song.238000.json','["自從消瘦減容光，雲雨巫山枉斷腸。", "獨宿孤房淚如雨，秋宵只爲一人長。"]'),
('d5103afc-445c-4d86-a6ea-f2884905d5af','永別  其二','賈雲華','宋','宋诗','song-poetry','','[]','正成薄命久尋思，宛轉蛾眉能幾時。',32,'全唐诗/poet.song.238000.json','["正成薄命久尋思，宛轉蛾眉能幾時。", "漢水楚雲千萬里，留君不住益凄其。"]'),
('f6bbdfdc-efe7-4f5d-8f28-4692c8098fe0','永別  其三','賈雲華','宋','宋诗','song-poetry','','[]','物換星移幾度秋，鳥啼花落水空流。',32,'全唐诗/poet.song.238000.json','["物換星移幾度秋，鳥啼花落水空流。", "人間何事堪惆悵，貴賤同歸土一丘。"]'),
('d3a7c6f2-98f7-4ac1-a6b0-d441af1cf0bb','永別  其四','賈雲華','宋','宋诗','song-poetry','','[]','相見時難別亦難，寒潮惟带夕陽還。',32,'全唐诗/poet.song.238000.json','["相見時難別亦難，寒潮惟带夕陽還。", "鈿蟬金雁皆零落，離別煙波傷玉顔。"]'),
('8d8df183-8d6e-4031-b5f6-ab2c170ea379','永別  其五','賈雲華','宋','宋诗','song-poetry','','[]','倚欄無語倍傷情，鄉思撩人撥不平。',32,'全唐诗/poet.song.238000.json','["倚欄無語倍傷情，鄉思撩人撥不平。", "寂寞閑庭春又晚，杏花零落過清明。"]'),
('9cf7d4c8-4b20-4f6a-b94e-eae8ca58544f','永別  其六','賈雲華','宋','宋诗','song-poetry','','[]','紗窗日落漸黄昏，春夢無心只似雲。',32,'全唐诗/poet.song.238000.json','["紗窗日落漸黄昏，春夢無心只似雲。", "萬里關山音信斷，將身何處更逢君。"]'),
('a4b21b5a-a975-44d8-b915-8fdbea85e109','永別  其七','賈雲華','宋','宋诗','song-poetry','','[]','魂歸冥漠魄歸泉，却恨青娥誤少年。',32,'全唐诗/poet.song.238000.json','["魂歸冥漠魄歸泉，却恨青娥誤少年。", "三尺孤墳何處是，每逢寒食一潸然。"]'),
('a07a997c-25b5-4d76-a4ef-dac55232aad4','永別  其八','賈雲華','宋','宋诗','song-poetry','','[]','一封書寄數行啼，莫動哀吟易慘凄。',32,'全唐诗/poet.song.238000.json','["一封書寄數行啼，莫動哀吟易慘凄。", "古往今來只如此，幾多紅粉委黄泥。"]'),
('4ea41082-5ef4-4491-8ffc-e63d35f3eeaa','集元刺史句詠寒亭','杜子是','宋','宋诗','song-poetry','','[]','長山繞井邑，嘐嘐天外青。',96,'全唐诗/poet.song.238000.json','["長山繞井邑，嘐嘐天外青。", "煙雲無近遠，水石何幽清。", "半崖盤石徑，如見小蓬瀛。", "時節方大暑，忽若秋氣生。", "高亭臨極巓，登高宜新晴。", "俗士誰能來，野客熙清陰。", "漫歌無人聽，在酒共我傾。", "時復一回望，心月出四溟。"]'),
('11a29684-145f-4e5b-9e7a-a59e554bdabc','送西秦張仲實遊大滌洞天','金應桂','宋','宋诗','song-poetry','','[]','山林有真趣，得趣即神仙。',48,'全唐诗/poet.song.238000.json','["山林有真趣，得趣即神仙。", "好趁暮春月，來遊大滌天。", "晴嵐融玉室，花氣襲丹泉。", "此地通懸霤，清吟過叔元。"]'),
('e764f4b7-49b2-405d-9e59-0091d02d6e8c','絕命詞','邊居誼','宋','宋诗','song-poetry','','[]','孤城高倚漢江秋，血戰三年死未休。',32,'全唐诗/poet.song.238000.json','["孤城高倚漢江秋，血戰三年死未休。", "鐵石肝腸忠義膽，精靈常向峴山留。"]'),
('e5e97e8d-fc66-4050-8c72-e74f97809add','今朝','李智遠','宋','宋诗','song-poetry','','[]','四十三年處世中，夢中成夢又成空。',32,'全唐诗/poet.song.238000.json','["四十三年處世中，夢中成夢又成空。", "今朝撒手還歸去，木馬頻嘶物外風。"]'),
('78a69ce2-1545-4f28-bc4c-765cd0cfa124','春日田園雜興','劉汝鈞','宋','宋诗','song-poetry','','[]','年來夢斷百花場，安分農桑萬慮降。',64,'全唐诗/poet.song.238000.json','["年來夢斷百花場，安分農桑萬慮降。", "爲喜麥青行暖逕，因看蠶出倚晴窗。", "草坪閒見烏犍點，畬水飛來白鷺雙。", "滿飲茅柴拚爛醉，踏歌社下自成腔。"]'),
('3c8f5d4f-3f9f-4175-9dae-03182a1b1a3c','次胡濟鼎同年三律  其一','曹涇','宋','宋诗','song-poetry','','[]','五經爲笥腹便便，千佛名髙此作緣。',64,'全唐诗/poet.song.238000.json','["五經爲笥腹便便，千佛名髙此作緣。", "貴仕直堪梅和鼎，貧交猥爲酒供錢。", "連章秋月鴈回翅，貯袖天香龍吐涎。", "舊話新情如覿面，同年真是我同年。"]'),
('eaa8fb34-a0a5-4dd1-bee9-3cbfc9951a19','次胡濟鼎同年三律  其二','曹涇','宋','宋诗','song-poetry','','[]','共是金明衣緑郎，梅仙風致壓仇香。',64,'全唐诗/poet.song.238000.json','["共是金明衣緑郎，梅仙風致壓仇香。", "人如紫鳯儀丹閣，誰則青蚨涴錦囊。", "洛社菜羮時不禁，雪堂斗酒夜宜良。", "至尊端肯憐芹曝，臣罪當誅自恐惶。"]'),
('8f32b203-e48b-4403-b5f1-1be41e7ad80f','次胡濟鼎同年三律  其三','曹涇','宋','宋诗','song-poetry','','[]','費却長吟復短吟，投瓜投李愧何深。',64,'全唐诗/poet.song.238000.json','["費却長吟復短吟，投瓜投李愧何深。", "吾人只記錢留紙，此老能令戶作金。", "擲地有聲知處處，如蘭斯臭見心心。", "柏梁體後八仙賦，趾美重光未陸沉。"]'),
('7512f324-a885-454c-87b1-59e8340351f0','次胡餘學同年四首  其一','曹涇','宋','宋诗','song-poetry','','[]','對看中秋是好天，健來欣爲子分田。',64,'全唐诗/poet.song.238000.json','["對看中秋是好天，健來欣爲子分田。", "只消菽水歡無盡，况有經書腹可便。", "家事既傳情思穏，吟篇謾寫墨痕鮮。", "惟餘學課隨年捱，共我艱劬知幾員。"]'),
('49888e4b-ae7a-46fc-b328-46e8d095c7e8','次胡餘學同年四首  其二','曹涇','宋','宋诗','song-poetry','','[]','金明池上共揚鞭，豪氣寧求許祀田。',64,'全唐诗/poet.song.238000.json','["金明池上共揚鞭，豪氣寧求許祀田。", "不道福碑轟忒早，相逢頹景穏爲便。", "牙牌刻處謾誇貴，藍綬披來難敵鮮。", "千歲儘長公論在，于中定有好官員。"]'),
('6d1a1390-0a9b-4407-8eb2-55d5f9f04b11','次胡餘學同年四首  其三','曹涇','宋','宋诗','song-poetry','','[]','桃花柳絮及春敷，壹是浮輕匪壯圖。',64,'全唐诗/poet.song.238000.json','["桃花柳絮及春敷，壹是浮輕匪壯圖。", "幸有田耕幷井飲，猶勝身屨與妻纑。", "郎君競爽賢聲起，老子尊安道味腴。", "便是當年正考父，是間饘粥口堪糊。"]'),
('1ef5ea27-805e-489c-869b-d2c13193542c','次胡餘學同年四首  其四','曹涇','宋','宋诗','song-poetry','','[]','力田元不怵凶饑，瘠者爲誰誰是肥。',64,'全唐诗/poet.song.238000.json','["力田元不怵凶饑，瘠者爲誰誰是肥。", "但得髙堂翁媪健，定知奕世子孫宜。", "追風騏驥驟仍蹶，覽徳鸞鳯棲或飛。", "有酒急須頻對月，桂枝香了到梅枝。"]'),
('89e91061-7fec-43ba-84bc-5ee8ede02268','代柬濟鼎同年約其早飯','曹涇','宋','宋诗','song-poetry','','[]','小人難與作緣，惡食不妨志道。',28,'全唐诗/poet.song.238000.json','["小人難與作緣，惡食不妨志道。", "猶勝杜陵岳陽，一飯欲從人討。"]'),
('c4ce4cd8-788b-4201-b4e3-df8908d6121a','曉發姑孰城','吳龍翰','宋','宋诗','song-poetry','','[]','鵑啼驚夢敧春枕，花落迎風打曉窗。',32,'全唐诗/poet.song.238000.json','["鵑啼驚夢敧春枕，花落迎風打曉窗。", "攜杖攙先出城去，角聲吹月墮寒江。"]'),
('038d9ce9-234b-403a-9892-4aff495fd3ef','浙江姚樓觀水月','吳龍翰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','翠滚玻璃萬頃秋，長江又掛水晶毬。',32,'全唐诗/poet.song.238000.json','["翠滚玻璃萬頃秋，長江又掛水晶毬。", "水光月色梅邉客，今夜會盟江上樓。"]'),
('e1dcd250-d8b2-40b1-9424-bbb889869bf9','晚舟過臨平','吳龍翰','宋','宋诗','song-poetry','','[]','烟鐘舂起夕陽愁，淼淼臨平春事幽。',32,'全唐诗/poet.song.238000.json','["烟鐘舂起夕陽愁，淼淼臨平春事幽。", "惟有風蒲愛吟客，岸邉繚亂綰行舟。"]'),
('e426f5c7-f4ee-45b4-b75b-c2c353316bad','春晚留淮上','吳龍翰','宋','宋诗','song-poetry','','[]','淮山歴歴春雲澹，淮水湯湯夜月輝。',32,'全唐诗/poet.song.238000.json','["淮山歴歴春雲澹，淮水湯湯夜月輝。", "此處杜鵑啼不到，江南行客未成歸。"]'),
('b8942d0f-b202-4a70-942c-8f7cd5ad9b73','贈謁士','吳龍翰','宋','宋诗','song-poetry','','[]','一掬鄉心寒似月，半生行跡過於雲。',32,'全唐诗/poet.song.238000.json','["一掬鄉心寒似月，半生行跡過於雲。", "春風滿擔詩千首，是處青山留得君。"]'),
('271a1b0b-aa8e-4e5f-bbf0-d1e051266e78','白紵詞','吳龍翰','宋','宋诗','song-poetry','','[]','吴宫烟水碧迢迢，瓊樓十二凌青霄。',88,'全唐诗/poet.song.238000.json','["吴宫烟水碧迢迢，瓊樓十二凌青霄。", "北方佳人顔如花，素衣濯濯明朝霞。", "雲母屏風珍珠箔，香銷金鴨春寒薄。", "璧月流光羅綺筵，白紵舞殘月欲落。", "君看月落夜潮平，吴江濶兮越江深。", "吴王醉兮越王醒。"]'),
('f14575b5-a153-4627-a47a-aa2de4d57a60','嘉禾舟中','吳龍翰','宋','宋诗','song-poetry','','[]','天與東風便，千錢買一舟。',48,'全唐诗/poet.song.238000.json','["天與東風便，千錢買一舟。", "嘉禾三月路，陰木四山秋。", "野色緘詩思，鵑聲替客愁。", "烟波渺無際，是處可盟鷗。"]'),
('1c200d94-dd4d-4a36-97b3-b51c68a43f23','嘉禾沈園','吳龍翰','宋','宋诗','song-poetry','','[]','景物何其異，虚岩人力成。',48,'全唐诗/poet.song.238000.json','["景物何其異，虚岩人力成。", "清池沈鳥影，高樹落蟬聲。", "花日樓臺麗，香風簾幙輕。", "我来一吟賞，不惜買杯傾。"]'),
('5967445f-8457-4865-861d-1c639ebf83d2','重陽客中','吳龍翰','宋','宋诗','song-poetry','','[]','愁裏重陽近，他鄉酒易酤。',48,'全唐诗/poet.song.238000.json','["愁裏重陽近，他鄉酒易酤。", "秋風詩髩短，寒夜客燈孤。", "笋笠月穿破，荷衣霜打枯。", "有懐吟未就，端不爲催租。"]'),
('f31271a6-f254-4a4f-8f4a-f50bd03a1aaa','見劉後村先生  其一','吳龍翰','宋','宋诗','song-poetry','','[]','天禄臞仙後代孫，巍科幾世屬名門。',64,'全唐诗/poet.song.238000.json','["天禄臞仙後代孫，巍科幾世屬名門。", "千年絕學追先聖，四海真儒仰後村。", "直向天邊扶日月，只從筆底轉乾坤。", "年来諸老凋零盡，惟有靈光獨自存。"]'),
('12881729-d202-4466-bff7-fe15fe0c5203','見劉後村先生  其二','吳龍翰','宋','宋诗','song-poetry','','[]','玻璃萬頃海天秋，相國如居天上頭。',64,'全唐诗/poet.song.238000.json','["玻璃萬頃海天秋，相國如居天上頭。", "錦帳圍山丹荔熟，銀梭織水子魚遊。", "地靈自古稱多士，人物當今列上流。", "二季一翁家學在，湄洲即是蜀眉州。"]'),
('0e3eb67e-c4a0-489e-9d85-1f678f75a764','見劉後村先生  其三','吳龍翰','宋','宋诗','song-poetry','','[]','雪碗冰甌淬筆鋒，篇篇琢出玉玲瓏。',64,'全唐诗/poet.song.238000.json','["雪碗冰甌淬筆鋒，篇篇琢出玉玲瓏。", "鶴鳴逺岫千林曉，鯨展洪濤萬里雄。", "暮雪寒梅吟思外，春風芳草夢魂中。", "詩瓢行脚半天下，多謝先生棒喝功。"]'),
('3c3a6cdb-8a71-4179-8907-29db08b75676','見劉後村先生  其四','吳龍翰','宋','宋诗','song-poetry','','[]','騎却青鸞上禁林，岩岩聲價重於金。',64,'全唐诗/poet.song.238000.json','["騎却青鸞上禁林，岩岩聲價重於金。", "花磚日轉瓊箋暖，蓮燭星歸玉漏沈。", "翰墨挈来三昧手，絲綸畫出九重心。", "春風已築沙堤路，天上虚皇屬意深。"]'),
('89b1e92c-64db-44fc-a9bf-beebd04fc1e0','西湖曲','吳龍翰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里風光烟水白，嵯峨帝城紫霧隔。',163,'全唐诗/poet.song.238000.json','["十里風光烟水白，嵯峨帝城紫霧隔。", "笛聲吹斷蒲葉風，鷺飛界破青山色。", "湖波鱗鱗織成縠，翠蓋紅幢機上簇。", "長安冨兒美少年，馬行紫陌香塵撲。", "畫舫誰家窈窕娘，半額鵞黄時様粧。", "玉手折花嬌無力，花枝斜掛銀絲長。", "隔花躊蹰意相屬，稍稍談笑聞餘香。", "夕陽西下漢水逺，無計問覔雙瓊璫。", "巫山高哉但入夢，安得插翅飛其傍。", "君不見吳姬采蓮自唱曲，君王尚在舟中宿。"]'),
('e205cb67-e23f-4641-a5f3-ddab2a16cad1','拜林和靖墓','吳龍翰','宋','宋诗','song-poetry','','[]','老鶴髙飛入白雲，空餘殘照管孤墳。',32,'全唐诗/poet.song.238000.json','["老鶴髙飛入白雲，空餘殘照管孤墳。", "清風千古鎮長在，見著梅花如見君。"]'),
('95483e0e-ca9b-40d4-9e1e-d51676bb380e','久客湖海買舟西還','吳龍翰','宋','宋诗','song-poetry','','[]','萬里烟波興渺然，片心如在灞橋邉。',32,'全唐诗/poet.song.238000.json','["萬里烟波興渺然，片心如在灞橋邉。", "歸装詩少不成擔，自抝梅花湊滿船。"]'),
('b018bfb3-4537-4aa1-b077-a97015cd1e76','馮永之號冰壺工水墨丹青','吳龍翰','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','半生江海冰壺翁，擔風荷雨七尺笻。',369,'全唐诗/poet.song.238000.json','["半生江海冰壺翁，擔風荷雨七尺笻。", "爛嚼扶葉紫金椹，玉樓光徹十二重。", "飽喫孤山白玉花，一鑿九竅開玲瓏。", "能鉟明月鑄雙眼，故能搜索異景窺神功。", "能穿星斗掛胸次，故能神遊八極之鴻濛。", "手撼烟雲出硯石，酒酣奮筆驅雷風。", "迴山轉海有力量，頃刻鵞溪幻出白練之寒江，碧玉之奇峯。", "瀟湘洞庭忽在眼，冷落烟竹蒼梧空。", "碧天萬里渺無際，但見隠隠歸飛鴻。", "江門過雨涼如許，木落瀟瀟秋滿浦。", "月明何處起漁歌，小艇人歸急搖櫓。", "鷗沙漠漠洲渚昏，無數寒鴉栖古渡。", "景物變態雖無窮，筆端有口一一吐。", "研丹吮粉尤精奇，直與王爵争毫釐。", "寧肯没骨媚時好，逸氣往往追徐熙。", "一點春風幾花卉，化工權柄君所私。", "獻之牸牛韓幹馬，滕王蛺蝶僧繇魚。", "下筆衆妙各俱足，開卷錯落中珠璣。", "顧家層樓連天起，俗士那敢窺藩籬。", "嘔心抽思何自苦，乃使肌骨化作枯松枝。", "君不見梅邉有狂客，風饕雪虐寧忍饑。", "吟軀未老貌先老，不覺兩髩紛如絲。"]'),
('b1a393b1-cab6-4483-94c9-d8869f4d03e0','靈金山觀金燈','吳龍翰','宋','宋诗','song-poetry','','[]','嵯峨靈金山，峭壁偕天長。',288,'全唐诗/poet.song.238000.json','["嵯峨靈金山，峭壁偕天長。", "巑岏萬蒼翠，無復敢頡頏。", "登臨勞逺目，久羈塵俗韁。", "天風送笻屐，此願今一償。", "所喜侍老親，贔屭升崇岡。", "琪樹藹柔絲，瑤草超羣芳。", "松聲入幽懐，妙樂非笙簧。", "好鳥相勸酬，醉我林中觴。", "我吟遊仙詩，客和招隠章。", "起舞沸懽笑，人影亂夕陽。", "何妨阿堵女，山北敞虚堂。", "石池閟甘泉，瓦爐騰妙香。", "昔言山有靈，金燈夜呈祥。", "信哉華嚴經，佛眉施白光。", "澄公有妙力，一笑通禪房。", "詎知山石間，而有金光藏。", "崦嵫下朱景，山氣相激揚。", "若以色見佛，扵法參與商。", "我生事迂濶，咄咄顛復狂。", "讀書獵千古，浩氣凌八荒。", "乃欲落鬚髪，掬水曹溪傍。", "吹以無孔笛，倒騎牛一場。", "手擊混沌開，有此硬脊梁。", "指點生死根，棒喝行諸方。"]'),
('f3ceddcb-7bc5-4d0a-9e4b-fee7b9a13efc','辛酉秋吳畫士寫神','吳龍翰','宋','宋诗','song-poetry','','[]','功名自有兜鍪輩，榮辱寧干蓑笠翁。',32,'全唐诗/poet.song.238000.json','["功名自有兜鍪輩，榮辱寧干蓑笠翁。", "煩作田園秋興畫，短簷斜日稻花風。"]'),
('ebd364b9-21a7-41da-90a5-c99959628d9c','秋崖先生招飲荷葭塢席上賦詩','吳龍翰','宋','宋诗','song-poetry','','[]','相公潭水清於玉，翠屏四面環書屋。',146,'全唐诗/poet.song.238000.json','["相公潭水清於玉，翠屏四面環書屋。", "石梯幽幽登蒼崖，老樹晴烟千頃緑。", "好花對人無俗姿，春色盈盈囿虚谷。", "歸来庭院碧參差，八窗玲瓏有脩竹。", "先生長嘯臨清流，茱萸辛夷香滿洲。", "浪呼迪輩偕春遊，緑醅深注碧玉甌。", "我醉起舞相勸酬，願祝先生相業侔伊周。", "運留侯帷幄之籌，横莱公野水之舟。", "莫負蒼生望安石，東山高卧凌清秋。"]'),
('88bf0b6b-22cb-4700-b7d9-1701babf3c66','京城寓居春日','吳龍翰','宋','宋诗','song-poetry','','[]','春城庭院柳風輕，簾影玲瓏愛曉晴。',32,'全唐诗/poet.song.238000.json','["春城庭院柳風輕，簾影玲瓏愛曉晴。", "紅日半窗吟夢覺，咿啞墻外賣花聲。"]'),
('5c5b1cea-e2f7-41c3-b0f1-cd84ddd1bf1b','宫人斜','吳龍翰','宋','宋诗','song-poetry','','[]','碧石重重鎖墓門，蘭膏點火照黄昏。',32,'全唐诗/poet.song.238000.json','["碧石重重鎖墓門，蘭膏點火照黄昏。", "春風幾度生芳草，還似君王舊日恩。"]'),
('c7643c81-32aa-4260-b0e0-4dc3be1cdd7e','春夜隔江望揚州城','吳龍翰','宋','宋诗','song-poetry','','[]','煙樹蕪城熨不開，夜深燈火照樓臺。',32,'全唐诗/poet.song.238000.json','["煙樹蕪城熨不開，夜深燈火照樓臺。", "欲披紫綺過江去，月冷滄洲待鶴来。"]'),
('a90a4c75-50c7-4f8a-a2e1-e48ccf8b6601','數年前有小詞微雨後落花天嬌態病懨懨怕人猜著是相思鎮日不開簾寶釵横蟬髩亂院宇待人歸儘緩移蓮步玉闌前纎手掐花鈿茲月夜與客飲梅花下一姝歌前詞復出箋徴余新作','吳龍翰','宋','宋诗','song-poetry','','[]','月夜梅花下，開樽誰主賓。',156,'全唐诗/poet.song.238000.json','["月夜梅花下，開樽誰主賓。", "梅花嬌欲語，讓我白頭人。", "娉婷樓上女，無乃花中神。", "下樓款懽笑，莫惜抛千金。", "纎纎出素手，爲我彈瑤琴。", "自言諳古調，妾心合君心。", "感君纒綿意，未彈先有情。", "妾佩明月光，妾衣雲霞輕。", "共君驂白鳳，一息超玉京。", "君看天帝女，嫁與牽牛星。", "天河萬里長，鵲橋歲一陳。", "安得河水乾，夜夜長相親。", "君能挽天河，一洗八極塵。"]'),
('a5dc20b3-3268-4308-b11e-9ee1a2636b19','宫詞','吳龍翰','宋','宋诗','song-poetry','','[]','舞罷霓裳寶髻垂，桃花扇底暖風吹。',32,'全唐诗/poet.song.238000.json','["舞罷霓裳寶髻垂，桃花扇底暖風吹。", "夜深內殿重開宴，手撚燈花畫翠眉。"]'),
('b5d1c818-a24c-4c5c-8ec1-57ac5c3cdfab','秋崖先生以紅石見寄','吳龍翰','宋','宋诗','song-poetry','','[]','彤霞鑠石玉晶熒，琢出羲之風字形。',32,'全唐诗/poet.song.238000.json','["彤霞鑠石玉晶熒，琢出羲之風字形。", "却著寒松蒼石下，研烟傳寫相牛經。"]'),
('000fd767-6f53-46eb-856b-b52741daa3ba','心逺堂','吳龍翰','宋','宋诗','song-poetry','','[]','飄飄謫仙子，閉門逃世諠。',132,'全唐诗/poet.song.238000.json','["飄飄謫仙子，閉門逃世諠。", "達哉柴桑翁，心逺地乃偏。", "羨公隠廛市，高拍前人肩。", "園林富花木，景象羅春妍。", "翠鳥鳴高枝，白魚遊深淵。", "魚鳥欣有託，吾廬興悠然。", "詩瓢貯烟雲，茶鼎烹銀蟾。", "有此佳絕處，那受名利鞭。", "鵲尾聞妙香，片心超九天。", "淵然消萬慮，流光緯三田。", "乾坤任簸弄，追蹤古偓佺。"]'),
('f36d1f23-3d33-4b8c-a618-7498737b545f','持敬堂','吳龍翰','宋','宋诗','song-poetry','','[]','大哉紫陽箴，誠爲百世師。',132,'全唐诗/poet.song.238000.json','["大哉紫陽箴，誠爲百世師。", "心法故能傳，心印幾能提。", "明明道統燈，扵此接光輝。", "端居儼帝臨，暗室疑神窺。", "立足千仞淵，生怕傷髪膚。", "兢兢一寸心，烱烱冰雪壺。", "脱帽藐王公，無乃酒狂徒。", "蹀躞漁陽鼓，傲態逐刑誅。", "我則持以敬，譬如龍戀珠。", "斷斷猫捕鼠，綿綿雞哺雛。", "守之戒勿閑，意馬防馳驅。"]'),
('fa9f4636-20b3-4089-9bd9-69b196040c89','層翠樓','吳龍翰','宋','宋诗','song-poetry','','[]','結樓書屋傍，獨占林塘幽。',132,'全唐诗/poet.song.238000.json','["結樓書屋傍，獨占林塘幽。", "飛檐瞰寒碧，照影虹霓浮。", "層巒萬蒼翠，峭屼生戈矛。", "黛眉與螺髻，故故含嬌羞。", "此時樓中人，片心隨白鷗。", "風吹烏紗帽，露滴紫綺裘。", "白雲入我望，逸興何悠悠。", "沆瀣供晨餐，酌以碧玉甌。", "朝暾散朱景，嚥約十二樓。", "願言追黄鶴，致身八極遊。", "慷慨笛聲發，滿樓明月秋。"]'),
('3a3b93af-7d72-4b3e-b553-274321eeedfb','春寒','吳龍翰','宋','宋诗','song-poetry','','[]','二月漫漫雪滿山，羣芳空向雪中看。',32,'全唐诗/poet.song.238000.json','["二月漫漫雪滿山，羣芳空向雪中看。", "幽亭酌酒且沈醉，要爲小園花餪寒。"]'),
('8ab0dbee-3211-40fe-80a7-056170a592b3','凍吟','吳龍翰','宋','宋诗','song-poetry','','[]','座左插梅花，座右横詩筆。',24,'全唐诗/poet.song.238000.json','["座左插梅花，座右横詩筆。", "風雪墮寒肩，先生方抱膝。"]'),
('9c3ad7db-7aeb-4635-97f7-5bd511f35d9e','春興','吳龍翰','宋','宋诗','song-poetry','','[]','聞說春醪熟，提壺喚客嘗。',24,'全唐诗/poet.song.238000.json','["聞說春醪熟，提壺喚客嘗。", "乾坤一釀甕，花氣百和香。"]'),
('8f81c228-f8fc-4be6-9e16-8d114fc2d2d5','别吴中三年寄湖上一二知已','吳龍翰','宋','宋诗','song-poetry','','[]','麥秋天氣覺清和，老盡春風庭下莎。',64,'全唐诗/poet.song.238000.json','["麥秋天氣覺清和，老盡春風庭下莎。", "晚月荒山啼蜀帝，夕陽髙樹咽齊娥。", "三年寒我滄波約，一夜思君白髪多。", "世路不堪重著脚，相期何地理漁蓑。"]'),
('29d11ae7-8da3-4e64-ac68-348417ebbba4','壽鄉衮訥齋先生  其一','吳龍翰','宋','宋诗','song-poetry','','[]','華衮褒榮御墨鮮，堂堂劍珮在凌烟。',64,'全唐诗/poet.song.238000.json','["華衮褒榮御墨鮮，堂堂劍珮在凌烟。", "十三相後功爲最，五百年間遺有傳。", "落落甘霖施后土，岩岩鉅石補青天。", "太平有筞安排了，浯水清風崖可鎸。"]'),
('77eb477f-1a83-484e-aaed-9d7fe2fbde1d','壽鄉衮訥齋先生  其二','吳龍翰','宋','宋诗','song-poetry','','[]','世態浮雲無定形，先生緑野竟留情。',64,'全唐诗/poet.song.238000.json','["世態浮雲無定形，先生緑野竟留情。", "詎知寶祐老臣在，又見金陵新法行。", "洛邑幾時歸赤舄，東山再起答蒼生。", "不堪局面遲一著，願祝薇垣星更明。"]'),
('a082b31b-1998-42de-9bda-81d543bb239a','壽鄉衮訥齋先生  其三','吳龍翰','宋','宋诗','song-poetry','','[]','當年河嶽已儲神，理亂分明闗一身。',64,'全唐诗/poet.song.238000.json','["當年河嶽已儲神，理亂分明闗一身。", "瑞應麟書知孔子，恩光鳳誥見庚申。", "世臣喬木蒼蒼日，驛使梅花歲歲春。", "笑指紫陽山作壽，會看重慶喜尤新。"]'),
('d5a7f202-4d31-488d-86ed-4cce56d30ee4','感興  其一','吳龍翰','宋','宋诗','song-poetry','','[]','多病頻辭客，無人自掩扉。',48,'全唐诗/poet.song.238000.json','["多病頻辭客，無人自掩扉。", "劚松供藥火，葺葉補漁衣。", "日月雙丸疾，乾坤一粟微。", "不須求外道，悟此是玄機。"]'),
('1b2f92d3-f1ad-4efe-ad5a-630a916aafe9','感興  其二','吳龍翰','宋','宋诗','song-poetry','','[]','野興在漁艇，風潮不憚勞。',48,'全唐诗/poet.song.238000.json','["野興在漁艇，風潮不憚勞。", "苔生肥石骨，水落瘦溪毛。", "霜重稻粱熟，天清雁字髙。", "醉餘歌古調，人事析秋毫。"]'),
('d06af065-4803-46b1-b4e4-d1b2b27a8b49','感興  其三','吳龍翰','宋','宋诗','song-poetry','','[]','閉門逃俗客，攜酒過禪闗。',48,'全唐诗/poet.song.238000.json','["閉門逃俗客，攜酒過禪闗。", "竈古茶烟斷，碑殘雨蘚瘢。", "秋僧行影瘦，夜鶴病翎寒。", "片月隨人到，孤琴對佛彈。"]'),
('95aac754-e664-4f14-9738-c1b4888b7938','感興  其四','吳龍翰','宋','宋诗','song-poetry','','[]','百事謀何拙，一閒夢亦清。',48,'全唐诗/poet.song.238000.json','["百事謀何拙，一閒夢亦清。", "定交毛穎子，結怨孔方兄。", "鶴影雲烟瘦，蟬聲風露輕。", "寸心虛白久，蛻骨待丹成。"]'),
('baa0a1d7-14d0-46da-b8d9-8b39fb4dd1c3','金陵寓樓居','吳龍翰','宋','宋诗','song-poetry','','[]','樓中有酒客身閒，約住孤雲共往還。',32,'全唐诗/poet.song.238000.json','["樓中有酒客身閒，約住孤雲共往還。", "搖落碧桃春欲去，倚闌無語看鍾山。"]'),
('223e35ae-5113-4634-80ac-07eb879bd5c6','過涇邑水西縣尹先伯祖嘗爲邑簿領耆儒有識者','吳龍翰','宋','宋诗','song-poetry','','[]','客裏身無事，乘閒過水西。',48,'全唐诗/poet.song.238000.json','["客裏身無事，乘閒過水西。", "清波明白鷺，緑樹带黄鸝。", "酤酒道旁飲，吟詩石上題。", "邑中逢故舊，坐定說環溪。"]'),
('3fea13a5-0ca8-4858-ab74-5518a33129b1','南陵道中迫暮投茅店四圍率敗籬令僕夫環卧','吳龍翰','宋','宋诗','song-poetry','','[]','故山三百里，歸路正羊腸。',48,'全唐诗/poet.song.238000.json','["故山三百里，歸路正羊腸。", "密樹標茆店，荒池界竹墻。", "僕眠如鹿伏，我倦背龜藏。", "素志非南阮，丈夫掃八荒。"]'),
('7326097b-b423-416d-8bbe-7b933ee8f4c8','泊蕪湖縣','吳龍翰','宋','宋诗','song-poetry','','[]','古邑蒼江曲，鱗鱗華屋横。',48,'全唐诗/poet.song.238000.json','["古邑蒼江曲，鱗鱗華屋横。", "酒樓歌妓集，漁市販夫行。", "野濶雲無勢，江流月有聲。", "橋邊息詩擔，譙鼓更分明。"]'),
('7e199fc8-1a76-4bec-9f38-d31bde7a677e','庚申冬壽秋崖先生','吳龍翰','宋','宋诗','song-poetry','','[]','瑞宿當年降世間，祁山深處著仙壇。',64,'全唐诗/poet.song.238000.json','["瑞宿當年降世間，祁山深處著仙壇。", "梅開冰壑珊瑚瘦，崖聳晴空碧玉寒。", "清氣胚成龜鶴相，丹田煉就虎龍蟠。", "待教鬚髩渾如雪，恰寫耆英與世看。"]'),
('583597d0-da19-453a-92bf-b717bd6eef6e','九日','吳龍翰','宋','宋诗','song-poetry','','[]','秋雨梧桐退老時，寒城九日正霏霏。',64,'全唐诗/poet.song.238000.json','["秋雨梧桐退老時，寒城九日正霏霏。", "功名不直三杯酒，世事真如一局棋。", "頭且插敎黄菊滿，手今莫負紫螯肥。", "壯懐無復登臨恨，破帽西風一任吹。"]'),
('ffa04058-983e-4511-af95-0c3a0dd28fe9','春晚郊行','吳龍翰','宋','宋诗','song-poetry','','[]','芒鞵竹杖出柴闗，檢點園林脚不閒。',64,'全唐诗/poet.song.238000.json','["芒鞵竹杖出柴闗，檢點園林脚不閒。", "翠幄初張花結局，錦棚未解笋排班。", "烟波鷗鷺春風外，桑柘牛羊夕照間。", "野興不須邀客共，一尊白酒對黄山。"]'),
('a3fbdf40-8f19-4c21-ae2b-d4836ad55d3b','秋日遊竹會寺','吳龍翰','宋','宋诗','song-poetry','','[]','修竹陰陰古道場，誰憐兵火地荒涼。',64,'全唐诗/poet.song.238000.json','["修竹陰陰古道場，誰憐兵火地荒涼。", "晚山俱似佛頭緑，秋草不如僧髪長。", "白酒莫辭今日醉，黄花仍作去年香。", "禪翁留客殷勤甚，相對藤床話夕陽。"]'),
('0522e29a-c236-425b-a9b9-8d4dd369a9ab','子陵釣臺','吳龍翰','宋','宋诗','song-poetry','','[]','峭壁千尋屹曉寒，何年人插釣魚竿。',64,'全唐诗/poet.song.238000.json','["峭壁千尋屹曉寒，何年人插釣魚竿。", "烟霞不受衣冠涴，天地那如蓑笠寛。", "幸有同肩黄屋貴，不妨伸脚白雲端。", "能令漢室亦増重，可作巢由一例看。"]'),
('9eb2f3e3-36bb-4263-bb60-f9a3e4fdbd1c','夜泊富陽','吳龍翰','宋','宋诗','song-poetry','','[]','片帆東去一鷗輕，消得天公十日晴。',64,'全唐诗/poet.song.238000.json','["片帆東去一鷗輕，消得天公十日晴。", "新酒一尊詩幾首，故鄉千里月初更。", "烟收山翠揩摩淨，風軟江波熨貼平。", "苦是狂懐費消遣，船頭吹笛到天明。"]'),
('e352236e-7daf-46d0-90f5-a2f2205f3b74','别厲制使','吳龍翰','宋','宋诗','song-poetry','','[]','何日林間理故書，客中歲月只蘧廬。',64,'全唐诗/poet.song.238000.json','["何日林間理故書，客中歲月只蘧廬。", "糴糧半給梅花鶴，燒葉餘分雪後驢。", "蝶夢悠揚家國逺，雁行零落弟兄疎。", "寒花到了自蕭索，不是東風不管渠。"]'),
('38e6a0f2-42c0-48d7-a513-f75be2ee3750','天目道中','吳龍翰','宋','宋诗','song-poetry','','[]','天目峰前小駐驂，長松笑道碧䰐鬖。',64,'全唐诗/poet.song.238000.json','["天目峰前小駐驂，長松笑道碧䰐鬖。", "客懐寂寞秋般淡，醉態朦朧午正酣。", "山色儼如嚴父面，鳥聲還勝俗人談。", "何年来此種芝术，乞與道人雲一龕。"]'),
('0ef79f36-cdf1-4ae7-80a3-b19c56935e4d','春雪','吳龍翰','宋','宋诗','song-poetry','','[]','一雪滿天地，三春景更妍。',48,'全唐诗/poet.song.238000.json','["一雪滿天地，三春景更妍。", "鶴梳瓊羽落，蝶舞粉衣翩。", "嫩柳飄新絮，殘梅補落鈿。", "東風初解凍，洗手破輕烟。"]'),
('efcef425-cbfd-4ba6-8ec0-55fcc002388a','嚴灘對月憶雪壺亡弟','吳龍翰','宋','宋诗','song-poetry','','[]','卯君看月此徘徊，今来月明君不来。',32,'全唐诗/poet.song.238000.json','["卯君看月此徘徊，今来月明君不来。", "安得清光刀剪破，爲分一半到泉臺。"]'),
('1493590d-aad5-44bb-a4e3-eb79f0b8e45c','婺源道中午憇  其一','吳龍翰','宋','宋诗','song-poetry','','[]','小息吟身古木陰，詩情羞澁錦囊輕。',32,'全唐诗/poet.song.238000.json','["小息吟身古木陰，詩情羞澁錦囊輕。", "風烟不受人收拾，擔閣行山半日程。"]'),
('49423b80-3da7-46af-9d74-db4e1f86143a','婺源道中午憇  其二','吳龍翰','宋','宋诗','song-poetry','','[]','滿路黄塵人往還，黄塵點汚幾青山。',32,'全唐诗/poet.song.238000.json','["滿路黄塵人往還，黄塵點汚幾青山。", "便投山店睡過午，要放詩魂出世間。"]'),
('ce67e46e-65c0-4cbf-b898-c080b3bec941','濯足五溪城','吳龍翰','宋','宋诗','song-poetry','','[]','東風吹水緑粼粼，小潄清寒入齒齦。',32,'全唐诗/poet.song.238000.json','["東風吹水緑粼粼，小潄清寒入齒齦。", "萬里流邊濯雙足，恐行五嶺涴晴雲。"]'),
('11c843f7-0fd3-407b-85ce-0ec192a7f8c4','登會稽山','吳龍翰','宋','宋诗','song-poetry','','[]','越上今爲客，息肩春樹林。',48,'全唐诗/poet.song.238000.json','["越上今爲客，息肩春樹林。", "啼鵑歸夢斷，落日旅愁深。", "詩紀一編史，琴傳千古心。", "會須重過此，禹穴一登臨。"]'),
('9d775b9b-e12b-4754-baef-a6831ef47e09','春日吳中','吳龍翰','宋','宋诗','song-poetry','','[]','照人芳樹遲遲日，吹面垂楊拂拂風。',32,'全唐诗/poet.song.238000.json','["照人芳樹遲遲日，吹面垂楊拂拂風。", "客思一笻攜不盡，鳥聲多在落花中。"]'),
('1264573b-785b-44d9-8bfb-bbd19159c773','嘉禾書所見','吳龍翰','宋','宋诗','song-poetry','','[]','翠幙重重護曉寒，窗間金鴨篆烟殘。',32,'全唐诗/poet.song.238000.json','["翠幙重重護曉寒，窗間金鴨篆烟殘。", "芳情不采閒花草，獨倚闌干看牡丹。"]'),
('5df3a3f8-edcf-405e-859f-cd2b24a88112','荷花四絕 露','吳龍翰','宋','宋诗','song-poetry','','[]','一機蜀錦著紗籠，不放纎塵到水宫。',32,'全唐诗/poet.song.238000.json','["一機蜀錦著紗籠，不放纎塵到水宫。", "但覺曉寒金掌重，仙人危立白雲中。"]'),
('0f8d8243-550b-4756-a346-6218de191228','荷花四絕 日','吳龍翰','宋','宋诗','song-poetry','','[]','醉臉潮紅嬌欲眠，玉幢移影蓋嬋娟。',32,'全唐诗/poet.song.238000.json','["醉臉潮紅嬌欲眠，玉幢移影蓋嬋娟。", "一奩晴色開明鏡，暖熨金鑪起碧烟。"]'),
('e61aa75f-15c2-43cc-9db0-178dfa357df0','荷花四絕 風','吳龍翰','宋','宋诗','song-poetry','','[]','颯颯涼生水國秋，可憐無計解花愁。',32,'全唐诗/poet.song.238000.json','["颯颯涼生水國秋，可憐無計解花愁。", "飄然一葉隨流水，付與真人駕作舟。"]'),
('39436385-7f1a-4e4d-95e2-d2810e1c51c9','荷花四絕 雨','吳龍翰','宋','宋诗','song-poetry','','[]','寒聲敲破玉琳琅，綰斷鴛鴦雙夢長。',32,'全唐诗/poet.song.238000.json','["寒聲敲破玉琳琅，綰斷鴛鴦雙夢長。", "幾斛明珠收不起，巧粘翡翠絡紅妝。"]'),
('de83a681-e2c4-435d-b6e3-4be21fda7f6f','俠客行','吳龍翰','宋','宋诗','song-poetry','','[]','擊筑復擊筑，欲歌雙泪横。',24,'全唐诗/poet.song.238000.json','["擊筑復擊筑，欲歌雙泪横。", "寶刀重如命，命如鴻毛輕。"]'),
('511f8f83-7e49-4704-ad68-9e313d189df3','烏棲曲','吳龍翰','宋','宋诗','song-poetry','','[]','風敲玉鈎蝦鬚垂，寒烏棲月萬年枝。',32,'全唐诗/poet.song.238000.json','["風敲玉鈎蝦鬚垂，寒烏棲月萬年枝。", "香薰翠被春宵冷，玉臂曲作珊瑚枕。"]'),
('4e5c0890-03ab-4a91-83b8-eec6fe3b0808','散髮','吳龍翰','宋','宋诗','song-poetry','','[]','玲瓏窗户午晴時，散髪林間自一奇。',64,'全唐诗/poet.song.238000.json','["玲瓏窗户午晴時，散髪林間自一奇。", "鳥睡香奩花影動，蟬吟涼境柳陰移。", "髙山流水琴三弄，明月清風酒一巵。", "要是閉門防俗客，莫令到眼敗吾詩。"]'),
('1d104435-448c-4bcf-8325-338df7fd8e2c','讀岳武穆王傳','吳龍翰','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鬼蜮爲妖天地昏，將軍那可一朝存。',64,'全唐诗/poet.song.238000.json','["鬼蜮爲妖天地昏，將軍那可一朝存。", "泰山頽喻哲人死，東海旱爲孝婦寃。", "當日主和甘下筞，到今無計復中原。", "清風凜凜一編史，拭盡英雄幾泪痕。"]'),
('8366da23-2f94-4595-ad0e-a076cd503179','行春次俞兄韻  其一','吳龍翰','宋','宋诗','song-poetry','','[]','幾日春愁不出行，園林又是了清明。',64,'全唐诗/poet.song.238000.json','["幾日春愁不出行，園林又是了清明。", "春風桃李一場夢，夜月江山千古情。", "吟倚長松伺鶴到，坐臨釣石看雲生。", "此懐不解自拈出，謾語離騷入笛聲。"]'),
('446d937e-f475-4404-8947-2792225ef4d1','行春次俞兄韻  其二','吳龍翰','宋','宋诗','song-poetry','','[]','多謝春風相此行，馬蹄千里夕陽明。',64,'全唐诗/poet.song.238000.json','["多謝春風相此行，馬蹄千里夕陽明。", "故人楊柳正年少，知己青山舊日情。", "思滿天涯芳草逺，望窮江際暮雲生。", "同来佳客自不俗，相對松陰聽瀑聲。"]'),
('70802586-3716-43d8-a010-acb4abb9a227','淳熙丙申二月晦翁歸婺源先曾大父因隨杖屨遂掛名於弟子之列乃以所著書說以求正晦翁可之又嘗投書論易甚詳龍翰不學緇玷家聲因讀遺文有作數語亦所以自勉云','吳龍翰','宋','宋诗','song-poetry','','[]','吾祖曾師雲谷仙，讀書直下悟蹄筌。',64,'全唐诗/poet.song.238000.json','["吾祖曾師雲谷仙，讀書直下悟蹄筌。", "道參太極本無極，易論先天與後天。", "緑遍春風窗外草，香浮夜月沼中蓮。", "派分一勺濓溪水，道統綿綿萬古傳。"]'),
('2650c47e-c1e2-4606-a762-0e267007e93a','再過孤山','吳龍翰','宋','宋诗','song-poetry','','[]','一函鶴骨已塵埃，空築孤山碧玉臺。',32,'全唐诗/poet.song.238000.json','["一函鶴骨已塵埃，空築孤山碧玉臺。", "添種紅蓮千萬朵，梅花從此不須開。"]'),
('d7f0a575-bedd-46a4-bfb9-5f048f4155a6','冬夜  其一','吳龍翰','宋','宋诗','song-poetry','','[]','讀罷床頭一卷易，晚風凍盡銅壺滴。',32,'全唐诗/poet.song.238000.json','["讀罷床頭一卷易，晚風凍盡銅壺滴。", "起傍危闌嘯一聲，月明何處人横笛。"]'),
('46df54ef-587c-4cb6-b3e4-acb58a513912','冬夜  其二','吳龍翰','宋','宋诗','song-poetry','','[]','一屋白雲無鎖鑰，酒酣要摘梅花嚼。',32,'全唐诗/poet.song.238000.json','["一屋白雲無鎖鑰，酒酣要摘梅花嚼。", "相逢石鼎老彌明，吟罷松梢月欲落。"]'),
('3f50a56e-b345-4a33-aade-9152b469e939','晚舟泊長河','吳龍翰','宋','宋诗','song-poetry','','[]','詩客行裝少，孤舟一葉輕。',48,'全唐诗/poet.song.238000.json','["詩客行裝少，孤舟一葉輕。", "寒鴉隨日落，秋雁破霜鳴。", "山色攢心事，江聲咽世情。", "故鄉無百里，酤酒話歸程。"]'),
('6063df49-0fd2-4e42-95c7-67626d778192','冬夜山中','吳龍翰','宋','宋诗','song-poetry','','[]','寒入雁聲霜滿地，香沈梅影月當崖。',32,'全唐诗/poet.song.238000.json','["寒入雁聲霜滿地，香沈梅影月當崖。", "獨鶴歸来童亦睡，微風簌簌落松釵。"]'),
('5a3980fc-a5a9-4318-9a8a-70d337a1759d','贈詩客梅窗','吳龍翰','宋','宋诗','song-poetry','','[]','騷人行脚遍天涯，何處青山不是家。',32,'全唐诗/poet.song.238000.json','["騷人行脚遍天涯，何處青山不是家。", "惆悵舊時雲外鶴，結巢窗外守梅花。"]'),
('a3793294-6adf-4968-8f62-85f26b5a7896','樂府四首  其一','吳龍翰','宋','宋诗','song-poetry','','[]','妾心江岸石，千古無變更。',24,'全唐诗/poet.song.238000.json','["妾心江岸石，千古無變更。", "郎心江上水，倐忽風波生。"]'),
('55360f03-16eb-4667-a057-db84189bd537','樂府四首  其二','吳龍翰','宋','宋诗','song-poetry','','[]','瑟瑟涼風來，妾身似秋扇。',24,'全唐诗/poet.song.238000.json','["瑟瑟涼風來，妾身似秋扇。", "安得復炎熱，相攜不相厭。"]'),
('8adbf105-ec0a-4149-86ab-40d2c7e5e8c7','樂府四首  其三','吳龍翰','宋','宋诗','song-poetry','','[]','製衣寄夫壻，妾有冰雪段。',24,'全唐诗/poet.song.238000.json','["製衣寄夫壻，妾有冰雪段。", "中有連理枝，不忍剪教斷。"]'),
('08ee48ee-e740-4973-975c-91ed2121f9a0','樂府四首  其四','吳龍翰','宋','宋诗','song-poetry','','[]','殘月小樓西，鵑啼思欲迷。',24,'全唐诗/poet.song.238000.json','["殘月小樓西，鵑啼思欲迷。", "妾夫在天南，何不那邊啼。"]'),
('49c2efed-9390-4d61-93be-71174460a3bf','夜興','吳龍翰','宋','宋诗','song-poetry','','[]','山房靜對碧巉岏，與客歌騷夜未闌。',32,'全唐诗/poet.song.238000.json','["山房靜對碧巉岏，與客歌騷夜未闌。", "客去燈寒眠不穏，心隨明月在闌干。"]'),
('16d0fea0-b6d3-4d9c-8bc2-11887f5af850','辛酉秋在京殊久日一到湖上','吳龍翰','宋','宋诗','song-poetry','','[]','湖上青山只麽閒，未須詩屋近山間。',32,'全唐诗/poet.song.238000.json','["湖上青山只麽閒，未須詩屋近山間。", "客邊有酒身無事，日日一来湖上看。"]'),
('4935885e-132f-4c8d-91fa-35ad2d1e1f2b','讀家集','吳龍翰','宋','宋诗','song-poetry','','[]','吾家友堂翁，硯影雙髩寒。',108,'全唐诗/poet.song.238000.json','["吾家友堂翁，硯影雙髩寒。", "刻志鑽書史，篝燈照夜闌。", "學術三代上，文章兩漢間。", "胸次秋沆瀣，詞吐玉琅玕。", "寃哉命壓頭，那復博一官。", "二塤策科第，亦不到金鑾。", "友堂紛遺稿，幾成汲塚殘。", "江東兵燹餘，白璧喜重完。", "會當乞鴻筆，清名期不刋。"]'),
('ac4ecb68-f5d7-4f24-a293-83f2010395b5','己未試監假道於嚴報謝使君','吳龍翰','宋','宋诗','song-poetry','','[]','秋試賢闗擲雉盧，道經鄰郡拜真儒。',64,'全唐诗/poet.song.238000.json','["秋試賢闗擲雉盧，道經鄰郡拜真儒。", "棠陰日暖鳥聲雋，苔跡月明吏影臞。", "春野一犂今有犢，暮歌五袴昔無襦。", "片帆願借吹噓力，一舸清風不用租。"]'),
('08f3f059-42bf-4820-8bae-7d910a2559aa','嚴郡謁烏龍廟遇打碑者','吳龍翰','宋','宋诗','song-poetry','','[]','何年故處士，靈魄此爲家。',48,'全唐诗/poet.song.238000.json','["何年故處士，靈魄此爲家。", "古壁填蒼蘚，空庭隘落花。", "山墳穿去鶴，廟祭下饑鴉。", "巫祝打碑賣，神功播海涯。"]'),
('843fa352-db1a-4427-a8fa-23b295867faf','春晚','吳龍翰','宋','宋诗','song-poetry','','[]','萬緑樷中春事闌，楊花如雪滿江干。',64,'全唐诗/poet.song.238000.json','["萬緑樷中春事闌，楊花如雪滿江干。", "露沾花樹蝶衣重，雨著芹泥燕嘴寒。", "愁到吟腸詩綰斷，夢依棋局客敲殘。", "何時買得青山住，煉就蓬壺換骨丹。"]'),
('871665b1-ad30-4ed3-8219-ec59c2691c05','古岩寺','吳龍翰','宋','宋诗','song-poetry','','[]','古巖靈蹟異，故故兀吟鞍。',48,'全唐诗/poet.song.238000.json','["古巖靈蹟異，故故兀吟鞍。", "石溜濺棋濕，松風沍笛寒。", "露華僧衲重，曙色佛燈殘。", "白社開何日，談經上石壇。"]'),
('b06ebf5a-5766-4dcc-b2eb-8a82d96124d2','見王廣文','吳龍翰','宋','宋诗','song-poetry','','[]','旅食京華不自謀，可堪典盡鷫鸘裘。',64,'全唐诗/poet.song.238000.json','["旅食京華不自謀，可堪典盡鷫鸘裘。", "一床風雨孤燈夜，千里江山兩髩秋。", "笑索寒梅吟苦句，醉拈禿筆掃窮愁。", "學人翻笑孫明復，強乞希明一點頭。"]'),
('ecb8bc9b-4039-4650-ba97-2e0c500d3a4c','牛渚山觀大江','吳龍翰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','巨靈劈破蒼山石，鞭起九龍入空碧。',165,'全唐诗/poet.song.238000.json','["巨靈劈破蒼山石，鞭起九龍入空碧。", "山分兩半合不成，夾住長江數千尺。", "九道驚湍相擊撞，雷聲怒發誰敢當。", "神蛟出没不可數，往往殺氣摩穹蒼。", "嗚呼蜀道行且難，劍門險似鐵門闗。", "一夫可敵萬夫勇，大開棧道通殽函。", "固知長江當城壁，立此天塹限南北。", "東南王氣無窮年，此江未必成桑田。", "君不見敵兵百萬連艨艟，雄師出鬭一掃空。", "書生不能長鎗與大劍，只坐帷幄收奇功。"]'),
('9eea25fa-7f67-4302-8955-17d7c8a2335b','秋深過田家','吳龍翰','宋','宋诗','song-poetry','','[]','策杖行行過石橋，農家雞黍逺相招。',64,'全唐诗/poet.song.238000.json','["策杖行行過石橋，農家雞黍逺相招。", "田鋪棋局露鴉下，山展畫屏煙雨描。", "病骨枯於秋後葉，詩懐雄似海東潮。", "一聲老鶴松梢上，賸欲乘風到九霄。"]'),
('e1c1aa52-cbaf-4d52-bede-33c7a3a9e198','春日松陰小憩','吳龍翰','宋','宋诗','song-poetry','','[]','瘦笻扶我過林端，無賴東風掠髩寒。',32,'全唐诗/poet.song.238000.json','["瘦笻扶我過林端，無賴東風掠髩寒。", "貪數青山不知去，松花吹滿石棋盤。"]'),
('38952f73-b223-45ec-92b4-04dda8f7c341','水邊早梅','吳龍翰','宋','宋诗','song-poetry','','[]','梅花淡淡著寒烟，漏洩春光老屋邊。',32,'全唐诗/poet.song.238000.json','["梅花淡淡著寒烟，漏洩春光老屋邊。", "會被清池寫疎影，一枝分作兩枝妍。"]'),
('6495096c-f8a8-4938-b0ad-1b80c449e4d5','繁昌道中','吳龍翰','宋','宋诗','song-poetry','','[]','江天日暖竹爲輿，獵獵春風載此臞。',32,'全唐诗/poet.song.238000.json','["江天日暖竹爲輿，獵獵春風載此臞。", "湊入？橋成一畫，楊花吹雪糝吟鬚。"]'),
('b2c5fbae-2519-47f0-a306-39e8ff0cef07','讀十七全史歲久而徹','吳龍翰','宋','宋诗','song-poetry','','[]','燈火青編結興長，可能歴歴記興亡。',64,'全唐诗/poet.song.238000.json','["燈火青編結興長，可能歴歴記興亡。", "董狐筆底風霜重，班馬書邊蘭蕙香。", "往事輸贏棋幾局，浮名今古紙千張。", "重重公案休拈起，中有靈臺定否臧。"]'),
('fef3427c-a4b1-4e39-abe6-2df544efaf94','題國直先伯祖海潮賦後','吳龍翰','宋','宋诗','song-poetry','','[]','銀山突兀蒼海頭，夜半鼓噪萬貔貅。',160,'全唐诗/poet.song.238000.json','["銀山突兀蒼海頭，夜半鼓噪萬貔貅。", "爭雄角力轉坤軸，旋磨塵世偕浮漚。", "朝朝暮暮自消長，誰言於此隨海鰌。", "鴟革裹尸已塵土，未必怒怨卒未休。", "看公立論屈前輩，筆端有力挽萬牛。", "孤峰絕崖氣象古，亦復粲粲珊瑚鈎。", "分明掘見陰陽根，判斷造化之深幽。", "玄機發泄天帝嗔，此文正恐雷霆收。", "不然亦似畫鳥跡，長夜鬼哭聲啾啾。", "公自騎鯨去不返，滿江明月蘆花秋。"]'),
('65b6a7ef-9f61-471c-a528-3549575ad584','過和州報恩寺唐籍故居也','吳龍翰','宋','宋诗','song-poetry','','[]','昔年此地著書人，詩骨成塵草木深。',32,'全唐诗/poet.song.238000.json','["昔年此地著書人，詩骨成塵草木深。", "突兀眼前僧結屋，塔鈴風裡替君吟。"]'),
('b465def5-4ca5-436f-bb1c-ced9fa7877b5','烏江項羽廟','吳龍翰','宋','宋诗','song-poetry','','[]','蓋世英雄只恁休，千年遺恨大江流。',32,'全唐诗/poet.song.238000.json','["蓋世英雄只恁休，千年遺恨大江流。", "漢提義帝作張本，當日君輸第一籌。"]'),
('bc61cc61-e4c7-4e68-bd26-962d4fa52ee5','連雪五日有無盡觀','吳龍翰','宋','宋诗','song-poetry','','[]','平生酷愛雪，老我看不足。',120,'全唐诗/poet.song.238000.json','["平生酷愛雪，老我看不足。", "安得走五臺，六月潄寒玉。", "無計巢雪山，與佛結幽獨。", "方輿多奇觀，出門欠車轂。", "天公副微願，連朝遣滕六。", "寒林振琳琅，朔風扇瓊木。", "樓臺烱夜光，地靈驚玉局。", "幻成銀世界，一旦飽雙目。", "清冷天地氣，吸入空洞腹。", "賸欲呼夜舟，飄然訪林麓。"]'),
('29133416-b736-4d8c-8321-75beef489b23','登金陵鍾山絕頂','吳龍翰','宋','宋诗','song-poetry','','[]','萬仞鍾山著屐登，中原今隔幾崚嶒。',32,'全唐诗/poet.song.238000.json','["萬仞鍾山著屐登，中原今隔幾崚嶒。", "自憐不及天邊雁，歲逐春風到八陵。"]'),
('cb600c43-83da-4db8-abe1-021b5dc3a6f9','張麗華墓  其一','吳龍翰','宋','宋诗','song-poetry','','[]','金井轆轤春夢殘，香魂飛不到長安。',32,'全唐诗/poet.song.238000.json','["金井轆轤春夢殘，香魂飛不到長安。", "君王爲虜妾爲土，夜月空分兩地寒。"]'),
('1bbeb803-08c2-4356-beab-3e44769efbcd','張麗華墓  其二','吳龍翰','宋','宋诗','song-poetry','','[]','結綺臨春跡已塵，尚餘抔土鎖娉婷。',32,'全唐诗/poet.song.238000.json','["結綺臨春跡已塵，尚餘抔土鎖娉婷。", "玉顔不及隴頭草，歲歲春風吹得青。"]'),
('2a49a889-bc9e-40b1-8904-0095de7ebb6b','王荆公讀書堂','吳龍翰','宋','宋诗','song-poetry','','[]','六籍紛紛盡可奴，翻騰字說乃菑畬。',32,'全唐诗/poet.song.238000.json','["六籍紛紛盡可奴，翻騰字說乃菑畬。", "可知山半青燈夜，只讀商君一卷書。"]'),
('90e555d6-4a6c-42fd-bad8-d5ded013c16c','登長干寺塔','吳龍翰','宋','宋诗','song-poetry','','[]','金陵王氣已銷沈，幾度憑闌愁滿襟。',64,'全唐诗/poet.song.238000.json','["金陵王氣已銷沈，幾度憑闌愁滿襟。", "往事僅存南北史，傷情空費短長吟。", "龍蟠故國山河在，鳳去荒臺草木深。", "舊物尚餘吳塔在，夕陽移影照江心。"]'),
('2a5dfec1-554f-4816-bb29-e7e0c6375856','詩境','吳龍翰','宋','宋诗','song-poetry','','[]','流水環詩境，未容塵土侵。',48,'全唐诗/poet.song.238000.json','["流水環詩境，未容塵土侵。", "步迂松徑曲，坐占草堂深。", "秋句蛩分和，山杯鳥勸斟。", "好懷無客共，相對一躊躇。"]'),
('294c0e0e-84ca-4ff1-9117-e495bee1e0cd','謾題','吳龍翰','宋','宋诗','song-poetry','','[]','放曠疏林下，清風吹鬢毛。',48,'全唐诗/poet.song.238000.json','["放曠疏林下，清風吹鬢毛。", "傍梅讀周易，對酒歌離騷。", "詩思秋雲淡，古懷明月高。", "五湖天地別，煙水綠平篙。"]'),
('a82c8d5b-1202-473c-99a7-beb8894d658e','過淮南湖','吳龍翰','宋','宋诗','song-poetry','','[]','黄塵茫茫北風起，黄蘆蕭蕭日色死。',96,'全唐诗/poet.song.238000.json','["黄塵茫茫北風起，黄蘆蕭蕭日色死。", "百萬征夫血怒流，點汚淮南一湖水。", "向来失著圖中原，一朝此地化爲邊。", "養兵百年不用力，將軍金印慙空懸。", "南湖南湖君莫渡，萬仞山高鬼門户。", "夜夜青燐照斷蓬，訓狐自戴髑髏舞。"]'),
('41222228-52df-4c17-b408-98386e341d3e','泊真州方山下','吳龍翰','宋','宋诗','song-poetry','','[]','烟冷隋宫草木秋，屏山分翠接江流。',32,'全唐诗/poet.song.238000.json','["烟冷隋宫草木秋，屏山分翠接江流。", "片雲不隔長蘆寺，夜半鐘聲敲客愁。"]'),
('7255716f-a0d4-4014-aa80-8216a9a92abc','有所嗟','吳龍翰','宋','宋诗','song-poetry','','[]','乘鸞人去玉簫寒，雲斂巫山曉夢殘。',32,'全唐诗/poet.song.238000.json','["乘鸞人去玉簫寒，雲斂巫山曉夢殘。", "柳線不堪繫離別，自和烟雨搭闌干。"]'),
('40fb9f0a-74fd-4fb7-8165-fd3b9ac825b8','戊午詔與弟文戰棘闈自慚師衂況有炊臼之夢不能爲懐幸故人有薦鄉書魁漕闈者良以自慰','吳龍翰','宋','宋诗','song-poetry','','[]','霜葉秋風下，寒窗著病身。',48,'全唐诗/poet.song.238000.json','["霜葉秋風下，寒窗著病身。", "乾坤爲逆旅，歲月轉車輪。", "白首無賢婦，青雲有故人。", "愁懐今日解，漫啜甕邊春。"]'),
('a6746b2f-9639-4577-bb10-6325cc5346ba','先曾大父作竹夫人銘北窗蘧蘧偎爾冰肌毋徇其名乃邪其思甚有思致余不能道漫作俳優語','吳龍翰','宋','宋诗','song-poetry','','[]','水沈爲骨玉爲肌，専寵涼臺會有時。',32,'全唐诗/poet.song.238000.json','["水沈爲骨玉爲肌，専寵涼臺會有時。", "長得夫人容兩足，客星不遣史官知。"]'),
('92d29eb4-5001-46c8-a879-976d0fd57b58','雨宿祁門道中','吳龍翰','宋','宋诗','song-poetry','','[]','乘驂古渡頭，景色十分幽。',48,'全唐诗/poet.song.238000.json','["乘驂古渡頭，景色十分幽。", "山雨敲詩夢，溪流赴客愁。", "寒禽知警夜，髙樹故吟秋。", "壯志難磨盡，終期汗漫遊。"]'),
('3d22ed38-17c0-471f-82b5-abf531cc6966','登當塗凌歊臺','吳龍翰','宋','宋诗','song-poetry','','[]','髙臺突兀玉千尋，尚想當年翠輦臨。',32,'全唐诗/poet.song.238000.json','["髙臺突兀玉千尋，尚想當年翠輦臨。", "坐守夕陽移半塔，我吟未了讓蟬吟。"]'),
('29cdbaac-6592-4902-8cbe-b700b1636be7','曉發黄池過寧國','吳龍翰','宋','宋诗','song-poetry','','[]','簇簇人烟兩岸分，暫時掛搭此行程。',32,'全唐诗/poet.song.238000.json','["簇簇人烟兩岸分，暫時掛搭此行程。", "一笻風月無拘束，又復挑詩到宛城。"]'),
('fed30373-7958-4981-b61b-5190599c7be8','登宣城郡樓仰謝公','吳龍翰','宋','宋诗','song-poetry','','[]','翠屏四面敞闌干，謝老詩情不說官。',32,'全唐诗/poet.song.238000.json','["翠屏四面敞闌干，謝老詩情不說官。", "魂冷青山呼欲醒，吟聲滲在石泉間。"]'),
('844a3cfe-4a3f-43a1-9934-c7142a6600cb','歸途績溪界喜見十里岩','吳龍翰','宋','宋诗','song-poetry','','[]','策杖前溪去，吾鄉此路分。',48,'全唐诗/poet.song.238000.json','["策杖前溪去，吾鄉此路分。", "雨磨山出色，風約水成文。", "歸信憑秋雁，思親望白雲。", "碧岩今日見，快飲带微醺。"]'),
('4348fd89-f3f6-458f-a9c5-79a4cc72752c','自建鄴歸至績溪迂路觀石照','吳龍翰','宋','宋诗','song-poetry','','[]','誰磨白石如冰鑑，勲業安能試一窺。',32,'全唐诗/poet.song.238000.json','["誰磨白石如冰鑑，勲業安能試一窺。", "但覺秋風上潘髩，半因爲客半因詩。"]'),
('82c67ca9-05b7-43e6-93b1-9dd64b5d923d','內丹','吳龍翰','宋','宋诗','song-poetry','','[]','太極虚空亦有根，打開闗捩是何人。',64,'全唐诗/poet.song.238000.json','["太極虚空亦有根，打開闗捩是何人。", "丹田旋轉乾坤槖，碧海循環日月輪。", "久矣我前曾有我，悠哉身外豈無身。", "分明好個通天竅，只要時人認得真。"]'),
('c8222c0c-18ab-4919-ac88-5ebe97ff3c45','外丹','吳龍翰','宋','宋诗','song-poetry','','[]','手掇乾坤鐺裏煎，神仙肘後有書傳。',64,'全唐诗/poet.song.238000.json','["手掇乾坤鐺裏煎，神仙肘後有書傳。", "紅鉛黑汞一斤藥，陽火陰符六百篇。", "金鼎自凝三素炁，玉鑪輕散九霞烟。", "玄霜糝入空虚腹，一息乘風上碧天。"]'),
('f813075f-ab37-4a4d-b77b-4b5be153edb1','對月','吳龍翰','宋','宋诗','song-poetry','','[]','長空有明月，與我良有情。',120,'全唐诗/poet.song.238000.json','["長空有明月，與我良有情。", "遙遙萬里道，隨我杖履行。", "耿耿吟床間，相隨入枕衾。", "而我病風雅，長作秋蛩吟。", "吟聲悲入月，月色寒入吟。", "月即是天眼，照我淚縱横。", "垂垂草上露，盡從月眼傾。", "不爲富貴兒，只作苦吟人。", "君看朱門邃，翠幕圍陽春。", "管絃沸清曉，銀燭正熒熒。"]'),
('8b9f1f06-af38-4f4e-b117-70e42cc7c256','題西湖畫軸','吳龍翰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','丹青誰寫滿軸蓮，濯濯西施一段妍。',32,'全唐诗/poet.song.238000.json','["丹青誰寫滿軸蓮，濯濯西施一段妍。", "汴水百年塵隔斷，可無人作畫圖傳。"]'),
('fada5890-8c5c-4c52-956e-4a4c7a4c23a7','登嚴子陵釣臺','吳龍翰','宋','宋诗','song-poetry','','[]','萬乘從君脚底眠，客星便入史官占。',32,'全唐诗/poet.song.238000.json','["萬乘從君脚底眠，客星便入史官占。", "東都基業隨流水，今日斯臺尚姓嚴。"]'),
('17647b2e-d7d8-4948-a180-86499fdd27ac','栽斑竹','吳龍翰','宋','宋诗','song-poetry','','[]','竹母初分種屋頭，斑斑淚點带詩愁。',32,'全唐诗/poet.song.238000.json','["竹母初分種屋頭，斑斑淚點带詩愁。", "他時看取成林玉，遙剪湘江一片愁。"]'),
('c5e7bffe-a29e-482b-a937-e15de3d82b6f','縣尹先伯祖家觀遺書','吳龍翰','宋','宋诗','song-poetry','','[]','嗟哉吾伯祖，文響玉珊珊。',48,'全唐诗/poet.song.238000.json','["嗟哉吾伯祖，文響玉珊珊。", "髙折蟾宫桂，卑棲花縣官。", "琴聲流水盡，書卷白雲寒。", "尚想伊吾夜，髙樓幾倚闌。"]'),
('d2d12478-33fd-4d38-aa9c-21fbafd5ef20','春山晚望','吳龍翰','宋','宋诗','song-poetry','','[]','糢糊數叠屋前山，翠色欺凌詩髩寒。',32,'全唐诗/poet.song.238000.json','["糢糊數叠屋前山，翠色欺凌詩髩寒。", "啼鳥一聲泥滑滑，晚鐘春雨過林端。"]'),
('5f895f42-597b-4150-a084-5506960a1c36','讀董卓傳','吳龍翰','宋','宋诗','song-poetry','','[]','巨妖吐毒氣如蒸，誰遣腥羶漢帝陵。',32,'全唐诗/poet.song.238000.json','["巨妖吐毒氣如蒸，誰遣腥羶漢帝陵。", "烟斷洛陽殘火在，爲他吹著點臍燈。"]'),
('2dad8df0-ecdd-48d7-9883-82733a4bec5d','春日書所見','吳龍翰','宋','宋诗','song-poetry','','[]','寒雲漠漠暮天低，社鼓聲中日欲西。',32,'全唐诗/poet.song.238000.json','["寒雲漠漠暮天低，社鼓聲中日欲西。", "隔岸垂楊遮酒店，風帘移影照寒溪。"]'),
('cd8c658c-4149-4c8c-b363-278aad3e4299','春懐','吳龍翰','宋','宋诗','song-poetry','','[]','梨花院落雨初晴，小醉醒来睡不成。',64,'全唐诗/poet.song.238000.json','["梨花院落雨初晴，小醉醒来睡不成。", "過客光陰易老態，故人山色却長情。", "歌喉嚦嚦鳥聲雋，舞袖翩翩蝶翅輕。", "好景相看作撻盡，閉門不覺了清明。"]'),
('b12e14b3-82de-4b74-b650-56224f1ca806','昭君怨','吳龍翰','宋','宋诗','song-poetry','','[]','漢家金屋貯娥眉，六宫何啻三千姬。',112,'全唐诗/poet.song.238000.json','["漢家金屋貯娥眉，六宫何啻三千姬。", "中有一姬傾國色，可憐不到君王知。", "毛生筆下真少恩，玉顔黑子迷妍媸。", "君王按圖不入眼，出身逺嫁單于妻。", "盈盈淚眼邊月照，蕭蕭愁髩胡風吹。", "不憂死作龍城鬼，貞魂長在深宫裏。", "猶勝男兒未貴時，咫尺金門如萬里。"]'),
('256bffc4-593a-43aa-a573-d805188ac852','飲馬長城窟','吳龍翰','宋','宋诗','song-poetry','','[]','漢兵北伐時，飲馬長城窟。',72,'全唐诗/poet.song.238000.json','["漢兵北伐時，飲馬長城窟。", "此城何以髙，中填戰夫骨。", "此池何以深，戰血化爲洫。", "秋風吹水腥，馬聞亦辟易。", "馬渴可柰何，要馬載金戈。", "長安有遊冶，走馬燕支坡。"]'),
('563134fa-aa29-45a7-b356-283bab1c9574','餞王廣文','吳龍翰','宋','宋诗','song-poetry','','[]','宦居三載滿，嚴駕出山城。',48,'全唐诗/poet.song.238000.json','["宦居三載滿，嚴駕出山城。", "詩擔梅花白，離杯竹葉清。", "更籌催客夢，斥堠計行程。", "去去驂鸞鶴，長歌上玉京。"]'),
('49f90167-6471-4154-b1a1-0070b73a2ff7','寓興','吳龍翰','宋','宋诗','song-poetry','','[]','盈盈樓上仙家姝，綠波濯濯明芙渠。',80,'全唐诗/poet.song.238000.json','["盈盈樓上仙家姝，綠波濯濯明芙渠。", "感君恩情玉連鎖，羅襦繫君雙明珠。", "青瑣玲瓏春夜永，爲君閒調相思引。", "瓊樹朝新璧月滿，琴聲未斷腸先斷。", "剪剪輕寒襲春笋，金猊噴香薫袖暖。"]'),
('335cb5ff-7326-4b0d-8fdb-77164d505bc9','夏日書事','吳龍翰','宋','宋诗','song-poetry','','[]','東林數間屋，長掩竹笆籬。',48,'全唐诗/poet.song.238000.json','["東林數間屋，長掩竹笆籬。", "檻柳拂棋局，瓶花落硯池。", "蝶狂如被酒，蟬咽似吟詩。", "脫帽挂岩石，涼颸入髩絲。"]'),
('eea7e4c5-03b5-41af-b45e-c8850418a8aa','草堂','吳龍翰','宋','宋诗','song-poetry','','[]','蒼烟落日草堂深，淺淺寒侵白玉簪。',32,'全唐诗/poet.song.238000.json','["蒼烟落日草堂深，淺淺寒侵白玉簪。", "等客不来童睡去，自搖修竹和新吟。"]'),
('539663d9-a3fe-44ee-ba26-cfa535dfb246','夜吟','吳龍翰','宋','宋诗','song-poetry','','[]','小院沈沈夜欲闌，東風吹月上闌干。',32,'全唐诗/poet.song.238000.json','["小院沈沈夜欲闌，東風吹月上闌干。", "手撼梅花露研墨，醉將吟筆蘸清寒。"]'),
('aa1a37d3-3a04-4489-a3a1-1f0d61377a84','荷花','吳龍翰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','花列千行彩袖，葉收萬斛明珠。',28,'全唐诗/poet.song.238000.json','["花列千行彩袖，葉收萬斛明珠。", "可惜坡仙不在，風情絕勝西湖。"]'),
('a169ff99-7a7f-4524-8a04-333d3486fa61','升仙謠','吳龍翰','宋','宋诗','song-poetry','','[]','衣縹緲，佩丁東。',36,'全唐诗/poet.song.238000.json','["衣縹緲，佩丁東。", "金莖滴香露，玉樹生涼風。", "衝破青冥跨黄鶴，身披星斗珍珠絡。"]'),
('c784477e-e00b-49e0-9ae1-467be5b13531','輓徐縣尹','吳龍翰','宋','宋诗','song-poetry','','[]','雄筆工褒貶，登科年少時。',48,'全唐诗/poet.song.238000.json','["雄筆工褒貶，登科年少時。", "青山知宦拙，白首尚書癡。", "鶚薦仍歸弟，鳳毛喜有兒。", "傳家遺卷在，光彩玉離離。"]'),
('9d27e481-620e-4fd1-9bcd-2ad048affa61','贈相士','吳龍翰','宋','宋诗','song-poetry','','[]','萬里烟霞侵鶴骨，九天風露注蟬尸。',32,'全唐诗/poet.song.238000.json','["萬里烟霞侵鶴骨，九天風露注蟬尸。", "君看个人作詩苦，梅花細嚼當晨炊。"]'),
('bb05d569-e1f5-44c8-b3ec-b1ffd36381b7','春郊即事','吳龍翰','宋','宋诗','song-poetry','','[]','登臨故故檢春工，小立蒼苔數落紅。',32,'全唐诗/poet.song.238000.json','["登臨故故檢春工，小立蒼苔數落紅。", "院宇人歸春寂寂，秋千閒在月明中。"]'),
('19ee4a57-25f4-4795-93dc-041822dab3a3','寄題友梅堂友梅乃竹洲先生孫也','吳龍翰','宋','宋诗','song-poetry','','[]','公昔洲多竹，而孫梅作堂。',48,'全唐诗/poet.song.238000.json','["公昔洲多竹，而孫梅作堂。", "月窗傳瘦影，風壑度寒香。", "友也真魚水，兄兮可雁行。", "相看動吟興，時吐玉琳琅。"]'),
('17ce118a-77e6-4616-9515-1d475bdfe1bf','甲子舉中補濫忝前名考官劉簿云已在解選澇漉袁簿批有文字清快老健惜乎正榜之額有限之語','吳龍翰','宋','宋诗','song-poetry','','[]','奴顔婢膝浪驅馳，幾被秋風吹髩絲。',64,'全唐诗/poet.song.238000.json','["奴顔婢膝浪驅馳，幾被秋風吹髩絲。", "百萬博盧空得雉，八千兵潰豈因騅。", "功名付我銀鑿落，世事從渠鐵蒺藜。", "且跨蹇驢出門去，六朝故地要吾詩。"]'),
('3bc48226-b267-4399-929d-2e2fb7b08a89','秦淮  其一','吳龍翰','宋','宋诗','song-poetry','','[]','數里秦淮畫軸開，唐人賞後宋人来。',32,'全唐诗/poet.song.238000.json','["數里秦淮畫軸開，唐人賞後宋人来。", "無邊風月要酬答，一處旗亭買一杯。"]'),
('257607b1-be10-483b-96d7-2888cd60f2fe','秦淮  其二','吳龍翰','宋','宋诗','song-poetry','','[]','歌歇陳宫玉樹春，可憐商女亦成塵。',32,'全唐诗/poet.song.238000.json','["歌歇陳宫玉樹春，可憐商女亦成塵。", "老成惟有秦淮月，往日曾經照古人。"]'),
('dca0aa91-cb0d-4d7b-9cee-4ad9208b8c2a','金陵懐古','吳龍翰','宋','宋诗','song-poetry','','[]','鍾阜龍蟠勢可奇，何年開此帝王基。',64,'全唐诗/poet.song.238000.json','["鍾阜龍蟠勢可奇，何年開此帝王基。", "東西日月磨今古，南北江山幾合離。", "六代衣冠荒草下，中原臺殿白雲涯。", "春風吹落英雄淚，立盡斜陽未有詩。"]'),
('97dbd64d-16c2-45f9-a3f8-e6aafb22464b','拜李謫仙墓','吴龍翰','宋','宋诗','song-poetry','','[]','先生放曠士，浩氣吞洪濛。',120,'全唐诗/poet.song.238000.json','["先生放曠士，浩氣吞洪濛。", "蓬池與紫閣，軒蓋繹相從。", "經營紫河車，破費十載功。", "金鼎馴烏兔，炎炎丹光紅。", "一擊混沌破，落地尋無蹤。", "神仙有水解，戲劇驚愚蒙。", "當年遺劍履，一鍤秋雲封。", "我亦鑽玄學，此心良券同。", "朅来薦泉菊，紫綺疑相逢。", "儼如真面目，曉月印寒空。"]'),
('e7ad2b1b-0f55-420a-be7b-bf0280a554c2','登采石望夫石','吴龍翰','宋','宋诗','song-poetry','','[]','良人戍楚竟蹉跎，極目天涯歲月多。',32,'全唐诗/poet.song.238000.json','["良人戍楚竟蹉跎，極目天涯歲月多。", "賴有江流是知己，有聲似和扊扅歌。"]'),
('421bd6f9-9fb1-437f-a487-ea17e387a5ff','登和州八公山昔年周師俘敵扵此有碑屹其上','吴龍翰','宋','宋诗','song-poetry','','[]','萬姓叢居一彈丸，八公何在路漫漫。',64,'全唐诗/poet.song.238000.json','["萬姓叢居一彈丸，八公何在路漫漫。", "中原北望已塵暗，邊地秋来又棗丹。", "獵獵陰風征骨亂，茫茫夜月鬼聲寒。", "老兵指點擒生處，峴首殘碑带淚看。"]'),
('992bf499-3278-4ac9-9956-1be77c8592b3','哭趙信菴  其一','吴龍翰','宋','宋诗','song-poetry','','[]','祥雲中屹祝融峯，秀出全材一鉅公。',64,'全唐诗/poet.song.238000.json','["祥雲中屹祝融峯，秀出全材一鉅公。", "銀管曾提修國史，金戈幾出策邉功。", "九秋健羽横空鶚，萬里威聲當道熊。", "譚國爲前冀國後，汗青千古玉玲瓏。"]'),
('989eea36-02e0-4073-9613-876f71e30c15','哭趙信菴  其二','吴龍翰','宋','宋诗','song-poetry','','[]','麟符玉策總兵權，手托江淮半壁天。',64,'全唐诗/poet.song.238000.json','["麟符玉策總兵權，手托江淮半壁天。", "大節有闗宗社裡，深謀常畫廟堂先。", "三朝已表蟬冠像，八袠終逢雞夢年。", "不獨羊公碑尚在，萬民墮淚滴湘烟。"]'),
('c73ef116-7ce0-48f9-a182-6a08ab07f3ff','秋日綿溪','吴龍翰','宋','宋诗','song-poetry','','[]','萬頃寒潭鏡面平，數聲征雁叫霜晴。',32,'全唐诗/poet.song.238000.json','["萬頃寒潭鏡面平，數聲征雁叫霜晴。", "滿林落葉秋風老，山路黄昏人少行。"]'),
('fc12dacf-893e-4265-9020-c528c0d4d484','哭秋崖先生  其一','吴龍翰','宋','宋诗','song-poetry','','[]','氣節昻斯世，先生千載人。',48,'全唐诗/poet.song.238000.json','["氣節昻斯世，先生千載人。", "可憐成白首，猶只到朱輪。", "芧取羣狙怒，雪逢越犬狺。", "方離羅織辱，身世已成塵。"]'),
('a2f56c9b-3b24-4608-8f0e-348fe37dcea2','哭秋崖先生  其二','吴龍翰','宋','宋诗','song-poetry','','[]','歐蘇喚不起，文印屬秋崖。',48,'全唐诗/poet.song.238000.json','["歐蘇喚不起，文印屬秋崖。", "大雅非常調，正音不類俳。", "寒江濯文思，明月鏤吟懐。", "傳業有楊晏，遺書塚墓埋。"]'),
('099348f1-c000-4e2b-b5fd-b823f0f55ca1','哭秋崖先生  其三','吴龍翰','宋','宋诗','song-poetry','','[]','昔年經盼目，此日罷從遊。',48,'全唐诗/poet.song.238000.json','["昔年經盼目，此日罷從遊。", "尤許爲上足，敢令出一頭。", "聖涯窺浩蕩，學海探深幽。", "一瓣南豐後，他師不復求。"]'),
('f0624c1c-0aaa-44f5-9549-e63ee1a7b954','吴越歸秋晚','吴龍翰','宋','宋诗','song-poetry','','[]','湖海歸来晚，園荒菊幾叢。',48,'全唐诗/poet.song.238000.json','["湖海歸来晚，園荒菊幾叢。", "秋山吟骨瘦，霜葉醉顔紅。", "弔影寒溪曲，懐人落月中。", "青燈滋味永，不用哭途窮。"]'),
('65190bb5-3bca-4587-b7ef-7032bf5d5a7d','座中詠蟬分韻得饑字','吴龍翰','宋','宋诗','song-poetry','','[]','兩翼纔乾殻已離，便升喬木最髙枝。',64,'全唐诗/poet.song.238000.json','["兩翼纔乾殻已離，便升喬木最髙枝。", "銀床落葉秋風裡，金掌盤敧曉露時。", "斷續翻成無調曲，悲凉做出苦吟詩。", "前身應是夷齊輩，髙臥西山自忍饑。"]'),
('ce0cfc31-5b56-4f1b-9352-b6e0a29e2446','春晚野步','吴龍翰','宋','宋诗','song-poetry','','[]','尋花籬下蝶牽引，酌酒林間鳥勸酧。',32,'全唐诗/poet.song.238000.json','["尋花籬下蝶牽引，酌酒林間鳥勸酧。", "山色不隨春態老，笛聲自起夕陽愁。"]'),
('2ee7757c-becb-4337-9f73-65ed2f763702','寓感','吴龍翰','宋','宋诗','song-poetry','','[]','周家敦八議，姬旦衡何平。',72,'全唐诗/poet.song.238000.json','["周家敦八議，姬旦衡何平。", "秦家尚苛法，四海怨商君。", "鳳鳥時一鳴，梟鳥時一鳴。", "一鳴以爲周，一鳴以爲秦。", "法重滅爾族，德重潤爾身。", "天帝厭殺伐，勿使傷陽春。"]'),
('e1df53b7-07a8-4cb4-b5bd-8af275551004','離怨','吴龍翰','宋','宋诗','song-poetry','','[]','楊柳如少年，春風吹得老。',95,'全唐诗/poet.song.238000.json','["楊柳如少年，春風吹得老。", "朝爲白雪花，暮爲浮萍草。", "明月照妾夫，夜夜闗山道。", "明月分半光，照妾顔色好。", "空閨一十年，芳容秋葉槁。", "寶馬嘶，妾夫歸，對鏡畫眉雙淚垂。", "前日夫悮妾今日妾悮夫，妾貌不如夫去時。"]'),
('ec85e739-c732-4382-b8ef-db6ee61e27ca','故人見寄韻','吴龍翰','宋','宋诗','song-poetry','','[]','青年鐵硯亦曾磨，壯不如人可奈何。',64,'全唐诗/poet.song.238000.json','["青年鐵硯亦曾磨，壯不如人可奈何。", "松菊猶存陶令逕，煙雲不碍邵公窩。", "吟廊緩步看修竹，醉石髙眠枕緑莎。", "一笠一蓑吾事足，江湖浩蕩白鷗波。"]'),
('ab1d166c-1d44-4c13-83ee-84174217ee10','樓居狂吟  其一','吴龍翰','宋','宋诗','song-poetry','','[]','茅齋悔著市廛間，長與青山面目慳。',32,'全唐诗/poet.song.238000.json','["茅齋悔著市廛間，長與青山面目慳。", "突兀小樓初結就，竹床石枕臥看山。"]'),
('eba63c0b-cfeb-483c-bdca-f32763775541','樓居狂吟  其二','吴龍翰','宋','宋诗','song-poetry','','[]','樓間丹壁富藏書，悮學相如賣子虚。',32,'全唐诗/poet.song.238000.json','["樓間丹壁富藏書，悮學相如賣子虚。", "何不買牛勤敎子，邵平□地要人鋤。"]'),
('6ec129cd-8a63-4393-bc33-0019cf3c332e','樓居狂吟  其三','吴龍翰','宋','宋诗','song-poetry','','[]','覔得樓中一覺眠，將身化蝶入壺天。',32,'全唐诗/poet.song.238000.json','["覔得樓中一覺眠，將身化蝶入壺天。", "平生睡債何時足，春在梅花紙帳邊。"]'),
('7effd524-5764-40d2-b78d-43d0d314f39c','樓居狂吟  其四','吴龍翰','宋','宋诗','song-poetry','','[]','湖海真成萬里遊，寒風吹破黑貂裘。',32,'全唐诗/poet.song.238000.json','["湖海真成萬里遊，寒風吹破黑貂裘。", "歸来臥占樓千尺，夢落滄波明月舟。"]'),
('67849a77-199f-4e64-aeb8-2a6ed8707824','樓居狂吟  其五','吴龍翰','宋','宋诗','song-poetry','','[]','汗漫相期欲控鯨，龜樓粗可寄閒身。',32,'全唐诗/poet.song.238000.json','["汗漫相期欲控鯨，龜樓粗可寄閒身。", "天敎吴猛親常健，乞與商山九斛塵。"]'),
('930e274e-a0f9-492f-98e0-7b5b9fe6e11a','樓居狂吟  其六','吴龍翰','宋','宋诗','song-poetry','','[]','振衣千仞興悠哉，一日看山十二回。',32,'全唐诗/poet.song.238000.json','["振衣千仞興悠哉，一日看山十二回。", "胸次誰人有丘壑，便容攜酒上樓来。"]'),
('06f3a19e-345f-4c1b-8875-81262a1f65ac','樓居狂吟  其七','吴龍翰','宋','宋诗','song-poetry','','[]','四山如畫不勝奇，朝暮烟雲都是詩。',32,'全唐诗/poet.song.238000.json','["四山如畫不勝奇，朝暮烟雲都是詩。", "樓上吟聲穿碧落，天公罰我髩成絲。"]'),
('fc37322f-e6b1-4beb-9f4f-12382fd94d44','樓居狂吟  其八','吴龍翰','宋','宋诗','song-poetry','','[]','胸次玲瓏著九垓，政須時復興崔巍。',32,'全唐诗/poet.song.238000.json','["胸次玲瓏著九垓，政須時復興崔巍。", "樓髙手可捫星斗，移掇天河入酒杯。"]'),
('9caea5c8-8fba-4ffd-8985-beb2c72a514b','樓居狂吟  其九','吴龍翰','宋','宋诗','song-poetry','','[]','諸方參遍一枯藤，苦節期傳夜半燈。',31,'全唐诗/poet.song.238000.json','["諸方參遍一枯藤，苦節期傳夜半燈。", "景登樓持棒喝，不容人上第三層。"]'),
('bf3af8be-c18c-4c89-8b96-58d388446341','樓居狂吟  其一○','吴龍翰','宋','宋诗','song-poetry','','[]','偃月鑪深紫氣浮，紅鉛黑汞六丹頭。',32,'全唐诗/poet.song.238000.json','["偃月鑪深紫氣浮，紅鉛黑汞六丹頭。", "梅翁欲挹浮丘訣，顓爲黄山作此樓。"]'),
('71fb22ca-fba2-4791-a34f-a3ad5d17e1c2','句  其一','吴龍翰','宋','宋诗','song-poetry','','[]','一聲欸乃煙波闊，千古離騷日明光。',16,'全唐诗/poet.song.238000.json','["一聲欸乃煙波闊，千古離騷日明光。"]'),
('d1c30a2b-50f9-4f52-b5ce-6c6638e82a9f','句  其二','吴龍翰','宋','宋诗','song-poetry','','[]','天地可呼歸舴艋，利名不遣涴笭箵。',16,'全唐诗/poet.song.238000.json','["天地可呼歸舴艋，利名不遣涴笭箵。"]'),
('eb5407a1-1964-4cf8-b5ba-4354a97e3b7c','句  其三','吴龍翰','宋','宋诗','song-poetry','','[]','蜀儒爲郡追傳任昉，歙士呼天借寇恂。',17,'全唐诗/poet.song.238000.json','["蜀儒爲郡追傳任昉，歙士呼天借寇恂。"]'),
('acc43911-a170-47cb-9de4-784cab721951','澹山巖','文子璋','宋','宋诗','song-poetry','','[]','舟艤澹巖前，巖扃不記年。',47,'全唐诗/poet.song.238000.json','["舟艤澹巖前，巖扃不記年。", "臺高先得月，石透可通天。", "洞古依禪剎，碑殘紀昔賢。", "勝遊回首望，林麓雲煙。"]'),
('038e464c-48ae-4b2f-bba2-f3996fb8471f','浯溪','文子璋','宋','宋诗','song-poetry','','[]','漫郎直筆老文太師□字尤卓犖。',121,'全唐诗/poet.song.238000.json','["漫郎直筆老文太師□字尤卓犖。", "天然二妙刻蒼崖，墨本傳來重和璞。", "三年流客居瀟嶷，甚欲一來觀此碑。", "盡被前賢剛說破，手磨苔刻難爲辭。", "爲子從來止於孝，古以敝屣匹天下。", "神武妖氛清，南內淒涼淚血灑。", "一時大業中興唐，萬世□虎狼。", "從今罪案休拈起，祇挹□與元郎。"]'),
('34c13325-9979-4a3c-820b-6ea997963f47','淡山巖','陳梅所','宋','宋诗','song-poetry','','[]','天下人知此一巖，霜清杖履雅宜閑。',32,'全唐诗/poet.song.238000.json','["天下人知此一巖，霜清杖履雅宜閑。", "閩峯儘有堪怡處，猿鶴多時望客還。"]'),
('0af3648c-8df4-4114-bd5c-75c5500be821','便民詩上顔正叔宣慰廣東','李肖龍','宋','宋诗','song-poetry','','[]','枯苗一著雨，田疇經芊芊。',168,'全唐诗/poet.song.238000.json','["枯苗一著雨，田疇經芊芊。", "蟄蟲一逢春，窟穴聲闐闐。", "餘民望小定，甚於饑渴然。", "昔何好弄兵，今何知服田。", "急流無住魚，晴空有飛鳶。", "干戈未肯息，百里無人煙。", "去年科徭重，剜瘡在眼前。", "父子不相保，悲泣空自懸。", "新官榜往催，觀者塞市廛。", "全活數萬衆，此恩大如天。", "人生能幾何，飲啄皆前緣。", "聚水盈科進，缺月及時圓。", "唯謀官職高，未必子孫賢。", "有意行王道，願言書七篇。"]'),
('c9504f14-6188-4f52-b067-1407a0fa3901','題潭然公舊址','李肖龍','宋','宋诗','song-poetry','','[]','昔聞釋流號自然，棲遁龍潭山之巔。',96,'全唐诗/poet.song.238000.json','["昔聞釋流號自然，棲遁龍潭山之巔。", "爲憐旱魃赤茲上，積薪自焚上告天。", "感得天公沛霖雨，至仁一念周萬宇。", "人心如此苟不傳，天下誰復爲伊呂。", "我欲筑室祠其下，以愧知己忘物者。", "勒吾之言石之中，欲雨歌此呼臥龍。"]'),
('f27493a9-49f1-4f8d-9ed4-25d6d6467f7b','寶林寺二首  其一','宋日隆','宋','宋诗','song-poetry','','[]','年來試凋邑，如僧住破庵。',275,'全唐诗/poet.song.238000.json','["年來試凋邑，如僧住破庵。", "頗識衆因果，寧忍事嗔貪。", "晨飧雖不飽，夜夢却自安。", "緬懷使里內，何異一室間。", "痛癢舉切身，惻怛失歡顔。", "曾徵三異政，勿見兩暑寒。", "皇帝念閩壤，掃帥田從班。", "紅旗已開閫，紫氣且度關。", "負弩擬郊迎，襥被出市闤。", "瞻蝕草木榮，覺此天地寬。", "禾實吐離離，泉瀉鳴潺潺。", "一稔已可期，百憂頓能刪。", "群來鄉士秀，共訴里胥奸。", "飛走寧有據，乞取苦無端。", "傷爾心肉剜，令我眉峰攢。", "刑非所用，欲已良亦難。", "五百決臀杖，雄卒捏手環。", "於以寬民力，於以警吏頑。", "亭午發丹陽，薄暮抵精藍。", "瓣香謁獨覺，且過借一簞。", "臨風飽清供，穿雲漫懷慚。", "候騎未來報，主僧且盤桓。", "桑下無三宿，挑包過別山。"]'),
('baac56fa-61e8-46a6-9bf4-79ffb74a7749','寶林寺二首  其二','宋日隆','宋','宋诗','song-poetry','','[]','寶林連上剎，獨覺佛中尊。',48,'全唐诗/poet.song.238000.json','["寶林連上剎，獨覺佛中尊。", "石室真身隱，苔碑勝跡存。", "空門留法嗣，俗舍有聞孫。", "晴雨從民欲，枌榆萬古恩。"]'),
('4c891066-bbe6-4819-ae6d-ad22f1396ce5','酬答鄱陽黎祥仲  其一','張洪','宋','宋诗','song-poetry','','[]','長鑱白木柄，茫茫走天涯。',24,'全唐诗/poet.song.238000.json','["長鑱白木柄，茫茫走天涯。", "寧知屋角松，流膏藏龜蛇。"]'),
('909a5194-eed3-4bb7-b8d5-09aaf36d1d4f','酬答鄱陽黎祥仲  其二','張洪','宋','宋诗','song-poetry','','[]','醫和不可鑄，空林芳菲菲。',24,'全唐诗/poet.song.238000.json','["醫和不可鑄，空林芳菲菲。", "六丁護香珀，千歲以爲期。"]'),
('24043aee-9f1c-49a6-b686-2f4b8892a282','句','朱惟賢','宋','宋诗','song-poetry','','[]','層簷月印高低影，寒壑風號遠近聲。',16,'全唐诗/poet.song.238000.json','["層簷月印高低影，寒壑風號遠近聲。"]'),
('b83d5f59-4117-4932-9559-62f38a7a5f89','大暑松下臥起二首  其一','陳天瑞','宋','宋诗','song-poetry','','[]','迅翻趨炎歊，高標閟幽雅。',72,'全唐诗/poet.song.238000.json','["迅翻趨炎歊，高標閟幽雅。", "隱士何所營，茇之清蔭下。", "故居禾黍生，帡幪若大廈。", "熟臥南風邊，飛夢游虞夏。", "五絃天上鳴，擊壤歌滿野。", "起來記遺音，析薪有樵者。"]'),
('1d1c60ed-1f93-4d91-a257-1b0d9bd81be9','大暑松下臥起二首  其二','陳天瑞','宋','宋诗','song-poetry','','[]','炎威一何驕，不有商飇慘。',96,'全唐诗/poet.song.238000.json','["炎威一何驕，不有商飇慘。", "蒼茫雲海路，飛龍不可覽。", "我本灌園人，昔乃從鉛槧。", "萬事已灰心，十載空嘗膽。", "亭亭松篁邊，小池開菡萏。", "芬清泥自污，根固波徒撼。", "終日哦其間，一臥寂百感。", "相期晚節香，看此秋容淡。"]'),
('715d2796-7343-4d6e-b441-e690a6b4ad1a','月巖','陳天瑞','宋','宋诗','song-poetry','','[]','怪石堆雲矗太宗，女媧煉出廣寒宮。',64,'全唐诗/poet.song.238000.json','["怪石堆雲矗太宗，女媧煉出廣寒宮。", "一輪常滿陰晴見，萬古無虧晝夜同。", "擣藥聲繁驅白兔，漏天孔正透清風。", "光明自照如來境，肯學嫦娥西復東。"]'),
('5426dea9-a5bb-41fe-9f98-b1b50cb03f1b','蘭溪道中','宋慶之','宋','宋诗','song-poetry','','[]','朝買蘭溪船，暮泊香頭市。',108,'全唐诗/poet.song.238000.json','["朝買蘭溪船，暮泊香頭市。", "如何十月天，復此連夜雨。", "朔風寒似鐵，曉色暗如土。", "道行不見人，路哭疑是鬼。", "棲棲遠方士，忽忽鄉心起。", "落葉響疎庭，空燈照寒被。", "離家能幾時，旅況已如此。", "茫茫楚山雲，渺渺楚江水。", "屈指計行程，此去復萬里。"]'),
('2baddda5-f906-4302-bf00-6366c48d2bd0','開爐日賦','宋慶之','宋','宋诗','song-poetry','','[]','筋力已非舊，逢寒亦自憐。',48,'全唐诗/poet.song.238000.json','["筋力已非舊，逢寒亦自憐。", "風霜在簷外，妻子語燈前。", "紙被添新絮，茶甌煮細泉。", "雖云方寸地，春意一陶然。"]'),
('bace7731-c6fc-43ff-b2df-9c678a2529cc','稽村','宋慶之','宋','宋诗','song-poetry','','[]','雪後寒增健，貪幽愛路生。',48,'全唐诗/poet.song.238000.json','["雪後寒增健，貪幽愛路生。", "羣兒燒葉坐，一鳥啄冰行。", "山色晴猶慘，梅花謝亦榮。", "小輿風割面，微醉任攲傾。"]'),
('c906404a-c4d7-45f8-af25-f1ed001ff0a9','哭趙東閣','宋慶之','宋','宋诗','song-poetry','','[]','秋風慘欲割，秋月明不發。',83,'全唐诗/poet.song.238000.json','["秋風慘欲割，秋月明不發。", "誰令聲名高，竟使壽命折。", "往年失四靈，詩道微一髪。", "縞素革織組，宮徵節亂聒。", "力排唐末陋，意風雅軋。", "清廟不待陳，黄壤詎能沒。", "新篇今寂寞，故墨慎無忽。"]'),
('ffb81867-6ea1-486e-9b52-af548143865f','項園即事。','宋慶之','宋','宋诗','song-poetry','','[]','時節飛花盡，幽林亦自香。',48,'全唐诗/poet.song.238000.json','["時節飛花盡，幽林亦自香。", "閒來看新水，獨立又斜陽。", "簷角鳥鳴霽，樹根魚就涼。", "一春風雨過，游事極相妨。"]'),
('6029ce61-9968-4185-ae12-3135e6e0d325','次惠上人冷泉夜坐','宋慶之','宋','宋诗','song-poetry','','[]','此景寫不盡，此懷誰與俱。',48,'全唐诗/poet.song.238000.json','["此景寫不盡，此懷誰與俱。", "月來林影碎，雲去石頭孤。", "萬籟各休息，天香乍有無。", "因師寄佳句，清夢更勞吾。"]'),
('3d78f89d-0909-4157-ab49-fdb5eda16d82','郊行偶成','宋慶之','宋','宋诗','song-poetry','','[]','野水連天闊，孤舟盡日閒。',24,'全唐诗/poet.song.238000.json','["野水連天闊，孤舟盡日閒。", "會須風雨過，一濟諒非難。"]'),
('e361f39e-5ac4-4143-bf3f-c2a8665a53a2','碧雞草堂呈劉後村','宋慶之','宋','宋诗','song-poetry','','[]','斯文海內聲名闊，猶是乾淳一脈餘。',63,'全唐诗/poet.song.238000.json','["斯文海內聲名闊，猶是乾淳一脈餘。", "須信昌黎曾得謗，可憐太史未書。", "碧雞有地吟詩老，金馬無心待詔初。", "甚欲見君三十載，春風今時侍巾車。"]'),
('67e8fcc5-e1a2-493b-b865-59b7e68e7af4','寓武昌報恩寺','宋慶之','宋','宋诗','song-poetry','','[]','孟宗祠下竹依然，借得空房竹樹邊。',64,'全唐诗/poet.song.238000.json','["孟宗祠下竹依然，借得空房竹樹邊。", "貧寺少逢僧過夏，遠鄉多是客經年。", "倩人汲水時煎茗，就佛分燈夜照眠。", "家信不來心欲斷，明朝又買漢陽船。"]'),
('2f1facf0-2c27-484a-afc9-09d5ce636d46','武昌懷古','宋慶之','宋','宋诗','song-poetry','','[]','極目平蕪送落暉，六朝征戰尚依稀。',64,'全唐诗/poet.song.238000.json','["極目平蕪送落暉，六朝征戰尚依稀。", "風生戰舸周郎過，月落南樓庾老歸。", "秋塞戍閒番馬病，春江流下蜀魚肥。", "神州北望知何處，父老猶能話岳飛。"]'),
('291ccefb-127c-403a-a1d4-3db533b4c678','放翁有五更讀書示子詩予亦次韻','宋慶之','宋','宋诗','song-poetry','','[]','秋風蟋蟀牀下鳴，茅茨耿耿秋燈明。',96,'全唐诗/poet.song.238000.json','["秋風蟋蟀牀下鳴，茅茨耿耿秋燈明。", "老夫掩卷發深喟，起視河漢初參橫。", "世人飲食幾知味，眼底古今復涇渭。", "藩籬是筆屋是書，風葉塵埃力空費。", "六籍在天日月存，我亦收拾還本根。", "此事兒輩未可論，紛紛場屋爭作元。"]'),
('f5c7f69d-485a-4479-a0e0-a86a97a12b12','戍歸詞','宋慶之','宋','宋诗','song-poetry','','[]','君去無還期，妾思無已時。',47,'全唐诗/poet.song.238000.json','["君去無還期，妾思無已時。", "軍無女子，誰爲補征衣。", "或傳雲中危，夫死賢王圍。", "恐傷老姑心，有淚不敢垂。"]'),
('dfa18860-4356-4869-8f2e-1b1520792472','廢墓','宋慶之','宋','宋诗','song-poetry','','[]','山水不改色，殘碑空蘚衣。',48,'全唐诗/poet.song.238000.json','["山水不改色，殘碑空蘚衣。", "多年翁仲在，寒食子孫稀。", "魈鬼時憑樹，虞人夜伏機。", "悲涼眼前事，火葬未全非。"]'),
('f0af8118-85a7-4c0a-9715-2af026557a97','然上人還松臺','宋慶之','宋','宋诗','song-poetry','','[]','白頭寧俯仰，自覺住山非。',48,'全唐诗/poet.song.238000.json','["白頭寧俯仰，自覺住山非。", "舊業雙松在，初秋一錫歸。", "從人借茶具，就日補寒衣。", "不見新詩久，朝來叩我扉。"]'),
('4d98f872-22fe-433f-a5fe-42429bd3fac5','句  其一','宋慶之','宋','宋诗','song-poetry','','[]','城中豈云隘，我見無夷途。',36,'全唐诗/poet.song.238000.json','["城中豈云隘，我見無夷途。", "所以龐德公，車不向此驅。", "斜陽掛林杪，野花續春餘。"]'),
('5e2efd5e-0dbf-4ec8-9f0c-6f3fbd993e19','句  其二','宋慶之','宋','宋诗','song-poetry','','[]','數年何處客，昨夜獨歸船。',12,'全唐诗/poet.song.238000.json','["數年何處客，昨夜獨歸船。"]'),
('3e557006-9d42-443c-aed0-1da2a7e69601','句  其三','宋慶之','宋','宋诗','song-poetry','','[]','飄泊知何處，艱難亦到僧。',12,'全唐诗/poet.song.238000.json','["飄泊知何處，艱難亦到僧。"]'),
('e835e4ff-888e-41bd-9013-32b79949f66d','句  其四','宋慶之','宋','宋诗','song-poetry','','[]','更長初過雁，蟄後稍無蛩。',12,'全唐诗/poet.song.238000.json','["更長初過雁，蟄後稍無蛩。"]'),
('16b01f55-7a16-472e-8de2-91a175cbe17c','東嶺旋憩亭','張朴','宋','宋诗','song-poetry','','[]','祖道東關外，於今已十年。',48,'全唐诗/poet.song.238000.json','["祖道東關外，於今已十年。", "未知何日是，還向此亭旋。", "鳥語雲根落，桃花嶺上妍。", "深慚頻作客，鄉國眼空懸。"]'),
('79d3b5f1-c168-44ca-94ab-c96eec2d8c4a','木筆花','張朴','宋','宋诗','song-poetry','','[]','亭亭花一樹，乍發小東牆。',48,'全唐诗/poet.song.238000.json','["亭亭花一樹，乍發小東牆。", "碧管描春色，丹鋒點化工。", "凝窗時染翰，弄影日書空。", "莫問龍蛇事，臨池興不窮。"]'),
('e2bcb3ea-40da-4a63-9af0-fbbb15942a79','題奣巖','何揚祖','宋','宋诗','song-poetry','','[]','石室何時霹靂開，曾聽繡斧凱歌回。',32,'全唐诗/poet.song.238000.json','["石室何時霹靂開，曾聽繡斧凱歌回。", "誰知二百餘年後，復有旌旗笳鼓來。"]'),
('849adbee-848a-4661-9beb-3d1b016d90f9','競渡櫂歌  其一','黄公紹','宋','宋诗','song-poetry','','[]','望天湖，望天湖，綠楊深處鼓𪔱𪔱。',32,'全唐诗/poet.song.238000.json','["望天湖，望天湖，綠楊深處鼓𪔱𪔱。", "好是年年三二月，湖邊日日看劃船。"]'),
('e6978de7-3c1e-442f-b3d8-d3e943883ca1','競渡櫂歌  其二','黄公紹','宋','宋诗','song-poetry','','[]','鬬輕橈，鬬輕橈，雪中花捲棹聲搖。',32,'全唐诗/poet.song.238000.json','["鬬輕橈，鬬輕橈，雪中花捲棹聲搖。", "天與玻璃三萬頃，儘教看得幾吳舠。"]'),
('ef1ff209-436c-49dd-a51e-74c8879c7752','競渡櫂歌  其三','黄公紹','宋','宋诗','song-poetry','','[]','看龍舟，看龍舟，兩隄未鬬水悠悠。',32,'全唐诗/poet.song.238000.json','["看龍舟，看龍舟，兩隄未鬬水悠悠。", "一片笙歌催鬧晚，忽然鼓棹起中流。"]'),
('7d97f327-d4ee-482f-aebc-40e03118e89c','競渡櫂歌  其四','黄公紹','宋','宋诗','song-poetry','','[]','駕靈鼉，駕靈鼉，幾年翠舞與珠歌。',32,'全唐诗/poet.song.238000.json','["駕靈鼉，駕靈鼉，幾年翠舞與珠歌。", "看到日斜猶未足，湧金門外湧金波。"]'),
('88872990-8af6-449a-81d9-3eac4652a698','競渡櫂歌  其五','黄公紹','宋','宋诗','song-poetry','','[]','馬如龍，馬如龍，飛過蘇隄健鬬風。',32,'全唐诗/poet.song.238000.json','["馬如龍，馬如龍，飛過蘇隄健鬬風。", "枊下繫船青作纜，湖邊薦酒碧爲筒。"]'),
('274265b0-9afb-4088-b16e-cf03c3656ee7','競渡櫂歌  其六','黄公紹','宋','宋诗','song-poetry','','[]','繡周張，繡周張，樓臺簾幙絮高揚。',32,'全唐诗/poet.song.238000.json','["繡周張，繡周張，樓臺簾幙絮高揚。", "誰賦珠宮幷內闕，懷王去後去沉湘。"]'),
('0c2daee6-560e-4fe7-9f34-963f5488f81c','競渡櫂歌  其七','黄公紹','宋','宋诗','song-poetry','','[]','棹如飛，棹如飛，水中萬鼓起潛螭。',32,'全唐诗/poet.song.238000.json','["棹如飛，棹如飛，水中萬鼓起潛螭。", "最是玉堂堂上好，躍來奪錦看吳兒。"]'),
('b683faa5-efb6-48ec-b5bf-4994aff6df76','競渡櫂歌  其八','黄公紹','宋','宋诗','song-poetry','','[]','建雲斿，建雲斿，土風到處總相猶。',32,'全唐诗/poet.song.238000.json','["建雲斿，建雲斿，土風到處總相猶。", "朝了霍山朝岳帝，十分打扮是杭州。"]'),
('46f1d5ea-be6f-4606-851d-94a2c097a7e8','競渡櫂歌  其九','黄公紹','宋','宋诗','song-poetry','','[]','踏青青，踏青青，西泠橋畔草連汀。',32,'全唐诗/poet.song.238000.json','["踏青青，踏青青，西泠橋畔草連汀。", "撲得龍船兒一對，畫闌倚遍看遊人。"]'),
('96c4e880-5744-4bbc-8a5e-1dd447c1d3c9','競渡櫂歌  其一○','黄公紹','宋','宋诗','song-poetry','','[]','月明中，月明中，滿湖春水望難窮。',32,'全唐诗/poet.song.238000.json','["月明中，月明中，滿湖春水望難窮。", "欲學楚歌歌不得，一場離恨兩眉峯。"]'),
('6dfe2825-5089-4e6d-949d-10a639cfa919','題康店鋪','李炳','宋','宋诗','song-poetry','','[]','短衣自獵南山虎，正好漁樵不亂群。',32,'全唐诗/poet.song.238000.json','["短衣自獵南山虎，正好漁樵不亂群。", "妄以宿嫌誅醉尉，令人翻恨李將軍。"]'),
('c2d7014b-d997-4f6a-9db6-ded993f6eae0','寄陳古堂  其一','翁森','宋','宋诗','song-poetry','','[]','往來幾興亡，古今一天地。',48,'全唐诗/poet.song.238000.json','["往來幾興亡，古今一天地。", "而人生其中，云胡不自貴。", "渺予寸心孤，浩發千載喟。", "殘夜抱遺編，青燈照無寐。"]'),
('8ced6dd0-8b5b-4d6d-aef7-10f38958950d','寄陳古堂  其二','翁森','宋','宋诗','song-poetry','','[]','懷人月千里，開門秋一林。',48,'全唐诗/poet.song.238000.json','["懷人月千里，開門秋一林。", "徘徊不得寐，對此石上琴。", "山水有真領，寥寥本無音。", "寄語子鍾子，須知琴外心。"]'),
('c2f2a7c9-d528-4ecf-a1f4-b988a129016a','次古堂歲寒雜書韻','翁森','宋','宋诗','song-poetry','','[]','清新如修竹，月露洗瑯玕。',96,'全唐诗/poet.song.238000.json','["清新如修竹，月露洗瑯玕。", "愛之不能舍，一月三四看。", "伊人偉識量，文字餘波瀾。", "出處早見幾，在漢申屠蟠。", "風雨江村暮，門掩清燈寒。", "所抱寸心在，千載重不刊。", "滿前熾子孫，已足遺以安。", "會當驂白鹿，華頂煉還丹。"]'),
('235476b7-435d-4911-9e94-ef6f7df745aa','吳烈女','翁森','宋','宋诗','song-poetry','','[]','士習與世換，一墮不自持。',144,'全唐诗/poet.song.238000.json','["士習與世換，一墮不自持。", "寧如二女子，至性不自移。", "人之能爲人，所懼大節虧。", "吾父死汝手，吾身豈汝隨。", "匪云隨我節，義合同其歸。", "空山雨流血，白日寒無輝。", "女子有是哉，道旁爲嗟咨。", "北風颯萬類，始見青松姿。", "有女焯其行，發潛可無詩。", "死其身不顧，身後遑所知。", "傷心復傷心，風味日以漓。", "寄語讀書者，曷不媿於斯。"]'),
('54814668-1bd6-436c-ac94-0b80b7f16d5c','柬陳南園','翁森','宋','宋诗','song-poetry','','[]','自昔賢哲士，遭運每多屯。',49,'全唐诗/poet.song.238000.json','["自昔賢哲士，遭運每多屯。", "世途自屈曲，難揉胸輪囷。", "終夜起太息，所以憂非賤貧。", "相望各努力，勗哉追天游。"]'),
('b639a1f5-5496-4f87-a374-2e8dac960c98','四時讀書樂  其一','翁森','宋','宋诗','song-poetry','','[]','山光照檻水遶廊，舞雩歸詠春風香。',64,'全唐诗/poet.song.238000.json','["山光照檻水遶廊，舞雩歸詠春風香。", "好鳥枝頭亦朋友，落花水面皆文章。", "蹉跎莫遣韶光老，人生唯有讀書好。", "讀書之樂樂何如，綠滿窗前草不除。"]'),
('c15b4049-22fa-4ac6-8eb6-c6c198193f2c','四時讀書樂  其二','翁森','宋','宋诗','song-poetry','','[]','新竹壓簷桑四圍，小齋幽敞明朱曦。',64,'全唐诗/poet.song.238000.json','["新竹壓簷桑四圍，小齋幽敞明朱曦。", "晝長吟罷蟬鳴樹，夜深燼落螢入幃。", "北窗高臥羲皇侶，只因素稔讀書趣。", "讀書之樂樂無窮，瑤琴一曲來薰風。"]'),
('48f97b87-d61a-47b9-aa22-1f789b98d725','四時讀書樂  其三','翁森','宋','宋诗','song-poetry','','[]','昨夜庭前葉有聲，籬豆花開蟋蟀鳴。',64,'全唐诗/poet.song.238000.json','["昨夜庭前葉有聲，籬豆花開蟋蟀鳴。", "不覺商意滿林薄，蕭然萬籟涵虛清。", "床前賴有短檠在，及此讀書功更倍。", "讀書之樂樂陶陶，起弄明月霜天高。"]'),
('550b40db-0b95-461b-9335-3072555265c9','四時讀書樂  其四','翁森','宋','宋诗','song-poetry','','[]','木落水盡千崖枯，迥太吾亦見真吾。',64,'全唐诗/poet.song.238000.json','["木落水盡千崖枯，迥太吾亦見真吾。", "坐對韋編燈動壁，高歌夜半雪壓廬。", "地爐茶鼎烹活火，一清足稱讀書者。", "讀書之樂何處尋，數點梅花天地心。"]'),
('112dfe93-c403-42e5-92df-6b36dda2daf0','採桑','翁森','宋','宋诗','song-poetry','','[]','採桑子，採桑子。',130,'全唐诗/poet.song.238000.json','["採桑子，採桑子。", "朝去採桑日已曙，暮去採桑雲欲雨。", "桑葉鬰茂寒露眉，桑枝屈曲勾破衣。", "大婦年年憂蠶饑，小婦忙忙催葉歸。", "東鄰女，對西鄉。", "道蠶眠起較遲早，已覺官吏促早繰。", "新絲二月已賣了，賣了新絲更栽桑。", "桑栽還似去年長，豈知城中花囿花壓牆。", "朱樓旭日映紅粧，不識桑樹有羅裳。"]'),
('7fc4835c-ac6e-45a8-a05a-1458cc7db12c','送行可和尚遊雁宕','翁森','宋','宋诗','song-poetry','','[]','靈運平生屐，如何一瘦藤。',48,'全唐诗/poet.song.238000.json','["靈運平生屐，如何一瘦藤。", "夕陽紅葉寺，秋雨白頭僧。", "閱世三兵火，傳心幾佛燈。", "詎羅還記我，曾向此山登。"]'),
('19985ea9-40c3-4ca7-8ce2-dd9739471951','過天台','翁森','宋','宋诗','song-poetry','','[]','日落千山外，悠然一望賖。',48,'全唐诗/poet.song.238000.json','["日落千山外，悠然一望賖。", "黄檀六七里，綠竹兩三家。", "幽步窺殘雪，孤愁入遠霞。", "今宵何處宿，茆屋有梅花。"]'),
('2e02db82-3117-44db-b48f-925cd5a819e4','山齋偶書','翁森','宋','宋诗','song-poetry','','[]','春風桃灼灼，秋雨黍離離。',24,'全唐诗/poet.song.238000.json','["春風桃灼灼，秋雨黍離離。", "眼底千年事，空山獨坐時。"]'),
('095a046e-a06c-491b-aef3-dd8470a193df','題陶淵明臨流賦詩圖','翁森','宋','宋诗','song-poetry','','[]','閒居淡無事，臨流忽有得。',24,'全唐诗/poet.song.238000.json','["閒居淡無事，臨流忽有得。", "平生詩外心，灘上一鷗白。"]'),
('bd2df342-1470-4ea2-a844-a501a11b387e','屋頭梅開一蕊','翁森','宋','宋诗','song-poetry','','[]','寂寞茆齋下，孤梅一蕊開。',24,'全唐诗/poet.song.238000.json','["寂寞茆齋下，孤梅一蕊開。", "無人知此意，日暮繞蒼苔。"]'),
('9286246d-5001-4d1a-b08d-29f07ea78aff','宿山中田家','翁森','宋','宋诗','song-poetry','','[]','欹坐頹簷醉濁醪，松油燒盡夜蕭騷。',32,'全唐诗/poet.song.238000.json','["欹坐頹簷醉濁醪，松油燒盡夜蕭騷。", "兒童十歲能吹笛，嘹亮一聲山月高。"]'),
('d061dec6-f90b-47fc-9878-4b12dd3abf05','海門道中宿田家','翁森','宋','宋诗','song-poetry','','[]','煙浦偶同漁父渡，竹籬愛宿野人家。',32,'全唐诗/poet.song.238000.json','["煙浦偶同漁父渡，竹籬愛宿野人家。", "悠然此夜得真領，隴月初生梅始華。"]'),
('9625fa11-f184-4488-981f-71440b3c0d31','漁','翁森','宋','宋诗','song-poetry','','[]','三月桃花浪暖初，隔溪人問有魚無。',32,'全唐诗/poet.song.238000.json','["三月桃花浪暖初，隔溪人問有魚無。", "回言未納官租稅，不敢私將網下湖。"]'),
('e828a99b-0515-48a3-a98b-308a124876bf','樵','翁森','宋','宋诗','song-poetry','','[]','妻出叮嚀夫轉聽，採薪須束擔頭輕。',32,'全唐诗/poet.song.238000.json','["妻出叮嚀夫轉聽，採薪須束擔頭輕。", "夜來雨過蒼苔滑，莫向巉巖險處行。"]'),
('3dd859df-fc07-4d1e-a146-f470112c2019','耕','翁森','宋','宋诗','song-poetry','','[]','村北村南叫杜鵑，簑披春雨掏含煙。',32,'全唐诗/poet.song.238000.json','["村北村南叫杜鵑，簑披春雨掏含煙。", "不辭辛苦秋成熟，會見黄雲遍野田。"]'),
('2ed97860-b771-44b8-ad08-cb269740154d','牧','翁森','宋','宋诗','song-poetry','','[]','細雨空濛煙草稠，相呼相逐過林丘。',32,'全唐诗/poet.song.238000.json','["細雨空濛煙草稠，相呼相逐過林丘。", "回來莫向山邊去，昨夜前村虎食牛。"]'),
('4e233352-60a8-4c1f-b760-0a0459342e23','落花呈王如山監簿','翁森','宋','宋诗','song-poetry','','[]','滿地飛花錦作堆，休言落後不如開。',32,'全唐诗/poet.song.238000.json','["滿地飛花錦作堆，休言落後不如開。", "愛渠不逐波流去，自在陰崖覆綠苔。"]'),
('7f656bb4-73aa-42f3-b993-08abad7c1ef8','訪古村彥高不值留竹間','翁森','宋','宋诗','song-poetry','','[]','西風吹起一襟秋，遙度前村訪子猷。',32,'全唐诗/poet.song.238000.json','["西風吹起一襟秋，遙度前村訪子猷。", "不見子猷空倚竹，此心猶爲此君留。"]'),
('92df1eaf-9e4f-488c-8f95-bd2aba1c3aaa','訪朱道士不遇題山扉','翁森','宋','宋诗','song-poetry','','[]','閒來松下叩仙家，惟見山扉掩碧霞。',32,'全唐诗/poet.song.238000.json','["閒來松下叩仙家，惟見山扉掩碧霞。", "步繞籬根霜屨滑，已將心事語黄花。"]'),
('c18ce21f-ee5c-4730-acdd-6c1104ca8742','山房','翁森','宋','宋诗','song-poetry','','[]','清臥荒村絕點塵，疏鐘敲月夢中聞。',32,'全唐诗/poet.song.238000.json','["清臥荒村絕點塵，疏鐘敲月夢中聞。", "山僧早起知何事，當戶燒香禮白雲。"]'),
('2611301b-5967-4f8e-8ea6-64aa3e45616d','春暮即事','翁森','宋','宋诗','song-poetry','','[]','啼鵑春已暮，徙倚念流光。',48,'全唐诗/poet.song.238000.json','["啼鵑春已暮，徙倚念流光。", "雨漲溪舂急，山晴火種忙。", "尋芳知興淺，懷遠覺愁長。", "兩月無來客，青苔滿石牀。"]'),
('cecceff8-1b4e-4072-9497-0a8c15af65c4','夏日書懷','翁森','宋','宋诗','song-poetry','','[]','孤坐衲蒙頭，巖扉花竹幽。',48,'全唐诗/poet.song.238000.json','["孤坐衲蒙頭，巖扉花竹幽。", "山明雲罷雨，天迥月懸秋。", "煮茗猿分飲，藏蔬鼠或偷。", "道人方睡去，夢入五台遊。"]'),
('eeee92d4-3d88-475c-bbc8-50b9039f7a9d','寄懷呂六松','翁森','宋','宋诗','song-poetry','','[]','西風吹薄暝，萬葉賦秋聲。',48,'全唐诗/poet.song.238000.json','["西風吹薄暝，萬葉賦秋聲。", "高鵠雲邊少，孤蟬雨後清。", "年光凄短思，世態重離情。", "石壁滄洲闊，休寒白鷺盟。"]'),
('51ff8be5-ca98-43ad-94e1-d2d34145a60e','叢桂軒 嫩紅','趙崇㻱','宋','宋诗','song-poetry','','[]','昨夜西風吹御溝，紅搖桂子麝香浮。',64,'全唐诗/poet.song.238000.json','["昨夜西風吹御溝，紅搖桂子麝香浮。", "蟾宮影散三千界，玉殿根盤第一流。", "仙骨知非凡俗相，錦標喜簇少年頭。", "欲從雲外移真種，試向丹梯最上遊。"]'),
('bd22ac44-e3cf-48c0-87a5-cec960711a05','叢桂軒 口黄','趙崇㻱','宋','宋诗','song-poetry','','[]','半軒秋雨染鵝黄，望裏還疑分外香。',64,'全唐诗/poet.song.238000.json','["半軒秋雨染鵝黄，望裏還疑分外香。", "月到樹傍生浄想，雲開花底擁仙裝。", "披襟笑賞和衣馥，攜手高攀滿袖芳。", "信道男兒輸宿願，一枝早占廣寒香。"]'),
('fefe4a2b-21d3-4d01-ac79-c5d7b5caeffb','叢桂軒 妖白','趙崇㻱','宋','宋诗','song-poetry','','[]','種自姮娥宮裏栽，如何亦向世間開。',64,'全唐诗/poet.song.238000.json','["種自姮娥宮裏栽，如何亦向世間開。", "偏宜素質妝秋晚，不比晚華怕早摧。", "風遞香來薰綺席，月移影上弄瑤臺。", "看時直欲令人醉，似向瓊林宴御杯。"]'),
('7235572e-6316-4e8f-ba80-939f3e906ba0','叢桂軒 老翠','趙崇㻱','宋','宋诗','song-poetry','','[]','霓裳阿妹舞婆娑，老翠連雲秀復華。',64,'全唐诗/poet.song.238000.json','["霓裳阿妹舞婆娑，老翠連雲秀復華。", "露令山房籠月色，風清池館落天葩。", "分來竇氏三秋種，斧罷吳生幾樹花。", "莫訝仙才無用處，一朝隊引嘯煙霞。"]'),
('d2e13e4d-bcbb-4c44-b48d-338c6785aa89','過叔祖崇栲翁別業','趙良坡','宋','宋诗','song-poetry','','[]','別業開東野，蕭然足臥雲。',48,'全唐诗/poet.song.238000.json','["別業開東野，蕭然足臥雲。", "濤聲晴射雨，庭影夏呈秋。", "返照霞初幕，遙峰翠欲流。", "以斯清樂境，不信有瀛洲。"]'),
('57c67837-736b-4b63-baef-47ab8ca0e8f0','贈友之閩','趙良坡','宋','宋诗','song-poetry','','[]','世人作離別，惟別酒一觴。',60,'全唐诗/poet.song.238000.json','["世人作離別，惟別酒一觴。", "今我與君別，稍稍鄙玕瑯。", "閩海古名地，幕職不可量。", "聖明廣延攬，計日下褒章。", "願將此言贈，用以代瓊漿。"]'),
('a9343672-cde1-4ef1-8e5d-09b8b2f7e20c','隱居','趙良坡','宋','宋诗','song-poetry','','[]','習靜深山裏，幽棲趣偪真。',48,'全唐诗/poet.song.238000.json','["習靜深山裏，幽棲趣偪真。", "青樓何足契，白雪故相親。", "守道無妨困，藏書不聖貧。", "昔人嘉遯漢，我亦愛逃秦。"]'),
('5672f32d-29bf-445d-b0df-84d1ef11eb38','雪水菴咏雪二十韻','趙良坡','宋','宋诗','song-poetry','','[]','玄冥司號令，屏翳驅雲車。',240,'全唐诗/poet.song.238000.json','["玄冥司號令，屏翳驅雲車。", "巧舞穿幽隙，輕揚下曲漥。", "初疑蠶食葉，猶恐蠏行沙。", "鉛汞三千界，璚瑤百萬家。", "樓臺銀作砌，城闕玉爲衙。", "壓竹枝翻重，封梅色更佳。", "文光偏得月，點綴易爲花。", "萬瓦魚鱗矗，千山鳥迹遐。", "凝簷珠錯落，布地粉交加。", "恍若水晶溜，猶然寶鑑華。", "餘暉翻鶴羽，皓彩撲烏紗。", "鏤刻非因巧，陶鎔未有瑕。", "冰奩緣沼合，縞带逐車斜。", "圜石銀盤疊，尖峯玉筍芽。", "豪家爭玩賞，洞府亦諠譁。", "錦帳傳巵酒，竹爐沸鼎茶。", "豐年先有兆，清氣浩無涯。", "飛絮那能擬，憑虛最可誇。", "不須東郭履，自是剡溪艖。", "恭喜瞻三白，停杯看六葩。"]'),
('b3d480f2-92e1-450c-b897-199286518f68','咏楊司業觀菊圖','趙良坡','宋','宋诗','song-poetry','','[]','寄傲南窗罷草玄，寥寥三徑菊花前。',32,'全唐诗/poet.song.238000.json','["寄傲南窗罷草玄，寥寥三徑菊花前。", "春風自足繁桃李，爲愛秋香到晚妍。"]'),
('83f836c9-101d-465a-ab85-ca727c22118c','避暑山亭','趙良坡','宋','宋诗','song-poetry','','[]','茂林深處散清涼，石罅泉聲引興長。',32,'全唐诗/poet.song.238000.json','["茂林深處散清涼，石罅泉聲引興長。", "高掛角巾舒嘯傲，炎飈那得到山莊。"]'),
('e2cff7fc-c87b-4998-82b8-d365210b81b1','程鉅夫惠茶','趙若恢','宋','宋诗','song-poetry','','[]','臥病文園日正長，斜題遠寄雨前槍。',64,'全唐诗/poet.song.238000.json','["臥病文園日正長，斜題遠寄雨前槍。", "黄綾不羨龍團貴，紫筍還聞雀舌香。", "一硯落花人醉醒，半簾飛絮燕歸忙。", "新泉活火松風細，何處黄州白玉堂。"]'),
('2bcb6376-7bc1-4ba5-8403-0f40521969d1','鳳鳴洞','史唐卿','宋','宋诗','song-poetry','','[]','何年雷斧鑿山裂，千尺蒼崖瀉飛雪。',65,'全唐诗/poet.song.238000.json','["何年雷斧鑿山裂，千尺蒼崖瀉飛雪。", "孤鳳一去聲不聞，海水桑田幾興滅。", "我知仙去仙當存，時見真形坐巖穴。", "青天半夜玉簫寒，喚時醒幽人弄明月。"]'),
('eb3c13e4-5667-4ff0-ab69-86ddf22fe555','山水小景','陳虞之','宋','宋诗','song-poetry','','[]','千年老樹立蒼石，三峯兩峯天出雲。',32,'全唐诗/poet.song.238000.json','["千年老樹立蒼石，三峯兩峯天出雲。", "青溪道士坐船上，自按玉簫人不聞。"]'),
('822ed557-9e2e-4df6-949e-6b2454009ba5','送別','陳虞之','宋','宋诗','song-poetry','','[]','柳濕征衫晚出關，荒城古雪劍花寒。',32,'全唐诗/poet.song.238000.json','["柳濕征衫晚出關，荒城古雪劍花寒。", "西風漠漠龍沙路，馬上青山带醉看。"]'),
('4475aca3-97b3-4665-8e27-acb14c40cef5','題北郭外前湯普濟庵','陳炤','宋','宋诗','song-poetry','','[]','一尖龍舌地，蘭若此中開。',48,'全唐诗/poet.song.238000.json','["一尖龍舌地，蘭若此中開。", "曲徑深依竹，荒池淺鑿苔。", "要令溪水接，莫礙野雲來。", "只恐菴居興，難淹出世材。"]'),
('468bf5d9-3bbb-430e-8c5a-ecd156f6213b','秦皇石','俞應僉','宋','宋诗','song-poetry','','[]','祖龍盛氣役神鞭，壁立無移只屹然。',32,'全唐诗/poet.song.238000.json','["祖龍盛氣役神鞭，壁立無移只屹然。", "定見先朝陳寶化，陰靈寂寂笑求仙。"]'),
('04d23736-a642-4cdb-8bfd-c7d41108a74b','溫陵吳氏瓠齋  其一','余謙一','宋','宋诗','song-poetry','','[]','試問高齋底許，瓠瓜星舍明邊。',28,'全唐诗/poet.song.238000.json','["試問高齋底許，瓠瓜星舍明邊。", "椰大能容千古，壺中別有洞天。"]'),
('bf506c04-91ca-4650-8314-df056d27d318','溫陵吳氏瓠齋  其二','余謙一','宋','宋诗','song-poetry','','[]','大樗大椿等類，率是內篇寓言。',28,'全唐诗/poet.song.238000.json','["大樗大椿等類，率是內篇寓言。", "我謂惠王瓠種，合種莊家漆園。"]'),
('1029a87e-c8c5-4b17-9eb6-29110c9fafaf','溫陵吳氏瓠齋  其三','余謙一','宋','宋诗','song-poetry','','[]','詩記斷壺秋半，易占碩果春先。',28,'全唐诗/poet.song.238000.json','["詩記斷壺秋半，易占碩果春先。", "粒許中間種子，乾坤生意無邊。"]'),
('4a28e8ea-cafe-4aac-9fe2-8814bfe640b1','溫陵吳氏瓠齋  其四','余謙一','宋','宋诗','song-poetry','','[]','提壺足供杯勺，吹匏可入絃歌。',28,'全唐诗/poet.song.238000.json','["提壺足供杯勺，吹匏可入絃歌。", "一瓢濩落無用，無奈夫君拙何。"]'),
('afbbff11-6bd3-44e4-b2ec-a3ded98c2ab2','三友堂','余謙一','宋','宋诗','song-poetry','','[]','歲晚惟松竹，於梅伯仲間。',24,'全唐诗/poet.song.238000.json','["歲晚惟松竹，於梅伯仲間。", "藉溪幷白水，着個老屏山。"]'),
('b0e5d1c7-9e8c-44ef-a86e-742b3c973590','送陳竹所帥越  其一','余謙一','宋','宋诗','song-poetry','','[]','留侯羽翼計危成，誰遣鴻飛避杳冥。',31,'全唐诗/poet.song.238000.json','["留侯羽翼計危成，誰遣鴻飛避杳冥。", "一女倚楹猶識，不知柱後立何人。"]'),
('a35c2c64-ab72-401d-a39c-98f4476311ff','送陳竹所帥越  其二','余謙一','宋','宋诗','song-poetry','','[]','供帳榮歸一日同，故鄉增重漢朝空。',32,'全唐诗/poet.song.238000.json','["供帳榮歸一日同，故鄉增重漢朝空。", "二疎事莫徵圖畫，西陌東阡看兩翁。"]'),
('7e223900-b07a-4ad6-b72e-29c7e63607ae','送陳竹所帥越  其三','余謙一','宋','宋诗','song-poetry','','[]','便使絲絇離禁闥，還教牙纛傍天京。',32,'全唐诗/poet.song.238000.json','["便使絲絇離禁闥，還教牙纛傍天京。", "鄴侯浪說君王寵，避謗江西幾許程。"]'),
('f2003a02-766e-476f-a4eb-c642fe5bd3bd','次韻胡竹莊元夕','余謙一','宋','宋诗','song-poetry','','[]','佳人月下翠成行，糰鋪高張椀舞忙。',64,'全唐诗/poet.song.238000.json','["佳人月下翠成行，糰鋪高張椀舞忙。", "想見風情杜書記，暗中揮淚憶錢塘。", "一老東家喚不譍，當年膴仕正承平。", "何人誦得科燈判，莫向膏脂上取明。"]'),
('1981024c-4b03-4046-b815-997786953774','挽陳郡倅用虎妻朱安人  其一','余謙一','宋','宋诗','song-poetry','','[]','闔郡無男子，夫人可奈何。',48,'全唐诗/poet.song.238000.json','["闔郡無男子，夫人可奈何。", "平生羞蔡琰，一死伴湘娥。", "門盍來旌表，鄰應輟杵歌。", "潘郎家國恨，怪得鬢絲多。"]'),
('d7d5ddf4-c5aa-4329-976d-eec42858a498','挽陳郡倅用虎妻朱安人  其二','余謙一','宋','宋诗','song-poetry','','[]','太息睢陽事，重圍保障孤。',48,'全唐诗/poet.song.238000.json','["太息睢陽事，重圍保障孤。", "兄公能死節，女子亦捐軀。", "半被金閨婿，孤燈自發姑。", "百年遺恨處，風雨暗環湖。"]'),
('1e623619-5402-4472-a5ff-30bd63299bf6','城山國清塘','余謙一','宋','宋诗','song-poetry','','[]','湖光山色酒杯中，此會那知一笑同。',64,'全唐诗/poet.song.238000.json','["湖光山色酒杯中，此會那知一笑同。", "風暖空巖落松子，雨晴新漲沒鳬翁。", "隔林村落微茫見，一徑禪房曲折通。", "老艾當年題品處，斜陽無語想高風。"]'),
('c82c19eb-84ba-4263-ada8-46e3bf8c25a0','賀南谷兄與男孫同科','趙與闢','宋','宋诗','song-poetry','','[]','暮年驥足騁青雲，更喜文星耀一門。',64,'全唐诗/poet.song.238000.json','["暮年驥足騁青雲，更喜文星耀一門。", "觀榜同登父與子，策名重見祖和孫。", "偶然盛事酬先志，賸有奇芳在後昆。", "我亦瀛洲連步者，相蘄忠孝報君恩。"]'),
('601b27ab-9d06-4035-9d71-707896f87647','良坦姪再轉福清縣贈行','趙與闢','宋','宋诗','song-poetry','','[]','甲年謝策志應酬，今日分符力已優。',32,'全唐诗/poet.song.238000.json','["甲年謝策志應酬，今日分符力已優。", "好把丹心懸北闕，春風次第荷綸褒。"]'),
('e497499e-f42b-4ef9-9d5e-2420f3cb8304','贈良坦姪知永嘉','趙與闢','宋','宋诗','song-poetry','','[]','墨綬銅章拜命新，鳴琴之治在於今。',32,'全唐诗/poet.song.238000.json','["墨綬銅章拜命新，鳴琴之治在於今。", "花封佇見風流似，柳舍休教別人殷。"]'),
('aa00067a-b9bc-4e86-9dc7-e94d8ae15c65','村晚','雷震','宋','宋诗','song-poetry','','["\u513f\u7ae5", "\u5199\u666f", "\u519c\u6751"]','草滿寒塘水滿陂，山銜落日浸寒漪。',32,'全唐诗/poet.song.238000.json','["草滿寒塘水滿陂，山銜落日浸寒漪。", "牧童歸去橫牛背，短笛無腔信口吹。"]'),
('69245a85-1e54-48bd-a2e2-986cc4b501bc','紅梅','李謹思','宋','宋诗','song-poetry','','[]','月香水影眩錦畫，冰魂雪骨酣華春。',64,'全唐诗/poet.song.238000.json','["月香水影眩錦畫，冰魂雪骨酣華春。", "神仙狡獪本玩世，處士游俠聊驚人。", "怒艴不顧殺氣橫，忠赤自與晴曦親。", "山林著汝吾未許，絳衣朱襮鏖緇塵。"]'),
('ada8598a-0cbf-4072-93de-2e0b6ff297cd','楮衾','李謹思','宋','宋诗','song-poetry','','[]','相親賴有楮先生，雪與陽春指顧成。',64,'全唐诗/poet.song.238000.json','["相親賴有楮先生，雪與陽春指顧成。", "狐白溫溫疑伯仲，龜紋隱隱見縱橫。", "夜闌更作封章夢，晨起猶聞展卷聲。", "垂老未忘鑽故紙，三生飛氣太分明。"]'),
('5c033b8b-a117-45e4-972d-0b840cabed23','題文丞相吟嘯集','李謹思','宋','宋诗','song-poetry','','[]','南人不識兩膝貴，曲摺百態卑且勞。',248,'全唐诗/poet.song.238000.json','["南人不識兩膝貴，曲摺百態卑且勞。", "斯人護膝不護頭，故以頸血霑君刀。", "蟠胸孤憤擘不碎，殺氣千丈纏旌旄。", "援桴親鼓盡南海，背水更用蜑丁鏖。", "俘來吮血語神語，咄咄尚與天爭豪。", "須臾赤日減顔色，玄雲莾莾風颼颼。", "或言巨靈收拾付真宰，讀罷拊臆生長號。", "又言豐隆列對愁絕，疾指玉鞭鞭六鼇。", "雨瓢倒翻水怪舞，斗樞橫軋天籟號。", "憐伊肝膽苦復苦，亦見曩昔真離騷。", "劫灰滿地莫掛眼，蓬萊雖遠容輕舠。", "長巨人癘鬼尚堪戰，儘閑未許飛仙遨。", "乃言興廢在爾不吾與，吾死吾主吾焉逃。", "魯叟聞言拍手笑，斯人六經爲骨爲皮毛。", "斯人捲取六經去，空將贋本傳兒曹。"]'),
('acea1569-fc52-4c1a-b905-9b18b6f0b424','懷古','李謹思','宋','宋诗','song-poetry','','[]','昔我從耆英，圖史娛朝昏。',192,'全唐诗/poet.song.238000.json','["昔我從耆英，圖史娛朝昏。", "咄嗟陵與谷，永謝西州門。", "夢中亦識路，欲往先銷魂。", "往還無須臾，失聲強復吞。", "西山照公檻，南山亙公垣。", "平生五畝池，東海遙崩奔。", "公門山海幷，遂斡造化元。", "招公在薇菊，酬公有佳尊。", "行吟聞地籟，飛奏劘天閽。", "公來月星懸，公歸江漢翻。", "六籍未渠央，百聖諒斯存。", "翩翩媚學子，風節當誰敦。", "我髪日以變，洮面留心源。", "庶無騂汗流，獨此清淚痕。", "英英出靈變，杳杳通緒言。", "因風薦商參，秋思隨孤騫。"]'),
('94761bef-32fd-4555-9b56-144e6ab4b189','補疎齋題鵝湖','李謹思','宋','宋诗','song-poetry','','[]','客來誰與期，微鐘度山椒。',48,'全唐诗/poet.song.238000.json','["客來誰與期，微鐘度山椒。", "松風如起予，間以笙與簫。", "逸響諒斯存，幽蹤莽難招。", "極目不知還，新詩坐泬寥。"]'),
('0af6f899-de08-4644-8503-3a2d1efbf8ed','王以道三喪未舉','李謹思','宋','宋诗','song-poetry','','[]','豈無一弓地，載子三世碑。',48,'全唐诗/poet.song.238000.json','["豈無一弓地，載子三世碑。", "碑端語云云，碑下冢纍纍。", "白楊秋氣深，碧草春露滋。", "翻憐會稽山，禹穴不得窺。"]'),
('c8e6f5c2-5fc5-4389-a3ca-7afb82e7995c','贈李節婦','李謹思','宋','宋诗','song-poetry','','[]','猝猝多羝屈，幽幽獨雉經。',48,'全唐诗/poet.song.238000.json','["猝猝多羝屈，幽幽獨雉經。", "借渠施粉黛，聊與照丹青。", "孤槥何年寄，重泉底處扃。", "有人能縮地，不隔短長亭。"]'),
('03d8418e-3829-4eca-adeb-98f5b890532f','寄進士熊退齋  其一','李謹思','宋','宋诗','song-poetry','','[]','猶存火後書，罕識卷中字。',47,'全唐诗/poet.song.238000.json','["猶存火後書，罕識卷中字。", "無筆補玄經，有金酬載記。", "漫漫歲月馳，忽忽春閟。", "欲辨已忘言，涕淚空垂泗。"]'),
('93bfc8eb-cb97-46f2-84e0-c880d305530e','寄進士熊退齋  其二','李謹思','宋','宋诗','song-poetry','','[]','殉義若殉財，避名如避箭。',48,'全唐诗/poet.song.238000.json','["殉義若殉財，避名如避箭。", "況當喜懼交，肯與寵辱戰。", "百年元亮心，一日宣明面。", "朱門轍跡多，山路微如綫。"]'),
('c099a6cd-12a8-4256-b0d9-72bb41cd840c','直釣巖','李芮','宋','宋诗','song-poetry','','[]','無械仙翁去，巖垂直釣名。',48,'全唐诗/poet.song.238000.json','["無械仙翁去，巖垂直釣名。", "重開茅葦塞，仰見斗山明。", "便覺天光近，從教俗眼驚。", "登臨試一覽，心目得雙清。"]'),
('a4b0fb7a-c493-4460-a58d-37fe01d3f87f','寄羅惜惜','張幼謙','宋','宋诗','song-poetry','','[]','昔人一別恨悠悠，猶把梅花寄隴頭。',32,'全唐诗/poet.song.238000.json','["昔人一別恨悠悠，猶把梅花寄隴頭。", "咫尺花開君不見，有人獨自對花愁。"]'),
('fb180f08-dc57-4fe9-ae1d-592dbdf3c27b','詠雪用滕字韻','呂徽之','宋','宋诗','song-poetry','','[]','天上九龍施法水，人間二鼠齧枯藤。',32,'全唐诗/poet.song.238000.json','["天上九龍施法水，人間二鼠齧枯藤。", "鶩鵝聲亂功收蔡，蝴蝶飛來妙過滕。"]'),
('2d86dffe-1b2e-4927-bec4-c6d6a0cbfd77','又賦曇字韻','呂徽之','宋','宋诗','song-poetry','','[]','萬里關河凍欲含，渾如天地尚函三。',64,'全唐诗/poet.song.238000.json','["萬里關河凍欲含，渾如天地尚函三。", "橋邊驢子詩何惡，帳底羔兒酒正酣。", "竹委長身寒郭索，松埋短髪老瞿曇。", "不如乘此擒元濟，一洗江南草木慚。"]'),
('8a31246e-c7b6-486c-86d6-401461b65058','題畫梅贈黄君','呂徽之','宋','宋诗','song-poetry','','[]','黄君畫梅天下奇，枝枝筆底如龍飛。',64,'全唐诗/poet.song.238000.json','["黄君畫梅天下奇，枝枝筆底如龍飛。", "幹盤屈曲蒼苔古，老樹頃刻生光輝。", "婆娑月下弄清影，更有幽香襲詩境。", "地僻從無車馬塵，間關翠禽啼夢冷。"]'),
('33626e05-e28e-4277-bb11-2c7959356a9d','春景','呂徽之','宋','宋诗','song-poetry','','[]','脫溪凍解綠生波，好雨催花向曉過。',32,'全唐诗/poet.song.238000.json','["脫溪凍解綠生波，好雨催花向曉過。", "宿酒未醒眠未起，半窗紅日鳥聲多。"]'),
('d01723bb-f1c7-4220-9d67-2c1179b5ca8e','夏景','呂徽之','宋','宋诗','song-poetry','','[]','竹几藤牀石硯屏，薰風簾幕篆煙清。',32,'全唐诗/poet.song.238000.json','["竹几藤牀石硯屏，薰風簾幕篆煙清。", "空齋數點黄梅雨，添得芭蕉綠滿庭。"]'),
('1b467c80-cab0-422e-9fca-a3d8abb1ea8b','秋景','呂徽之','宋','宋诗','song-poetry','','[]','商聲早已到梧桐，夜氣生涼湛碧空。',32,'全唐诗/poet.song.238000.json','["商聲早已到梧桐，夜氣生涼湛碧空。", "閒倚小窗待明月，紫簫吹徹木犀風。"]'),
('5ad83d78-ef66-4bd6-afe6-ad6c6d22d983','冬景','呂徽之','宋','宋诗','song-poetry','','[]','斗室蕭蕭日晏眠，疏狂惟與懶相便。',32,'全唐诗/poet.song.238000.json','["斗室蕭蕭日晏眠，疏狂惟與懶相便。", "尋常甲子無心記，看到梅花又一年。"]'),
('f0c6b103-db11-4ea9-ab8a-ae6d7016f17c','千松圖','呂徽之','宋','宋诗','song-poetry','','[]','五百居東五百西，枝枝葉葉壓雲低。',32,'全唐诗/poet.song.238000.json','["五百居東五百西，枝枝葉葉壓雲低。", "自從老鶴歸來後，不許閒禽雜亂啼。"]'),
('e1fa1b30-b1af-4569-9694-f314250b914c','守犬','呂徽之','宋','宋诗','song-poetry','','[]','風恬月朗眠花影，吏不敲門門恰靜。',32,'全唐诗/poet.song.238000.json','["風恬月朗眠花影，吏不敲門門恰靜。", "何事猛然吠一聲，有人來汲門前井。"]'),
('06c6e6f3-1962-48ce-880a-ef8c3c6c904d','壺蜂','呂徽之','宋','宋诗','song-poetry','','[]','長日融和舞細腰，誰家庭院不相招。',32,'全唐诗/poet.song.238000.json','["長日融和舞細腰，誰家庭院不相招。", "江臯二月斜風急，拚逐飛花過短橋。"]'),
('eab7ac36-da47-4bf0-8f36-788279976988','紅梅','呂徽之','宋','宋诗','song-poetry','','[]','疏影離奇色更柔，誰將紅粉點枝頭。',32,'全唐诗/poet.song.238000.json','["疏影離奇色更柔，誰將紅粉點枝頭。", "牧童睡起朦朧眼，錯認桃林欲放牛。"]'),
('ab4a07b7-33f5-4d01-b6ce-6ed0e44f9265','綠萍','呂徽之','宋','宋诗','song-poetry','','[]','密密綿綿滿草堂，不容紅日下滄浪。',32,'全唐诗/poet.song.238000.json','["密密綿綿滿草堂，不容紅日下滄浪。", "却因風掃沾泥土，燕子啣來上畫梁。"]'),
('9f044118-d45a-4760-b411-c02149c87252','出塞曲  其一','張琰','宋','宋诗','song-poetry','','[]','腰間插雄劍，中夜龍虎吼。',48,'全唐诗/poet.song.238000.json','["腰間插雄劍，中夜龍虎吼。", "平明登前途，萬里不回首。", "男兒當野死，豈爲印如斗。", "忠誠表壯節，燦爛千古後。"]'),
('df6b18bf-8320-47a4-a4f8-2464a74cd1fb','出塞曲  其二','張琰','宋','宋诗','song-poetry','','[]','朝發山陽去，莫宿清水頭。',48,'全唐诗/poet.song.238000.json','["朝發山陽去，莫宿清水頭。", "上馬左右射，捷下如獼猴。", "先發服勇決，手提血髑髏。", "兵家互勝負，凡百慎前籌。"]'),
('bb5ee40d-187e-43ce-b42e-26c92fd0b643','出塞曲  其三','張琰','宋','宋诗','song-poetry','','[]','驅馬飲淮水，千里黄草平。',48,'全唐诗/poet.song.238000.json','["驅馬飲淮水，千里黄草平。", "種穀却流血，痛哭秋風生。", "寡妻出租稅，孤兒荷戈行。", "武威既不足，願見和親成。"]'),
('25fda91d-9096-4a6c-b2be-dfeeaef663c8','出塞曲  其四','張琰','宋','宋诗','song-poetry','','[]','軍中日奏凱，鼓行遼海東。',48,'全唐诗/poet.song.238000.json','["軍中日奏凱，鼓行遼海東。", "當寧怡玉色，千金勞成功。", "焉知昨日地，袒甲去如空。", "邊人不敢語，將軍益褒崇。"]'),
('d898c197-99ea-4899-99f3-9665ac2cc242','官柳','張琰','宋','宋诗','song-poetry','','[]','不見橋東黄布簾，樹猶如此我何堪。',32,'全唐诗/poet.song.238000.json','["不見橋東黄布簾，樹猶如此我何堪。", "裊裊亭亭忒無賴，又將春色誤江南。"]'),
('00ab584d-db27-4847-aa65-d87366e59980','被執口占','朱光','宋','宋诗','song-poetry','','[]','生爲大宋臣，死爲大宋鬼。',24,'全唐诗/poet.song.238000.json','["生爲大宋臣，死爲大宋鬼。", "一片忠義心，明月照秋水。"]'),
('7e1f6be5-5fdf-4708-954a-3678522e6434','復友人上官藻','張孝忠','宋','宋诗','song-poetry','','[]','風遞鴻音過故城，悲秋烈士不勝情。',64,'全唐诗/poet.song.238000.json','["風遞鴻音過故城，悲秋烈士不勝情。", "望窮雲白生鄉思，渴憶梅黄慰遠征。", "塵蔽碧天颷未掃，榻懸殘月夢難成。", "鱸肥却好君歸去，千里如期倒屣迎。"]'),
('95a3b94a-1566-42a8-8799-447a1e0eafa2','陳彥臣連靜女案判詞','王剛中','宋','宋诗','song-poetry','','[]','佳人才子兩相宣，置福端由禍所基。',32,'全唐诗/poet.song.238000.json','["佳人才子兩相宣，置福端由禍所基。", "永作夫妻諧汝願，不勞鑽穴隙相窺。"]'),
('569a20ee-5397-40e0-9f67-1587f968c444','和榴皮題壁韻','趙必曄','宋','宋诗','song-poetry','','[]','回仙吸露餐霞者，却勝人間煙火餘。',32,'全唐诗/poet.song.238000.json','["回仙吸露餐霞者，却勝人間煙火餘。", "二十八言留壁上，不須青鳥爲傳書。"]'),
('9be6fb6f-fbde-4f67-94b4-804eff337ff0','次鹿鳴宴詩','文天祥','宋','宋诗','song-poetry','','[]','禮樂皇皇使者行，光華分似及鄉英。',64,'全唐诗/poet.song.238000.json','["禮樂皇皇使者行，光華分似及鄉英。", "貞元虎榜雖聯捷，司隸龍門幸綴名。", "二宋高科猶易事，兩蘇清節乃真榮。", "囊書自負應如此，肯遜當年禰正平。"]'),
('f57c835a-57bd-4095-93aa-e818b5c3e09d','集英殿賜進士及第恭謝詩','文天祥','宋','宋诗','song-poetry','','[]','於皇天子自乘龍，三十三年此道中。',64,'全唐诗/poet.song.238000.json','["於皇天子自乘龍，三十三年此道中。", "悠遠直參天地化，昇平奚羨帝王功。", "但堅聖志持常久，須使生民見泰通。", "第一臚傳新渥重，報恩惟有厲清忠。"]'),
('13d1a507-1c7f-4412-8e55-847feeec3554','御賜瓊林宴恭和詩','文天祥','宋','宋诗','song-poetry','','[]','奉詔新彈入仕冠，重來軒陛望天顔。',64,'全唐诗/poet.song.238000.json','["奉詔新彈入仕冠，重來軒陛望天顔。", "雲呈五色符旗蓋，露立千官雜珮環。", "燕席巧臨牛女節，鸞章光映壁奎間。", "獻詩陳雅愚臣事，况見賡歌氣象還。"]'),
('60d38772-a419-4ac4-9d74-2467bba22032','明堂慶成恭進詩','文天祥','宋','宋诗','song-poetry','','[]','於皇藝祖德乘乾，聖主宣光奕葉前。',64,'全唐诗/poet.song.238000.json','["於皇藝祖德乘乾，聖主宣光奕葉前。", "運再庚申皇建極，祀同癸亥數參天。", "中嚴外辦三千禮，累洽重熙四十年。", "願贊帝心長對越，至忱功用貫垓埏。"]'),
('7f3385d0-f2ab-4ed7-aaef-8a76bb5bf232','敬和道山堂慶瞻御書韻','文天祥','宋','宋诗','song-poetry','','[]','墨灑天奎映籀紅，斯堂殿閣與俱隆。',64,'全唐诗/poet.song.238000.json','["墨灑天奎映籀紅，斯堂殿閣與俱隆。", "方壺圓嶠神仙宅，溫洛榮河造化工。", "列聖文章千載重，諸孫聲氣一時同。", "著庭更有邦人筆，稽首承休學二忠。"]'),
('1c047571-05d8-4bf0-85d6-9da783752ba8','次韻劉左司前以著作郎主祕書省營繕事時落成適潘祕丞得郡檇李并餞行有詩','文天祥','宋','宋诗','song-poetry','','[]','蓬壺日月四時春，金碧新來絢帝宸。',64,'全唐诗/poet.song.238000.json','["蓬壺日月四時春，金碧新來絢帝宸。", "俎豆幸陪麟省雋，衣冠中有虎符新。", "詩餘和氣生談麈，坐久風光入醉茵。", "多謝蘭臺舊盟主，好歸群玉領儒珍。"]'),
('dec18d7c-9dcc-4ee3-9ffe-7bfa078b4b9c','祕省再會次韻','文天祥','宋','宋诗','song-poetry','','[]','蓬萊春宴聚文星，多荷君恩錫百朋。',64,'全唐诗/poet.song.238000.json','["蓬萊春宴聚文星，多荷君恩錫百朋。", "四座衣冠陪賀監，一時梁棟盛吳興。", "圖書光動青藜杖，人物溫如古玉升。", "好是木天新境界，螢窗容我種金燈。"]'),
('b43d9a64-c6fc-421f-9a3b-ce39bd57afb4','送曹大著知廣德軍','文天祥','宋','宋诗','song-poetry','','[]','暫屈瀛州客，來臨汭水民。',48,'全唐诗/poet.song.238000.json','["暫屈瀛州客，來臨汭水民。", "山川歸史記，岳牧屬詞人。", "館舍朋簪舊，都門祖帳新。", "儒林官可紀，何止吏稱循。"]'),
('be39f306-4bd9-48c0-bce0-c3599f9acacc','贈祕書王監丞','文天祥','宋','宋诗','song-poetry','','[]','君不見祕書外監賀放翁，鏡湖一曲高清風。',262,'全唐诗/poet.song.238000.json','["君不見祕書外監賀放翁，鏡湖一曲高清風。", "又不見太子師傅兩疏氏，東門祖帳羅群公。", "人生晚節良不易，頹波直下誰障東。", "使人知有在我者，二三君子爲有功。", "我公金華山下住，赤松安期白雲處。", "風骨細瘦真神仙，急流勇退不肯顧。", "我昔山中想風采，幾回擊節歸田疏。", "適來追陪水蒼佩，親見辭歸白雲路。", "御筆擢公領蓬山，師表玉立東宮官。", "兩年苦口一去字，未許鷗鷺從公閑。", "瑶池深深鎖策府，玉皇宮闕僑其間。", "暫分赤符管下界，半空雲氣常往還。", "多少持麾辭上國，悠悠風塵見此客。", "莫作尋常太守看，疏賀以來偉人物。", "夜瞻婺女次舍中，一點光明射南極。", "公歸眠食重調護，世道尚憑公氣力。"]'),
('27ba0dc1-9910-46f2-9adf-c0072b3fc0eb','贈莆陽卓大著順寧精舍三十韻','文天祥','宋','宋诗','song-poetry','','[]','人生天地間，一死非細事。',288,'全唐诗/poet.song.238000.json','["人生天地間，一死非細事。", "識破此條貫，八九分地位。", "趙岐圖壽藏，杜牧擬墓志。", "祭文潜自撰，荷鍤伶常醉。", "此等蛻浮生，見解已不易。", "齊物逍遥游，大抵蒙莊意。", "聖門有大法，學者必孔自。", "知生未了了，未到知死地。", "原始則返終，終始本一致。", "後來得西銘，精藴發洙泗。", "吾體天地塞，吾氣天地帥。", "一節非踐形，終身莫繼志。", "舜功禹顧養，參全穎錫類。", "伯奇令無違，申生恭不貳。", "聖賢當其生，無日不惴惴。", "彼豈不大觀，何苦勤興寐。", "吾順苟不虧，吾寧始無愧。", "人而有所忝，曠達未足智。", "卓哉居士翁，方心不姿媚。", "蒙讒以去國，七年無怨懟。", "風雨三間茅，松楸接蒼翠。", "斯丘亦樂哉，未老先位置。", "宇宙如許大，豈以爲敝屣。", "當其歸去來，致命聊自遂。"]'),
('9e868ae2-b58d-447a-a47a-98ccfcf74e40','送卓大著知漳州','文天祥','宋','宋诗','song-poetry','','[]','蓬山隔風雨，芸觀司陽秋。',120,'全唐诗/poet.song.238000.json','["蓬山隔風雨，芸觀司陽秋。", "厭作承明直，出爲漳浦遊。", "問俗便桑梓，過家拜松楸。", "錦堂事相儷，棠舍陰易留。", "何來瀾蠡間，何物輒負舟。", "翻覆十年事，行止隨坎流。", "倘來豈不再，遲取終無尤。", "太守執此往，邦人庶其瘳。", "昔予援西銘，期子以前修。", "願覿弘濟學，四海放一舟。"]'),
('9dcbe824-6dca-4521-b0c7-0b80b302c283','又  其一','文天祥','宋','宋诗','song-poetry','','[]','陸氏登三閣，源明出一麾。',48,'全唐诗/poet.song.238000.json','["陸氏登三閣，源明出一麾。", "清聲光漳浦，便道拜長基。", "赤子歌來暮，同寅賦去思。", "西銘功用大，竚驗順寧詩。"]'),
('c483dae9-77ac-4b1f-b545-943a56586ff7','又  其二','文天祥','宋','宋诗','song-poetry','','[]','大陸登三閣，源明出一麾。',48,'全唐诗/poet.song.238000.json','["大陸登三閣，源明出一麾。", "臨軒親策後，上冢過家時。", "秋色吳山外，春風漳水涯。", "斯文交獨厚，羌賦送行詩。"]'),
('b9d6869d-38ea-4636-a480-87b2851a50ce','和蕭安撫平林送行韻','文天祥','宋','宋诗','song-poetry','','[]','得失元來付塞翁，何心桃李問東風。',64,'全唐诗/poet.song.238000.json','["得失元來付塞翁，何心桃李問東風。", "人皆有喜榮三仕，我尚無文謝五窮。", "秘苑固知朋可正，畏途猶恐甲方衷。", "欲酬長者殷勤祝，坎止流行學四忠。"]'),
('1df14442-c0fe-4118-812d-813f6208ab60','和朱衡守約山韻','文天祥','宋','宋诗','song-poetry','','[]','昔人一出正朋字，今我慚非行祕書。',64,'全唐诗/poet.song.238000.json','["昔人一出正朋字，今我慚非行祕書。", "人樣相看願元祐，詩章甚雅突黄初。", "競言汲戇猶須復，或謂顔愚亦可如。", "把酒對花姑勿論，春行後長莫妨徐。"]'),
('ae4381e0-6b03-465c-9ef8-718bb7e679bf','題玄潭觀雪浪閣用誠齋韻','文天祥','宋','宋诗','song-poetry','','[]','棄官學道勾山許，學到至人本無怒。',72,'全唐诗/poet.song.238000.json','["棄官學道勾山許，學到至人本無怒。", "赤子𧥄𧥄如魚頭，不堪妖孽腥上流。", "鉗鍵長潭鐵樹立，摩挲穹石寶劍濕。", "當時豈忍如是觀，毒流不可開眼看，英風凜凜萬古寒。"]'),
('328a2e47-cb13-4aea-bf6b-9c50753134a5','玄潭觀和龔宰韻','文天祥','宋','宋诗','song-poetry','','[]','晉代何曾谷此陵，到今樓觀隠居亭。',64,'全唐诗/poet.song.238000.json','["晉代何曾谷此陵，到今樓觀隠居亭。", "幻成鷗鷺乾坤闊，陶盡魚龍雲水腥。", "仙有神功參造化，人將故事入丹青。", "我來欲去長橋孽，祠下徘徊夜乞靈。"]'),
('74d0fcb2-c9b3-41b9-b7c3-1beaf822a25f','送朱制幹象祖','文天祥','宋','宋诗','song-poetry','','[]','一官聱漫任如何，屢疏牋天氣不磨。',64,'全唐诗/poet.song.238000.json','["一官聱漫任如何，屢疏牋天氣不磨。", "宋祚萬年陳大計，周圖五字訂前訛。", "重尋范老憂時箸，旁豎文公衛道戈。", "投匭近年殊不少，有人說似此君麽。"]'),
('ac08e3b0-6223-49db-a8e6-5796f969ea88','送三山林溶孫歸省','文天祥','宋','宋诗','song-poetry','','[]','束書遊京師，孤雲瞻太行。',48,'全唐诗/poet.song.238000.json','["束書遊京師，孤雲瞻太行。", "辭歸慕何蕃，捨養殊歐陽。", "山林乾坤靜，菽水日月長。", "好味諸公詩，勝讀寒泉章。"]'),
('aff55a98-7080-43af-8fe5-7d527034149e','京城借永福寺漆臺口占似王城山','文天祥','宋','宋诗','song-poetry','','[]','心如明鏡臺，此言出浮屠。',72,'全唐诗/poet.song.238000.json','["心如明鏡臺，此言出浮屠。", "後來發精義，并謂此臺無。", "此臺已是贅，何况形而器。", "圓釋正超然，點頭會意思。", "多謝城山翁，一語迎禪鋒。", "顧我塵俗人，與物方溶溶。"]'),
('dc975d0d-5581-4171-9b3e-86331048b333','景定壬戌司戶弟生日有感賦詩','文天祥','宋','宋诗','song-poetry','','[]','夏中與秋仲，兄弟客京華。',48,'全唐诗/poet.song.238000.json','["夏中與秋仲，兄弟客京華。", "椒柏同歡賀，萍蓬可歎嗟。", "孤雲在何處，明歲却誰家。", "料想親幃喜，中堂自點茶。"]'),
('cdb31bdf-1428-4a25-8dde-f2faf6945c17','梅  其一','文天祥','宋','宋诗','song-poetry','','[]','梅花耐寒白如玉，干涉春風紅更黄。',32,'全唐诗/poet.song.238000.json','["梅花耐寒白如玉，干涉春風紅更黄。", "若爲司花示薄罰，到底不能磨滅香。"]'),
('e5e7903d-5874-4d88-972e-62195e1db298','梅  其二','文天祥','宋','宋诗','song-poetry','','[]','香者梅之氣，白者梅之質。',72,'全唐诗/poet.song.238000.json','["香者梅之氣，白者梅之質。", "以爲香不香，鼻孔有通窒。", "我有天者在，一白自不易。", "古人重伐木，惟恐變顔色。", "大雅久不作，此道豈常息。", "詩翁言外意，不能磨滅白。"]'),
('73417d05-09fb-404d-8575-be8579c8be50','暑布送王廷舉用蕭敬夫韻  其一','文天祥','宋','宋诗','song-poetry','','[]','平生凉薄資，埏陶誤大窯。',84,'全唐诗/poet.song.238000.json','["平生凉薄資，埏陶誤大窯。", "誰知此石怪，愈沃乃愈焦。", "崑崙織火鼠，頓易鶉衣飄。", "榮我絲蘿附，免此蒲柳凋。", "服之雪漫白，長袂風摇摇。", "表之以霧縠，緣之以煙綃。", "振衣從姬滿，佩玉遊西瑶。"]'),
('f599f1db-cbec-4784-b678-316b149fdc7c','暑布送王廷舉用蕭敬夫韻  其二','文天祥','宋','宋诗','song-poetry','','[]','高人不煙火，跳出天地窯。',84,'全唐诗/poet.song.238000.json','["高人不煙火，跳出天地窯。", "掀然立千仞，塊視金與焦。", "香袂拂雪冷，紫髯逐風飄。", "摩挲雲冥樹，豈隨群卉凋。", "但知仙骨輕，不學倒影摇。", "人間盡描貌，妙不在生綃。", "揭斗斟天漿，霞衣却瓊瑶。"]'),
('efc33521-c66b-4e0a-b932-80d8ac08b53e','題陳國秀小園  其一','文天祥','宋','宋诗','song-poetry','','[]','席地自乾坤，半樹閲今古。',48,'全唐诗/poet.song.238000.json','["席地自乾坤，半樹閲今古。", "池館豈不寬，每換牡丹主。", "園公非隴傭，獨捎占春風。", "弄影不在多，臭香知乃翁。"]'),
('63995fa6-5d45-49f0-adfe-1a729343f0da','題陳國秀小園  其二','文天祥','宋','宋诗','song-poetry','','[]','長鶴展輕翮，遠棲松桂林。',48,'全唐诗/poet.song.238000.json','["長鶴展輕翮，遠棲松桂林。", "故宇入清夢，盤盤亦苦心。", "中林風月賒，十畝團幽陰。", "林下有奇士，繞樹從之吟。"]'),
('ca665772-300f-4617-bef5-29df1390d741','題靜山','文天祥','宋','宋诗','song-poetry','','[]','地得一以寧，凝然者卷石。',96,'全唐诗/poet.song.238000.json','["地得一以寧，凝然者卷石。", "嵁巖及培塿，異形不異質。", "古之能定者，悟此爲一極。", "春榮秋以悴，一歲百態出。", "鳥鳴花落句，此意誰與詰。", "所以尼丘人，仁智不廢一。", "萬象此緯經，死灰彼何物。", "明發此乎遊，參入觀水術。"]'),
('6434fc87-e0e2-46b6-aa58-62047afdc3a0','贈拆字嗅衣相士  其一','文天祥','宋','宋诗','song-poetry','','[]','水火坎離紫陽怪，滑波皮骨長坡駭。',64,'全唐诗/poet.song.238000.json','["水火坎離紫陽怪，滑波皮骨長坡駭。", "解州得解解中膠，費家封鋪同一解。", "唫字從金詩反窮，貝何爲分田何同。", "黄絹幼婦我自樂，竹犬多事鴉鶴翁。"]'),
('1926a2ea-71f4-4b2d-b1e5-a1f3016bac8c','贈拆字嗅衣相士  其二','文天祥','宋','宋诗','song-poetry','','[]','阿英薰蒸透肌理，不潔未蒙好西子。',64,'全唐诗/poet.song.238000.json','["阿英薰蒸透肌理，不潔未蒙好西子。", "芙蓉浪中薔薇水，蘇合蜣蜋忘彼己。", "馬嵬新襪釣新月，腥臊千年天地裂。", "是間曾著鼻孔麽，梅香竇臭無如何。"]'),
('1129e2e6-7557-422f-b438-54891248c8c1','贈閭丘相士','文天祥','宋','宋诗','song-poetry','','[]','急流勇退識真臞，昔有麻衣撥地爐。',32,'全唐诗/poet.song.238000.json','["急流勇退識真臞，昔有麻衣撥地爐。", "我亦愛君雲水趣，莫言雷雨趄江湖。"]'),
('5276f16d-429f-411a-bfa0-afcc6c1a5fa2','贈神目相士','文天祥','宋','宋诗','song-poetry','','[]','道茂數遁甲，長房得役鬼。',48,'全唐诗/poet.song.238000.json','["道茂數遁甲，長房得役鬼。", "風鑒麻衣仙，地理青烏子。", "擇術患不精，精義本無二。", "奇哉夢筆生，熊魚掩前氏。"]'),
('f768af3c-67d0-4d72-ad11-0f042e1257f4','贈鏡湖相士','文天祥','宋','宋诗','song-poetry','','[]','五月五日揚子江心水，鑄作道人雙瞳子。',32,'全唐诗/poet.song.238000.json','["五月五日揚子江心水，鑄作道人雙瞳子。", "吾面碟子大，安用鏡照二百里。"]'),
('3f296ec7-a741-49e4-b39f-f62a35eb4f4e','贈秋月葉相士','文天祥','宋','宋诗','song-poetry','','[]','急流勇退神仙，跛蹩龍鍾將相。',28,'全唐诗/poet.song.238000.json','["急流勇退神仙，跛蹩龍鍾將相。", "借問華山山中，何似天津橋上。"]'),
('4f6babcf-5d49-4b21-9855-8e7d51f26974','贈曾蘭谷相士','文天祥','宋','宋诗','song-poetry','','[]','許負眼，禰衡口。',16,'全唐诗/poet.song.238000.json','["許負眼，禰衡口。", "巧言甘，莠言醜。"]'),
('0a28ff10-bfae-4dac-b4bb-2b34a808e9f3','贈月洲相士','文天祥','宋','宋诗','song-poetry','','[]','月洲月眼閲人多，且道西州事若何。',32,'全唐诗/poet.song.238000.json','["月洲月眼閲人多，且道西州事若何。", "朱紫貴人皆好命，不知中有孔明麽。"]'),
('15b3b404-f0b8-4007-88e6-b0d3bf654afd','贈劉矮跛相士  其一','文天祥','宋','宋诗','song-poetry','','[]','鍊石爲形，鏗金爲音。',160,'全唐诗/poet.song.238000.json','["鍊石爲形，鏗金爲音。", "世方好圓，癡守方心。", "陰陽絪縕，人一氣質。", "善惡之微，證于聲色。", "意所欲發，雖吾不知。", "彼美子劉，洞其先幾。", "骯髒難合，今世道病。", "如子所言，生稟已定。", "戇夫勇士，往往一偏。", "以視妾婦，豈不猶賢。", "洪範得三，二曰剛克。", "會其歸其，好是正直。", "學問工夫，氣質用微。", "汝能觀形，安知其餘。", "子術已定，吾情已成。", "子執子術，吾安吾情。"]'),
('b3d8c76d-e582-42a2-bd0b-8ad8f01e5dae','贈劉矮跛相士  其二','文天祥','宋','宋诗','song-poetry','','[]','媻姍三尺軀，舉止如不揚。',72,'全唐诗/poet.song.238000.json','["媻姍三尺軀，舉止如不揚。", "瞻視照肝膽，音吐何琅琅。", "君看水中鳬，不及鶴脛長。", "昔聞夔憐蚿，未聞一足僵。", "萬物各自適，形色安足量。", "子言良有理，與子持酒漿。"]'),
('e3ee7d6d-f421-453f-b2d6-e848bcc05dc5','贈梅谷相士','文天祥','宋','宋诗','song-poetry','','[]','當年壽陽額，春風點顔色。',96,'全唐诗/poet.song.238000.json','["當年壽陽額，春風點顔色。", "後來廣平腸，冰雪峙氣骨。", "世人識花面，識花還自淺。", "花有歲寒心，清貞堅百鍊。", "君家在梅谷，自詭知梅熟。", "須得花性情，不假花頭目。", "莫說和羹事，花被和羹累。", "突兀煙水村，我梅自林氏。"]'),
('1be3ea4e-020d-4ab2-8fde-012b21c965f9','贈碧眼相士','文天祥','宋','宋诗','song-poetry','','[]','蒼蒼垂天雲，靈照行下土。',48,'全唐诗/poet.song.238000.json','["蒼蒼垂天雲，靈照行下土。", "秋江浸草木，魚蝦歷可數。", "眉山老麻衣，偷入此阿堵。", "色界只點頭，從人道吾瞽。"]'),
('8cfb3123-ce26-4773-a50e-76e46596eb22','贈鏡齋徐相士','文天祥','宋','宋诗','song-poetry','','[]','鄒忌不如徐公美，引鏡自窺得真是。',96,'全唐诗/poet.song.238000.json','["鄒忌不如徐公美，引鏡自窺得真是。", "門下食客纔有求，昏昏便與妻妾比。", "徐家耳孫却不然，自名一鏡京師市。", "世人無用看青銅，此君雙眼明秋水。", "君以無求游公卿，勿令此鏡生瑕滓。", "碟子大面何難知，從今光照二百里。"]'),
('36470445-7a79-4b12-b2fa-290d9df715e3','贈鑑湖相士','文天祥','宋','宋诗','song-poetry','','[]','瘦竹凌風弄碧漪，山光雲影共熹微。',32,'全唐诗/poet.song.238000.json','["瘦竹凌風弄碧漪，山光雲影共熹微。", "月黄昏裏疏枝外，認取半天孤鶴飛。"]'),
('e7cde75c-3a9c-45b2-abcf-1d9305b7f0fb','贈趙神眼','文天祥','宋','宋诗','song-poetry','','[]','一絛一褐髯如鐵，神爲秋水眼爲月。',32,'全唐诗/poet.song.238000.json','["一絛一褐髯如鐵，神爲秋水眼爲月。", "欲從壺子覓三機，劍首終然吹一吷。"]'),
('867bb182-da2f-4f82-9747-038f5daaab5d','贈桂巖楊相士','文天祥','宋','宋诗','song-poetry','','[]','榮悴紛紛未可期，夕多未振已朝披。',64,'全唐诗/poet.song.238000.json','["榮悴紛紛未可期，夕多未振已朝披。", "得剛難免於今世，行好須看有驗時。", "萱晝堂前惟有母，槐陰庭下豈無兒。", "好官要做無難做，身後生前是兩岐。"]'),
('cdd8c4fd-0f44-45d6-84db-6fa62edebbee','宣州罷任再贈','文天祥','宋','宋诗','song-poetry','','[]','貧賤元無富貴思，泥塗滑滑總危機。',64,'全唐诗/poet.song.239000.json','["貧賤元無富貴思，泥塗滑滑總危機。", "世無徐庶不如卧，見到淵明便合歸。", "流落丹心天肯未，崢嶸青眼古來稀。", "西風爲語巖前桂，若更多言却又非。"]'),
('724699d9-f001-430e-a8ab-a0e783facd66','贛州再贈','文天祥','宋','宋诗','song-poetry','','[]','此別重逢又幾時，贈君此是第三詩。',64,'全唐诗/poet.song.239000.json','["此別重逢又幾時，贈君此是第三詩。", "衆人皆醉從教酒，獨我無爭且看棋。", "凡事誰能隨物競，此心只要有天知。", "自知自有天知得，切莫逢人說項斯。"]'),
('f95bef38-e33e-4893-b29c-c38b0d0898bd','贈彭別峰太極數','文天祥','宋','宋诗','song-poetry','','[]','手把先天已後書，當來一畫本全無。',32,'全唐诗/poet.song.239000.json','["手把先天已後書，當來一畫本全無。", "白雲山下泠泠水，自在人間太極圖。"]'),
('9e159d4b-f1a4-491b-8661-9928dfb12fe8','贈黄生銀河數','文天祥','宋','宋诗','song-poetry','','[]','乘槎人從天上來，天上知有君平術。',32,'全唐诗/poet.song.239000.json','["乘槎人從天上來，天上知有君平術。", "黄生能談君平書，不知曾認支機石。"]'),
('c4f63d7b-39d7-4730-97d6-64716cf05299','贈楊樵隠應炎談命','文天祥','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','莘郊一介，堯舜君民。',80,'全唐诗/poet.song.239000.json','["莘郊一介，堯舜君民。", "薇山二難，百世忠清。", "富春耕叟，涕洟雲臺。", "終南遯士，仕宦梯媒。", "是數公者，俱以隠名。", "木石一跡，霄淵異情。", "九華山人，賣樵江湖。", "請算世間，幾種樵夫。"]'),
('5bd41206-2cf0-4983-8b98-0e42447553a1','贈葉大明','文天祥','宋','宋诗','song-poetry','','[]','大明標榜葉氏子，自稱後村門下士。',96,'全唐诗/poet.song.239000.json','["大明標榜葉氏子，自稱後村門下士。", "誤言木吉孛爲災，後村曾發一笑來。", "其師流傳說如此，寧知禍福乃不爾。", "犀腰貂首徒勞人，甘藜豢藿無苦辛。", "我生有命殊六六，木孛循環相起伏。", "袖中莫出將相圖，盡洗舊學讀吾書。"]'),
('19e28b4f-537a-45b5-9dd3-1b31f802c748','贈舒片雲','文天祥','宋','宋诗','song-poetry','','[]','麻源謫仙人，噓呵成陰陽。',100,'全唐诗/poet.song.239000.json','["麻源謫仙人，噓呵成陰陽。", "向來懷袖間，冉冉天孫裳。", "一夕大雷電，六丁下取將。", "仙人乘風來帝鄉，又從膚寸起飛揚。", "仙術亦如此，天機神翕張。", "有時行渾天，周游十三萬里强。", "往來仙馭不可韁，正恐問命人，望氣蓬萊隔渺茫。"]'),
('6e789141-dbd8-4c18-bd73-47a0cab422a3','贈彭神機','文天祥','宋','宋诗','song-poetry','','[]','挽强二石徒碌碌，學到穿楊精藝熟。',96,'全唐诗/poet.song.239000.json','["挽强二石徒碌碌，學到穿楊精藝熟。", "百發百中無虛弦，百中一跌前功辱。", "彭君絕識透黄間，不師逢羿師珞琭。", "天度三百六十强，一算不容失正鵠。", "吾聞天機難語人，往來了了拈衆鏃。", "君姑藏用凝於神，矢口莫輕談禍福。"]'),
('c6d0c12d-603f-4a0d-9398-d4da333e11be','贈劉忠樸','文天祥','宋','宋诗','song-poetry','','[]','楹何爲折劍何借，鬚肯爲拂糞肯嘗。',96,'全唐诗/poet.song.239000.json','["楹何爲折劍何借，鬚肯爲拂糞肯嘗。", "馬公布衾王公飯，石家錦障丁家香。", "忠邪佞邪兩無定，一琱一璞異其性。", "忠樸先生躔法高，古今四者豈關命。", "五九六餘能善惡，鐵算不是并州錯。", "便從忠樸問如今，忠果誰忠樸誰樸。"]'),
('a3ddb48e-e640-4889-8bbe-08d886e480e8','贈金稱','文天祥','宋','宋诗','song-poetry','','[]','我有一叢籬下花，黄金滿眼無人拾。',32,'全唐诗/poet.song.239000.json','["我有一叢籬下花，黄金滿眼無人拾。", "夜看璇璣度玉衡，猿啼雨外青山濕。"]'),
('0db725b2-f5e9-432d-8891-a9ae752dec47','贈余月心五首  其一','文天祥','宋','宋诗','song-poetry','','[]','月之所在謂之身，朝市山林幾樣人。',32,'全唐诗/poet.song.239000.json','["月之所在謂之身，朝市山林幾樣人。", "靜看一輪如此潔，莫將身著軟紅塵。"]'),
('d0974fa5-2654-418b-8961-26b0e232eb1c','贈余月心五首  其二','文天祥','宋','宋诗','song-poetry','','[]','我生之辰月宿斗，如何謗譽由箕口。',32,'全唐诗/poet.song.239000.json','["我生之辰月宿斗，如何謗譽由箕口。", "月明只合醒眼看，斗亦何須挹漿酒。"]'),
('49a6b928-26f7-4c87-985a-4dea4c399060','贈余月心五首  其三','文天祥','宋','宋诗','song-poetry','','[]','月比於人歷世多，纔圓又缺幾消磨。',32,'全唐诗/poet.song.239000.json','["月比於人歷世多，纔圓又缺幾消磨。", "只因受用長生藥，嗟爾死蛙如月何。"]'),
('3957c56c-2864-4ce6-967c-20e1bc7763f5','贈余月心五首  其四','文天祥','宋','宋诗','song-poetry','','[]','一種黄州月，曹蘇善惡幾。',24,'全唐诗/poet.song.239000.json','["一種黄州月，曹蘇善惡幾。", "吾磯連月釣，此月是邪非。"]');
